import type { Item } from './index';

// Catálogo C — "Growth con IA" (100 blueprints). Teaser gratis (beneficio+alcance);
// blueprint completo de pago (1,99 € suelto o en equipo a 3,99 €).
// Reescrito en lenguaje de beneficio de negocio a partir del catálogo técnico original;
// cifras de precisión sospechosa del origen suavizadas a lenguaje cualitativo (fact-checking).
export const GROWTH: Item[] = [
  {"id":"gr01","catalogo":"growth","grupo":"SEO","tema":"Arquitectura e indexación","titulo":"Que Google entienda tu web como un mapa, no como un laberinto","beneficio":"Organiza las páginas de tu web en categorías y subcategorías conectadas entre sí, para que buscadores y visitantes entiendan qué temas dominas y encuentren fácilmente el contenido relacionado. Esto reduce el riesgo de que páginas valiosas queden aisladas y sin tráfico.","alcance":"Qué sí hace: revisa el contenido existente, propone una jerarquía de página madre y páginas hijas por tema, añade enlaces internos recíprocos entre ellas y señala páginas huérfanas (sin ningún enlace interno que apunte a ellas). Qué no hace: no crea contenido nuevo, no garantiza mejoras de posición en buscadores ni una fecha en la que se notarán, y no debe aplicarse en producción sin que una persona revise antes los cambios de enlazado propuestos.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza el contenido publicado, agrupa las páginas por tema principal, define una relación de página madre (categoría) y páginas hijas (subtemas), inserta enlaces internos recíprocos entre ambos niveles y detecta páginas sin enlaces internos entrantes.","modo":"Auditoría y reestructuración de arquitectura","pasos":["Listar todas las URLs indexables del sitio junto con su título, encabezados principales y tema.","Agrupar las URLs en clústeres temáticos y proponer, dentro de cada clúster, cuál página actúa como madre y cuáles como hijas.","Revisar los enlaces internos actuales de cada clúster y detectar páginas que no reciben ningún enlace interno (huérfanas).","Añadir o proponer enlaces recíprocos: de la página madre hacia cada hija, y de cada hija de vuelta hacia la madre y, cuando tenga sentido, hacia sus hermanas.","Entregar un informe con los cambios propuestos, separando lo que se puede aplicar directamente de lo que requiere decisión editorial."],"reglas":["No publicar cambios de enlazado en producción sin revisión humana previa.","No forzar relaciones temáticas entre páginas que no comparten un tema real solo para evitar huérfanas.","Señalar explícitamente cualquier página huérfana que no se pueda resolver dentro del alcance del análisis."],"prompt":"Actúa como un consultor técnico de SEO especializado en arquitectura de la información. Trabaja sobre el repositorio del sitio en [ruta del proyecto] (framework: [Astro/WordPress/Next.js/otro]).\n\nObjetivo: mapear la autoridad temática del sitio y reforzar el enlazado interno entre páginas relacionadas.\n\nPasos a ejecutar:\n1. Genera un inventario de todas las URLs indexables (excluye borradores, páginas con noindex y utilidades internas como /admin o /login). Para cada una, extrae título, H1 y los temas principales que trata.\n2. Agrupa las URLs en clústeres temáticos coherentes. Dentro de cada clúster, identifica qué página debería actuar como 'madre' (la más general del tema) y cuáles como 'hijas' (subtemas específicos).\n3. Revisa el contenido de cada página y detecta cuáles no reciben ningún enlace interno desde otra página del sitio (huérfanas).\n4. Propón, en un documento de cambios (no apliques directamente en producción), los enlaces recíprocos a añadir: enlace de la madre hacia cada hija con texto ancla descriptivo del tema de destino, y enlace de cada hija de vuelta hacia su madre.\n5. Para las páginas huérfanas, propón al menos un enlace de entrada desde la página temáticamente más cercana.\n6. Entrega el resultado como una tabla: URL origen, URL destino, texto ancla propuesto y motivo del enlace. No modifiques archivos de producción sin que yo apruebe esta tabla primero.\n\nRestricciones: no inventes relaciones temáticas forzadas; si una página no encaja claramente en ningún clúster, indícalo en vez de forzarla. No prometas ni estimes posiciones de ranking resultantes."}},
  {"id":"gr02","catalogo":"growth","grupo":"SEO","tema":"Arquitectura e indexación","titulo":"Enlaces internos que guían al lector (y al buscador) hacia lo que sigue","beneficio":"Añade enlaces internos relevantes dentro del propio texto de tus páginas, con palabras descriptivas en vez de 'haz clic aquí', para que el lector navegue a contenido relacionado y los buscadores entiendan mejor de qué trata cada página.","alcance":"Qué sí hace: revisa el contenido de una página y busca dentro del propio texto menciones de temas que ya tienen una página propia en el sitio, para convertirlas en enlaces con texto ancla descriptivo. Qué no hace: no reescribe el contenido para forzar enlaces donde no hay una mención natural, no garantiza que más enlaces internos se traduzcan en más tráfico ni mejor posición, y los enlaces propuestos deben revisarse por una persona antes de publicarse, porque el contexto editorial puede escapar al análisis automático.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre el texto de una página, identifica frases o palabras que coinciden con el tema de otras páginas del sitio, y propone convertirlas en enlaces internos con un texto ancla que describe el destino, evitando anclas genéricas.","modo":"Edición de contenido existente","pasos":["Construir un índice de las páginas del sitio con su tema principal y palabras clave asociadas.","Recorrer el texto de la página objetivo buscando menciones naturales de esos temas.","Proponer, para cada mención encontrada, un enlace hacia la página relacionada con un texto ancla descriptivo (nunca genérico como 'aquí' o 'este artículo').","Limitar el número de enlaces propuestos a los que aporten valor real de navegación, evitando saturar el texto.","Entregar la lista de enlaces propuestos con su ubicación exacta en el texto para revisión antes de aplicarlos."],"reglas":["Nunca usar textos ancla genéricos como 'haz clic aquí', 'leer más' o 'este enlace'.","No insertar un enlace si la mención no es una coincidencia temática natural con la página de destino.","No aplicar los enlaces directamente en producción sin revisión editorial previa."],"prompt":"Actúa como editor SEO especializado en enlazado interno contextual. Trabajo sobre el contenido de [ruta del archivo o URL de la página] dentro del proyecto en [ruta del proyecto].\n\nObjetivo: encontrar oportunidades de enlazado interno dentro del texto ya publicado, sin alterar el mensaje ni el tono original.\n\nPasos:\n1. Construye un índice de las páginas del sitio (usa el sitemap o el listado de contenido en [carpeta de contenido]) con el tema principal de cada una.\n2. Lee el texto completo de la página objetivo y localiza frases o palabras que mencionen temas cubiertos por otras páginas del índice.\n3. Para cada coincidencia, propón un enlace con texto ancla descriptivo que resuma el tema de la página de destino (nunca 'aquí', 'este artículo' o variantes genéricas).\n4. Si una misma página de destino podría enlazarse varias veces, elige la mención más natural y relevante en el contexto, evitando repetir el mismo enlace de forma forzada.\n5. Entrega los cambios propuestos como una lista: fragmento de texto original, texto ancla sugerido, URL de destino y una frase que justifique la relación temática. No edites el archivo directamente: espera mi aprobación.\n\nRestricciones: no fuerces enlaces en frases donde la relación temática sea débil. No hagas afirmaciones sobre el impacto en el posicionamiento; esto es una mejora de navegación y contexto semántico, no una garantía de resultados en buscadores."}},
  {"id":"gr03","catalogo":"growth","grupo":"SEO","tema":"Arquitectura e indexación","titulo":"Un plano actualizado de tu web para que los buscadores no se pierdan","beneficio":"Genera un archivo sitemap.xml con las páginas que sí quieres que se indexen, excluyendo automáticamente las que tienen noindex o son duplicados por paginación, para que los buscadores dediquen su atención al contenido que realmente importa.","alcance":"Qué sí hace: genera o actualiza el archivo sitemap.xml a partir de las URLs indexables del sitio, excluyendo páginas marcadas como noindex y parámetros de paginación duplicados. Qué no hace: no obliga a un buscador a rastrear o indexar las URLs incluidas -eso depende del propio buscador-, no corrige por sí solo otros problemas de indexación del sitio, y el archivo generado debe revisarse y desplegarse siguiendo el proceso normal de publicación antes de sustituir el sitemap en producción.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre las rutas del sitio, filtra las que tienen noindex o son variantes de paginación/parámetros, y genera un archivo sitemap.xml válido con las URLs restantes y sus metadatos básicos (última modificación, si está disponible).","modo":"Generación de archivo","pasos":["Listar todas las rutas del sitio disponibles en el proyecto o en el CMS.","Excluir las rutas marcadas explícitamente con noindex en su metaetiqueta o configuración.","Excluir variantes de paginación y URLs con parámetros que dupliquen contenido ya listado (por ejemplo, páginas 2, 3... de un listado).","Generar el archivo sitemap.xml con el formato estándar, incluyendo fecha de última modificación cuando el dato exista.","Validar que el archivo resultante sea XML bien formado antes de entregarlo."],"reglas":["Nunca incluir una URL marcada como noindex en el sitemap generado.","No incluir URLs con parámetros de paginación cuando ya existe una versión canónica listada.","Entregar el archivo para revisión y despliegue manual, no sobrescribir el sitemap en producción de forma automática."],"prompt":"Actúa como ingeniero SEO técnico. Trabaja sobre el proyecto en [ruta del proyecto] (framework: [Astro/Next.js/WordPress/otro]).\n\nObjetivo: generar un archivo sitemap.xml limpio, que incluya solo URLs indexables.\n\nPasos:\n1. Recorre las rutas o el contenido del proyecto y construye la lista completa de URLs públicas.\n2. Para cada URL, revisa si tiene una metaetiqueta noindex o una configuración equivalente en el CMS; si la tiene, exclúyela de la lista.\n3. Identifica URLs de paginación (por ejemplo, ?page=2, /pagina/3) o con parámetros que generen contenido duplicado, y exclúyelas, dejando solo la versión principal o canónica de ese listado.\n4. Genera el archivo sitemap.xml siguiendo el estándar (etiquetas urlset, url, loc, y lastmod cuando el dato de última modificación esté disponible).\n5. Verifica que el XML resultante sea válido (sin etiquetas rotas, sin URLs relativas, todas con protocolo y dominio completos).\n6. Entrega el archivo en [ruta de salida] y un resumen de cuántas URLs se incluyeron y cuántas se excluyeron, con el motivo de exclusión de cada grupo.\n\nRestricciones: no asumas que una URL debe indexarse solo porque existe; respeta las marcas de noindex existentes. No despliegues el archivo directamente a producción sin que yo lo revise."}},
  {"id":"gr04","catalogo":"growth","grupo":"SEO","tema":"Arquitectura e indexación","titulo":"Una sola versión oficial de cada página, sin copias que compitan entre sí","beneficio":"Asegura que cada página declare cuál es su versión 'oficial' (canonical) de forma consistente, evitando que variantes con parámetros, mayúsculas o barras finales distintas compitan entre sí por la misma búsqueda.","alcance":"Qué sí hace: revisa la etiqueta canonical de cada página y corrige las que faltan, apuntan a una URL relativa, incluyen parámetros innecesarios o no coinciden con el protocolo/dominio absoluto correcto. Qué no hace: no decide por ti cuál de varias páginas similares debería ser la versión canónica cuando existe una ambigüedad de negocio real -eso requiere criterio editorial-, y no garantiza que un buscador respete siempre la canonical declarada. Los cambios deben probarse en un entorno de pruebas antes de aplicarse en producción.","precio":1.99,"blueprint":{"quePuedeHacer":"Audita las etiquetas canonical de todas las páginas del sitio, detecta las que faltan, están mal formadas o apuntan a una URL incorrecta, y las corrige para que cada página declare su versión absoluta y limpia.","modo":"Auditoría técnica y corrección","pasos":["Recorrer todas las páginas indexables y extraer su etiqueta canonical actual, si existe.","Detectar canonicals ausentes, relativas, con parámetros de tracking, con protocolo http en vez de https, o con barra final inconsistente respecto al resto del sitio.","Definir la URL absoluta y limpia correspondiente a cada página según la convención del sitio.","Corregir o añadir la etiqueta canonical en cada página con la URL absoluta correcta.","Reportar los casos ambiguos (por ejemplo, dos páginas muy similares sin que quede claro cuál debería ser la canónica) para decisión humana."],"reglas":["Nunca apuntar una canonical a una URL relativa; siempre debe ser absoluta con protocolo y dominio.","No decidir automáticamente cuál página es la canónica cuando existe ambigüedad de negocio entre dos versiones válidas: escalar para revisión humana.","Probar los cambios en un entorno de staging antes de aplicarlos en producción."],"prompt":"Actúa como auditor técnico de SEO. Trabaja sobre el proyecto en [ruta del proyecto].\n\nObjetivo: asegurar que cada página tenga una etiqueta canonical correcta, absoluta y consistente.\n\nPasos:\n1. Recorre todas las páginas indexables y extrae el valor actual de su etiqueta link rel='canonical', si existe.\n2. Marca como incidencia cualquier página donde la canonical: falte, sea una URL relativa, use http en vez de https, incluya parámetros de tracking (utm_*, fbclid, etc.), o tenga una barra final inconsistente con la convención del resto del sitio.\n3. Para cada incidencia, calcula cuál sería la URL absoluta y limpia correcta según la convención observada en el resto del sitio (dominio, protocolo, uso o no de barra final).\n4. Aplica la corrección en el código o la configuración correspondiente.\n5. Si detectas dos o más páginas muy similares donde no es evidente cuál debería ser la versión canónica, no decidas por tu cuenta: repórtalo como un caso a resolver por una persona.\n6. Entrega un informe con todas las correcciones aplicadas y los casos escalados para revisión.\n\nRestricciones: nunca generes una canonical relativa. No apliques los cambios directamente en el sitio en producción; primero valida en un entorno de pruebas o rama separada."}},
  {"id":"gr05","catalogo":"growth","grupo":"SEO","tema":"Arquitectura e indexación","titulo":"Direcciones limpias que cualquiera puede escribir, leer y compartir","beneficio":"Limpia las URLs del sitio quitando acentos, mayúsculas, espacios y caracteres especiales, para que sean más fáciles de leer, escribir de memoria y compartir, y para evitar variantes duplicadas de una misma dirección.","alcance":"Qué sí hace: detecta slugs (la parte de la URL que identifica la página) con acentos, mayúsculas, espacios, símbolos o caracteres no estándar, y propone una versión limpia equivalente. Qué no hace: no cambia URLs ya publicadas sin dejar constancia de que necesitan una redirección para no romper enlaces existentes ni perder el posicionamiento acumulado, y no decide el criterio de nomenclatura de tu marca -eso lo defines tú-. Cambiar slugs de páginas ya indexadas es delicado: revisa siempre el plan de redirecciones con una persona antes de publicar.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa los slugs existentes y los de contenido nuevo, detecta caracteres problemáticos (acentos, mayúsculas, espacios, símbolos), y genera la versión normalizada equivalente en minúsculas, sin acentos y con guiones en vez de espacios.","modo":"Normalización de URLs","pasos":["Listar los slugs actuales de todas las URLs del sitio.","Detectar los que contienen mayúsculas, acentos, espacios, guiones bajos o símbolos no estándar.","Generar la versión normalizada de cada slug problemático (minúsculas, sin acentos, palabras separadas por guiones).","Para slugs ya publicados e indexados, marcar que el cambio requiere una redirección 301 hacia la nueva URL, no solo el cambio del slug.","Entregar la lista de cambios propuestos separando 'contenido nuevo, se puede aplicar directo' de 'contenido publicado, requiere plan de redirección'."],"reglas":["Nunca cambiar el slug de una página ya publicada e indexada sin proponer también su redirección correspondiente.","No aplicar automáticamente cambios de slug en páginas con tráfico existente sin aprobación humana.","Mantener siempre minúsculas, sin acentos ni caracteres especiales, y guiones como separador."],"prompt":"Actúa como técnico SEO especializado en estructura de URLs. Trabaja sobre el proyecto en [ruta del proyecto].\n\nObjetivo: normalizar los slugs del sitio para que sean limpios, consistentes y sin caracteres problemáticos.\n\nPasos:\n1. Extrae la lista completa de slugs (la parte final de la URL que identifica cada página) del sitio.\n2. Marca los que contengan mayúsculas, acentos, espacios, guiones bajos, o símbolos fuera del rango [a-z0-9-].\n3. Genera para cada uno la versión normalizada: todo en minúsculas, sin acentos (á→a, ñ→n, etc.), espacios y guiones bajos convertidos a guiones simples, sin símbolos.\n4. Separa los resultados en dos grupos: (a) contenido nuevo o sin publicar, donde el slug puede corregirse directamente, y (b) contenido ya publicado e indexado, donde el cambio de slug requiere crear una redirección 301 desde la URL antigua hacia la nueva para no perder enlaces ni posicionamiento existente.\n5. Entrega ambos listados junto con las redirecciones necesarias para el grupo (b), listas para que yo las revise antes de aplicarlas.\n\nRestricciones: no cambies el slug de ninguna página del grupo (b) sin incluir su redirección correspondiente en la misma entrega. No apliques cambios directamente en producción sin revisión previa."}},
  {"id":"gr06","catalogo":"growth","grupo":"SEO","tema":"Arquitectura e indexación","titulo":"Que cada idioma de tu web sepa que existen los demás","beneficio":"Valida y corrige las referencias entre las distintas versiones de idioma o país de tu web, para que un buscador entienda que la página en español y la página en inglés (por ejemplo) son la misma página en dos idiomas, y muestre la versión correcta a cada usuario.","alcance":"Qué sí hace: revisa las etiquetas hreflang existentes y comprueba que cada versión de idioma referencia a todas las demás versiones equivalentes de forma recíproca (si la página en español apunta a la de inglés, la de inglés debe apuntar de vuelta a la de español). Qué no hace: no traduce contenido, no decide qué mercados o idiomas debería cubrir tu negocio, y no garantiza que el buscador siempre respete la señal de idioma sobre otros factores. Los cambios en hreflang afectan a varias páginas a la vez: conviene revisarlos en conjunto antes de publicarlos.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre todas las versiones de idioma/país de cada página, construye la matriz de referencias hreflang esperada, y detecta las referencias que faltan o que no son recíprocas.","modo":"Validación de configuración","pasos":["Identificar los grupos de páginas que son versiones equivalentes entre sí en distintos idiomas o países.","Extraer las etiquetas hreflang actuales de cada página del grupo.","Construir la matriz de referencias esperada: cada versión debe apuntar a todas las demás del mismo grupo, incluida una referencia a sí misma.","Comparar la matriz esperada con las etiquetas reales y detectar referencias ausentes, incorrectas o no recíprocas.","Corregir las etiquetas hreflang de cada página del grupo para completar la matriz.","Entregar un informe por grupo de páginas con el estado antes/después de la corrección."],"reglas":["Cada versión de idioma debe incluir una referencia hreflang a sí misma además de a las demás versiones del grupo.","No dar por completa una matriz hreflang si alguna referencia no es recíproca.","Revisar los cambios por grupo completo de páginas antes de publicarlos, no página por página de forma aislada."],"prompt":"Actúa como técnico SEO internacional. Trabaja sobre el proyecto en [ruta del proyecto], que tiene versiones en los idiomas/países: [lista de idiomas, ej. es, es-MX, en].\n\nObjetivo: validar y completar la matriz de etiquetas hreflang entre versiones equivalentes de idioma.\n\nPasos:\n1. Identifica los grupos de páginas equivalentes (la misma página de contenido en sus distintas versiones de idioma).\n2. Para cada grupo, extrae las etiquetas hreflang actuales de cada versión.\n3. Construye la matriz esperada: cada versión debe referenciar a todas las demás del grupo, con el código de idioma/país correcto, y también a sí misma (self-referencing hreflang).\n4. Compara la matriz esperada contra la real y lista las referencias que faltan, están mal escritas (código de idioma incorrecto) o no son recíprocas (A apunta a B pero B no apunta a A).\n5. Propón las correcciones necesarias para que cada grupo quede completo y recíproco.\n6. Entrega el informe agrupado por conjunto de páginas equivalentes, con el estado 'antes' y 'después' de cada una.\n\nRestricciones: no marques un grupo como correcto si falta aunque sea una sola referencia recíproca. No apliques los cambios en producción sin que yo revise el informe completo del grupo afectado."}},
  {"id":"gr07","catalogo":"growth","grupo":"SEO","tema":"Rendimiento técnico","titulo":"Una web que no salta ni tiembla mientras carga","beneficio":"Reduce los saltos visuales molestos que ocurren mientras la página carga (por ejemplo, cuando una imagen empuja el texto de golpe) y prioriza la carga del elemento principal que el usuario ve primero, para una experiencia más estable y agradable.","alcance":"Qué sí hace: revisa las imágenes y elementos visuales del sitio para asegurar que declaren sus dimensiones (ancho y alto) y evitar así saltos de layout, y prioriza técnicamente la carga del elemento principal visible al entrar a la página. Qué no hace: no optimiza todos los factores que influyen en la velocidad percibida de una web -por ejemplo, el rendimiento del servidor o de scripts de terceros pesados queda fuera de este alcance-, y no garantiza una puntuación concreta en herramientas de medición de rendimiento, ya que estas varían según el dispositivo y la conexión de cada visita. Verifica los cambios en un entorno de pruebas antes de publicarlos.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta imágenes y elementos visuales sin dimensiones declaradas, añade el ancho y alto correspondientes para evitar saltos de layout, e identifica el elemento principal visible al cargar la página para marcarlo con prioridad de carga.","modo":"Auditoría técnica y corrección","pasos":["Recorrer las plantillas y páginas del sitio en busca de imágenes y elementos visuales sin atributos de ancho/alto declarados.","Añadir las dimensiones correspondientes a cada elemento detectado, tomando el tamaño real del recurso o el definido en el diseño.","Identificar cuál es el elemento principal visible al cargar cada tipo de página (por ejemplo, la imagen de cabecera o el titular).","Marcar ese elemento con la prioridad de carga que ofrezca la plataforma (por ejemplo, carga anticipada en vez de diferida).","Verificar visualmente en un entorno de pruebas que no se produzcan saltos de layout al cargar la página."],"reglas":["No declarar dimensiones inventadas: deben corresponder al tamaño real del recurso o al definido en el diseño.","No marcar más de un elemento como 'principal' con prioridad de carga por vista; debe ser el que el usuario ve primero.","Probar los cambios visualmente en distintos tamaños de pantalla antes de publicarlos en producción."],"prompt":"Actúa como ingeniero de rendimiento web enfocado en estabilidad visual. Trabaja sobre el proyecto en [ruta del proyecto].\n\nObjetivo: reducir los saltos de layout durante la carga y priorizar el elemento principal visible en cada tipo de página.\n\nPasos:\n1. Recorre las plantillas y componentes del sitio y localiza imágenes, vídeos o elementos embebidos que no tengan declarado su ancho y alto (o su relación de aspecto).\n2. Para cada uno, añade las dimensiones reales del recurso (o las definidas en el diseño) como atributos o mediante CSS, de forma que el navegador reserve el espacio antes de que cargue el contenido.\n3. Identifica, para cada plantilla de página (home, ficha de producto, artículo, etc.), cuál es el elemento visual principal que el usuario ve primero al entrar.\n4. Aplica a ese elemento la técnica de carga prioritaria disponible en la plataforma (por ejemplo, evitar lazy-loading en él y usar prioridad de carga alta si el framework lo soporta), dejando el resto de imágenes fuera de esa prioridad.\n5. Verifica en un entorno local o de staging, en al menos una vista de escritorio y una móvil, que la página no produzca saltos visibles de layout durante la carga.\n6. Entrega un resumen de los elementos corregidos y las plantillas donde se aplicó la carga prioritaria.\n\nRestricciones: no inventes dimensiones; usa el tamaño real del recurso. No apliques los cambios directamente en producción sin verificarlos antes en un entorno de pruebas. No prometas una puntuación específica en herramientas de medición: la mejora depende también de factores fuera de este alcance."}},
  {"id":"gr08","catalogo":"growth","grupo":"SEO","tema":"Rendimiento técnico","titulo":"Menos saltos, más velocidad: del enlace viejo al destino final sin rodeos","beneficio":"Detecta cuando una URL redirige a otra que a su vez redirige a otra (y así sucesivamente) y las simplifica en un único salto directo, para que la página cargue más rápido y no se pierda información en el camino.","alcance":"Qué sí hace: identifica cadenas de redirecciones (más de un salto entre la URL original y el destino final) y las reemplaza por una única redirección directa. Qué no hace: no decide si una redirección debería existir o no desde el punto de vista de negocio -eso requiere criterio editorial cuando hay contenido fusionado o descontinuado-, y no puede corregir redirecciones gestionadas fuera del proyecto (por ejemplo, a nivel de proveedor de hosting o DNS) sin acceso a esa configuración. Verifica cada cadena manualmente antes de aplicar el cambio si el destino final no es evidente.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre el mapa de redirecciones del sitio, sigue cada cadena hasta su destino final, y sustituye las redirecciones intermedias por un único salto directo de la URL original al destino final.","modo":"Auditoría técnica y corrección","pasos":["Extraer todas las reglas de redirección configuradas en el proyecto.","Para cada URL de origen, seguir la cadena de redirecciones paso a paso hasta llegar a una URL que ya no redirige (destino final).","Marcar como cadena cualquier caso con más de un salto entre origen y destino final.","Reemplazar la cadena por una única regla que apunte directamente del origen al destino final.","Verificar que el destino final sea una página válida (no un error) antes de aplicar el cambio."],"reglas":["Nunca simplificar una cadena si el destino final resulta ser una página de error o ya no existe: reportarlo en vez de crear la redirección directa.","No eliminar las reglas intermedias sin haber confirmado el destino final correcto.","Aplicar los cambios primero en un entorno de pruebas antes de sustituir las reglas en producción."],"prompt":"Actúa como técnico SEO especializado en gestión de redirecciones. Trabaja sobre el archivo o configuración de redirecciones del proyecto en [ruta del proyecto o panel de configuración].\n\nObjetivo: encontrar cadenas de redirección y convertirlas en un salto directo único.\n\nPasos:\n1. Extrae todas las reglas de redirección actuales (301/302) del proyecto.\n2. Para cada URL de origen, sigue la cadena de redirecciones (origen → intermedio 1 → intermedio 2 → ... → destino final), registrando cada salto.\n3. Marca como 'cadena a simplificar' cualquier caso donde haya más de un salto entre el origen y el destino final.\n4. Antes de simplificar, confirma que el destino final devuelve una página válida (no un error 404 o 500); si el destino final está roto, no lo simplifiques, repórtalo como incidencia aparte.\n5. Para las cadenas válidas, crea una nueva regla que redirija directamente del origen al destino final, y elimina o desactiva las reglas intermedias que quedan redundantes.\n6. Entrega un informe con: URL origen, cadena original completa, destino final, y la nueva regla directa propuesta.\n\nRestricciones: no simplifiques cadenas cuyo destino final no hayas podido verificar como válido. No sobrescribas las reglas de producción directamente; entrega los cambios para revisión y despliegue manual."}},
  {"id":"gr09","catalogo":"growth","grupo":"SEO","tema":"Rendimiento técnico","titulo":"Imágenes más ligeras sin que se note la diferencia","beneficio":"Convierte y comprime las imágenes pesadas del sitio a formatos modernos como AVIF o WebP, reduciendo el peso de la página y el tiempo de carga sin sacrificar visiblemente la calidad de la imagen.","alcance":"Qué sí hace: identifica imágenes en formatos más pesados (como JPG o PNG sin comprimir) y genera versiones equivalentes en AVIF o WebP, cuidando que la pérdida de calidad no sea perceptible a simple vista. Qué no hace: no sustituye la necesidad de un buen diseño o selección de imágenes desde el origen, no garantiza compatibilidad automática si el sitio necesita servir el formato antiguo como respaldo para navegadores muy antiguos -eso debe configurarse aparte-, y la reducción de peso no garantiza por sí sola una mejora medible en el posicionamiento. Revisa una muestra de las imágenes convertidas antes de reemplazar las originales en producción.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre las imágenes del sitio, identifica las que están en formatos pesados o sin comprimir, y genera versiones en AVIF y/o WebP con una compresión que mantenga una calidad visual aceptable.","modo":"Conversión de archivos","pasos":["Listar las imágenes del proyecto y su formato y peso actual.","Priorizar las imágenes más pesadas o las que aparecen en páginas de mayor tráfico.","Generar la versión equivalente en formato moderno (AVIF y/o WebP) para cada imagen priorizada.","Comparar visualmente una muestra de originales contra sus conversiones para descartar pérdida de calidad perceptible.","Configurar el sitio para servir el formato moderno con una alternativa (fallback) al formato original para navegadores que no lo soporten."],"reglas":["No aplicar una compresión tan agresiva que la pérdida de calidad sea perceptible a simple vista.","Mantener siempre una alternativa en el formato original o ampliamente soportado para navegadores que no admitan el formato moderno.","Revisar una muestra representativa de las conversiones antes de reemplazar las imágenes originales en producción."],"prompt":"Actúa como ingeniero de rendimiento web enfocado en optimización de imágenes. Trabaja sobre las imágenes del proyecto en [ruta del proyecto o carpeta de assets].\n\nObjetivo: reducir el peso de las imágenes pesadas convirtiéndolas a formatos modernos, sin pérdida de calidad perceptible.\n\nPasos:\n1. Recorre la carpeta de imágenes del proyecto y lista cada archivo con su formato actual y su peso en disco.\n2. Prioriza para conversión las imágenes más pesadas y las que se usan en páginas de mayor tráfico o en el contenido visible al cargar la página (por ejemplo, imágenes de cabecera).\n3. Genera para cada una una versión en formato AVIF y/o WebP, ajustando el nivel de compresión para que el peso se reduzca de forma notable sin que la calidad visual se degrade a simple vista.\n4. Compara visualmente una muestra representativa de imágenes originales contra sus versiones convertidas para confirmar que no hay artefactos ni pérdida de nitidez perceptible.\n5. Configura el marcado o la plataforma para servir el formato moderno como opción principal y el formato original como alternativa (fallback) para navegadores que no soporten AVIF/WebP.\n6. Entrega un resumen con el peso total antes y después de la conversión, y la lista de imágenes convertidas.\n\nRestricciones: no sacrifiques calidad visible por peso; si una imagen se ve peor de forma notoria, ajusta el nivel de compresión o consérvala en su formato original. No elimines los archivos originales del proyecto sin confirmar que el fallback funciona correctamente."}},
  {"id":"gr10","catalogo":"growth","grupo":"SEO","tema":"Rendimiento técnico","titulo":"Carga rápido lo que se ve, deja para después lo que no","beneficio":"Aplica carga diferida (lazy load) a imágenes, vídeos y otros elementos visuales que quedan fuera de la pantalla inicial, para que el navegador priorice lo que el visitante ve de inmediato y la página se sienta más rápida.","alcance":"Qué sí hace: identifica elementos visuales que no son visibles al cargar la página (por estar más abajo del scroll inicial) y les aplica el atributo o técnica de carga diferida correspondiente. Qué no hace: no aplica carga diferida al elemento principal visible al entrar a la página -eso sería contraproducente-, no optimiza el peso de los propios archivos (eso corresponde a la compresión de imágenes), y no garantiza una mejora de rendimiento uniforme en todos los dispositivos, ya que depende también de la conexión del visitante. Comprueba visualmente que el contenido diferido siga apareciendo correctamente al hacer scroll antes de publicar.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre el contenido de cada plantilla, distingue los elementos visibles al cargar la página de los que quedan fuera de esa vista inicial, y aplica carga diferida solo a estos últimos.","modo":"Auditoría técnica y corrección","pasos":["Recorrer las plantillas del sitio e identificar todos los elementos visuales (imágenes, vídeos, iframes) presentes.","Determinar, para cada tipo de página, cuáles de esos elementos son visibles al cargar (por encima del scroll inicial) y cuáles no.","Aplicar la técnica de carga diferida disponible en la plataforma a los elementos que quedan fuera de la vista inicial.","Excluir explícitamente de la carga diferida al elemento principal visible al cargar la página.","Verificar en un entorno de pruebas que los elementos diferidos carguen correctamente al hacer scroll hacia ellos."],"reglas":["Nunca aplicar carga diferida al elemento principal visible al cargar la página.","No aplicar carga diferida de forma general a todo el contenido sin distinguir lo visible de lo que no lo es.","Verificar visualmente el comportamiento del scroll en un entorno de pruebas antes de publicar los cambios."],"prompt":"Actúa como ingeniero de rendimiento web. Trabaja sobre las plantillas del proyecto en [ruta del proyecto].\n\nObjetivo: aplicar carga diferida (lazy load) a los elementos visuales que no son visibles al cargar la página, sin afectar al elemento principal.\n\nPasos:\n1. Recorre las plantillas de cada tipo de página (home, listado, ficha, artículo, etc.) y lista todos los elementos visuales: imágenes, vídeos embebidos, iframes.\n2. Para cada plantilla, determina qué elementos se muestran por encima del scroll inicial (visibles sin interacción) y cuáles quedan más abajo.\n3. Aplica la técnica de carga diferida que ofrezca la plataforma (por ejemplo, el atributo loading='lazy' en imágenes, o la carga diferida de iframes) únicamente a los elementos que quedan fuera de la vista inicial.\n4. Excluye explícitamente de la carga diferida al elemento principal visible al cargar la página en cada plantilla (por ejemplo, la imagen de cabecera).\n5. Prueba en un entorno local o de staging que, al hacer scroll, los elementos diferidos carguen sin retrasos visibles ni huecos en blanco prolongados.\n6. Entrega un resumen de los elementos modificados por plantilla.\n\nRestricciones: no apliques carga diferida al elemento visible al cargar la página. No apliques cambios en producción sin verificar antes el comportamiento de scroll en un entorno de pruebas."}},
  {"id":"gr11","catalogo":"growth","grupo":"SEO","tema":"Datos estructurados y resultados enriquecidos","titulo":"Una respuesta clara y citable justo donde el buscador la busca","beneficio":"Estructura la definición clave de un tema en un párrafo breve y directo justo debajo del encabezado correspondiente, en el formato que los buscadores suelen preferir para mostrar como respuesta destacada a una pregunta.","alcance":"Qué sí hace: identifica encabezados que responden a una pregunta o definición clara y reescribe (o propone reescribir) el párrafo inmediatamente posterior como una respuesta breve y directa, sin cambiar el significado del contenido original. Qué no hace: no puede garantizar que un buscador elija mostrar ese fragmento como respuesta destacada -esa decisión depende del buscador y de la competencia por esa búsqueda-, y no inventa información nueva: solo reorganiza y clarifica lo que ya está en el contenido. El impacto en visibilidad, si ocurre, puede tardar en observarse; revisa el texto reescrito antes de publicarlo para asegurar que mantiene tu tono editorial.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta encabezados que formulan una pregunta o un concepto definible, y reescribe el párrafo que sigue como una respuesta breve y directa colocada justo debajo del encabezado, manteniendo el resto del contenido intacto.","modo":"Edición de contenido existente","pasos":["Recorrer el contenido y localizar encabezados formulados como pregunta o que introducen una definición o concepto clave.","Revisar el párrafo que sigue a cada encabezado y evaluar si responde de forma clara y directa desde la primera frase.","Cuando no lo haga, proponer una reescritura de ese párrafo como una respuesta breve y directa, colocada inmediatamente después del encabezado.","Mantener el resto del contenido (ejemplos, matices, desarrollo posterior) sin alterar.","Entregar los encabezados intervenidos junto con el texto original y el propuesto, para revisión editorial."],"reglas":["No inventar información nueva: la respuesta reescrita debe basarse únicamente en lo que ya dice el contenido existente.","No prometer ni dar por hecho que el fragmento aparecerá como respuesta destacada en un buscador.","Conservar el tono editorial del resto del contenido; no convertir el texto en un estilo robótico o artificial."],"prompt":"Actúa como editor de contenido especializado en optimización para fragmentos destacados. Trabaja sobre el contenido de [ruta del artículo o URL].\n\nObjetivo: estructurar las definiciones y respuestas clave del contenido como párrafos breves y directos, sin inventar información nueva.\n\nPasos:\n1. Recorre el contenido y localiza los encabezados (H2, H3) que formulan una pregunta explícita o introducen un concepto que se puede definir en pocas frases.\n2. Para cada uno, lee el párrafo inmediatamente posterior y evalúa si responde de forma clara y directa desde su primera frase, o si se desvía con contexto antes de llegar al punto.\n3. Cuando el párrafo no sea suficientemente directo, propón una reescritura breve (unas pocas frases) que responda la pregunta o defina el concepto de inmediato, basada estrictamente en la información que ya existe en el texto (no añadas datos nuevos ni afirmaciones no verificadas en el original).\n4. Deja el desarrollo, ejemplos y matices existentes después de ese párrafo inicial, sin eliminarlos.\n5. Entrega, para cada encabezado intervenido: el encabezado, el párrafo original y el párrafo propuesto, para que yo decida si aplicarlo.\n\nRestricciones: no inventes cifras, datos o afirmaciones que no estén ya en el contenido original. No des por garantizado que esto hará aparecer el contenido como respuesta destacada en un buscador; es una mejora de claridad editorial, no una garantía de resultado."}},
  {"id":"gr12","catalogo":"growth","grupo":"SEO","tema":"Datos estructurados y resultados enriquecidos","titulo":"Preguntas frecuentes que los buscadores pueden leer y mostrar como respuesta","beneficio":"Añade el marcado técnico (schema JSON-LD) que describe tus preguntas frecuentes de forma que los buscadores puedan leerlas con claridad, usando exactamente el mismo texto que ya ves publicado en la página.","alcance":"Qué sí hace: genera el marcado JSON-LD de tipo FAQ a partir de las preguntas y respuestas que ya existen visibles en la página, verificando que el texto del marcado coincida palabra por palabra con el texto visible. Qué no hace: no redacta preguntas y respuestas nuevas por iniciativa propia sin que existan ya en el contenido visible, no garantiza que el buscador muestre un resultado enriquecido con esas preguntas, y las políticas de qué contenido es elegible para resultados enriquecidos las define cada buscador y pueden cambiar. Revisa el marcado generado antes de publicarlo, sobre todo si el contenido visible cambia con el tiempo.","precio":1.99,"blueprint":{"quePuedeHacer":"Extrae las preguntas y respuestas visibles en una página, genera el marcado JSON-LD de tipo FAQPage correspondiente, y valida que cada pregunta y respuesta del marcado coincida exactamente con el texto visible en la página.","modo":"Generación de marcado (JSON-LD)","pasos":["Identificar en la página el bloque de preguntas frecuentes visibles para el usuario, con su pregunta y su respuesta.","Copiar el texto exacto de cada pregunta y respuesta, sin parafrasear ni resumir.","Generar el marcado JSON-LD de tipo FAQPage con esas preguntas y respuestas.","Comparar automáticamente el texto del marcado contra el texto visible para confirmar que coinciden palabra por palabra.","Insertar el marcado en la página, y señalar cualquier pregunta del marcado que no tenga una correspondencia exacta en el texto visible."],"reglas":["El texto de cada pregunta y respuesta en el marcado debe coincidir exactamente (palabra por palabra) con el texto visible en la página; nunca marcar contenido que no esté visible para el usuario.","No crear preguntas o respuestas nuevas que no existan ya en el contenido visible de la página.","Revisar el marcado generado antes de publicarlo, y actualizarlo si el contenido visible de las preguntas cambia."],"prompt":"Actúa como especialista en datos estructurados (schema.org). Trabaja sobre la página en [ruta o URL de la página] dentro del proyecto en [ruta del proyecto].\n\nObjetivo: generar el marcado JSON-LD de tipo FAQPage a partir de las preguntas frecuentes ya visibles en la página, sin inventar contenido.\n\nPasos:\n1. Localiza el bloque de preguntas frecuentes visible para el usuario en esta página y extrae el texto exacto de cada pregunta y su respuesta correspondiente.\n2. Genera el marcado JSON-LD siguiendo la estructura de schema.org para FAQPage, usando literalmente ese mismo texto (sin parafrasear, resumir ni corregir redacción).\n3. Compara, pregunta por pregunta, el texto del marcado contra el texto visible en el HTML de la página, y reporta cualquier discrepancia, por mínima que sea.\n4. Si detectas alguna pregunta en el marcado sin correspondencia exacta en el texto visible (o viceversa), no la incluyas hasta corregir la discrepancia.\n5. Inserta el bloque script tipo application/ld+json con el marcado validado en la página.\n6. Entrega el marcado final junto con la comparación pregunta por pregunta que confirma la coincidencia palabra por palabra.\n\nRestricciones: nunca generes una pregunta o respuesta en el marcado que no exista, con el mismo texto, visible para el usuario en la página. No des por hecho que esto activará un resultado enriquecido en un buscador determinado; es una condición necesaria pero no una garantía."}},
  {"id":"gr13","catalogo":"growth","grupo":"SEO","tema":"Datos estructurados y resultados enriquecidos","titulo":"Una ruta de migas de pan que refleja de verdad cómo se organiza tu web","beneficio":"Genera el marcado de breadcrumbs (la ruta tipo 'Inicio > Categoría > Página') a partir de la estructura real de carpetas o categorías del sitio, para ayudar a los buscadores a mostrar esa ruta y a los usuarios a entender dónde están.","alcance":"Qué sí hace: reconstruye la jerarquía de cada página a partir de su ubicación real en la estructura del sitio (carpetas, categorías) y genera el marcado de breadcrumbs correspondiente. Qué no hace: no puede inventar una jerarquía coherente si la organización real del sitio es inconsistente o no tiene una estructura de categorías clara -en ese caso, primero hay que ordenar la arquitectura del sitio-, y no garantiza que el buscador muestre visualmente esa ruta en los resultados. Revisa que la ruta generada tenga sentido para un usuario antes de publicarla.","precio":1.99,"blueprint":{"quePuedeHacer":"Determina la ruta jerárquica real de cada página según su ubicación en carpetas o categorías del sitio, y genera el marcado JSON-LD de tipo BreadcrumbList correspondiente, junto con la versión visible de esa ruta si el sitio no la muestra aún.","modo":"Generación de marcado (JSON-LD)","pasos":["Determinar, para cada página, su ruta jerárquica real según la estructura de carpetas o categorías del sitio (no una ruta inventada).","Construir la secuencia completa desde la página de inicio hasta la página actual, con el nombre y la URL de cada nivel intermedio.","Generar el marcado JSON-LD de tipo BreadcrumbList con esa secuencia.","Verificar que cada nivel de la ruta corresponda a una página real y navegable del sitio, no a una categoría inexistente.","Entregar el marcado junto con la versión visible de la ruta, para revisión antes de publicar."],"reglas":["La ruta jerárquica del marcado debe corresponder a la estructura real de navegación del sitio, no a una jerarquía inventada para parecer más organizada.","Cada nivel intermedio de la ruta debe apuntar a una página real y accesible, nunca a una URL que no existe.","Revisar que la ruta generada tenga sentido de navegación para un usuario antes de publicarla."],"prompt":"Actúa como especialista en datos estructurados (schema.org). Trabaja sobre el proyecto en [ruta del proyecto].\n\nObjetivo: generar el marcado de breadcrumbs (BreadcrumbList) reflejando la jerarquía real del sitio.\n\nPasos:\n1. Para cada página del sitio, determina su ubicación real dentro de la estructura de carpetas o categorías (por ejemplo: Inicio > Categoría > Subcategoría > Página).\n2. Si la organización real del sitio es inconsistente o no tiene una jerarquía clara para alguna página, no inventes una ruta: repórtalo como un caso que requiere primero ordenar la arquitectura del sitio.\n3. Para las páginas con jerarquía clara, construye la secuencia completa de niveles desde el inicio hasta la página actual, con el nombre visible y la URL de cada nivel.\n4. Genera el marcado JSON-LD de tipo BreadcrumbList con esa secuencia, usando las propiedades estándar (position, name, item).\n5. Verifica que cada URL de nivel intermedio en el marcado corresponda a una página real y accesible del sitio.\n6. Si el sitio no muestra actualmente una ruta de navegación visible, propón también el texto visible equivalente (ej. 'Inicio > Categoría > Página').\n7. Entrega el marcado y la ruta visible propuesta por página, para revisión.\n\nRestricciones: no inventes niveles de jerarquía que no existan en la estructura real de navegación del sitio. No apliques los cambios en producción sin revisión previa."}},
  {"id":"gr14","catalogo":"growth","grupo":"SEO","tema":"Monitorización y limpieza técnica","titulo":"Saber quién visita tu web de verdad: Google o alguien que finge serlo","beneficio":"Analiza los registros de acceso al servidor para distinguir las visitas reales de Googlebot (u otros buscadores legítimos) de bots que solo dicen serlo, dándote una visión más fiable de qué rastrea de verdad tu sitio.","alcance":"Qué sí hace: revisa los registros de acceso del servidor, identifica las peticiones que se identifican como Googlebot u otros bots de buscadores, y verifica mediante resolución DNS inversa si esas peticiones provienen realmente de las redes de esos buscadores o si son suplantaciones. Qué no hace: no bloquea nada por sí solo -eso corresponde al compilador de robots.txt o a la configuración del servidor-, no tiene visibilidad de accesos que no queden registrados en los logs disponibles, y no sustituye herramientas oficiales de cada buscador para confirmar el rastreo. Este análisis es un diagnóstico, no una corrección automática.","precio":1.99,"blueprint":{"quePuedeHacer":"Recorre los registros de acceso del servidor, filtra las peticiones que declaran ser un bot de buscador conocido, y verifica mediante resolución DNS inversa (y verificación directa posterior) si la IP de origen pertenece realmente a la red de ese buscador.","modo":"Análisis de registros (logs)","pasos":["Reunir los registros de acceso del servidor correspondientes al periodo a analizar.","Filtrar las peticiones cuyo user-agent se identifica como un bot de buscador conocido (por ejemplo, Googlebot, Bingbot).","Para cada IP de origen de esas peticiones, realizar una resolución DNS inversa y comprobar si el dominio resultante pertenece a la red oficial del buscador correspondiente.","Confirmar los casos dudosos con una resolución DNS directa adicional sobre el dominio obtenido, siguiendo el método de verificación recomendado por el propio buscador.","Clasificar las peticiones en 'bot verificado' y 'posible suplantación', y entregar un resumen con ejemplos de cada categoría."],"reglas":["No dar por verificado un bot solo por el texto de su user-agent; siempre confirmar mediante resolución DNS inversa y directa.","No bloquear ni tomar acciones automáticas sobre las IPs marcadas como sospechosas: solo reportar para que una persona decida.","Dejar claro en el informe qué parte de las peticiones no pudo verificarse por falta de datos suficientes en los logs."],"prompt":"Actúa como analista técnico de tráfico web. Trabaja sobre los registros de acceso del servidor ubicados en [ruta de los logs] correspondientes al periodo [rango de fechas].\n\nObjetivo: distinguir las peticiones reales de bots de buscadores legítimos de las que solo simulan serlo mediante el user-agent.\n\nPasos:\n1. Reúne y parsea los registros de acceso del periodo indicado.\n2. Filtra las peticiones cuyo user-agent se identifica como un bot de buscador conocido (Googlebot, Bingbot, u otros que definamos).\n3. Para cada IP de origen distinta encontrada en esas peticiones, realiza una resolución DNS inversa (rDNS) para obtener el nombre de dominio asociado.\n4. Verifica si ese dominio pertenece a la red oficial del buscador correspondiente (por ejemplo, dominios de Google para Googlebot) y, cuando sea posible, confirma con una resolución DNS directa adicional sobre ese dominio para comprobar que apunta de vuelta a la misma IP.\n5. Clasifica cada IP como 'bot verificado', 'posible suplantación' o 'no se pudo verificar por datos insuficientes'.\n6. Entrega un resumen con el número de peticiones por categoría, ejemplos de IPs sospechosas, y qué proporción del tráfico total de bots representa cada categoría.\n\nRestricciones: no concluyas que una petición es un bot legítimo basándote solo en el texto del user-agent. No tomes ninguna acción de bloqueo automáticamente; este análisis es solo diagnóstico y las decisiones de bloqueo las tomo yo con el siguiente blueprint."}},
  {"id":"gr15","catalogo":"growth","grupo":"SEO","tema":"Monitorización y limpieza técnica","titulo":"Una puerta con reglas claras sobre quién puede entrar a copiar tu contenido","beneficio":"Genera o actualiza el archivo robots.txt del sitio, bloqueando de forma explícita a bots conocidos de recolección masiva de datos que no aportan valor a tu negocio, mientras mantiene abierto el acceso a los buscadores que sí te interesan.","alcance":"Qué sí hace: genera reglas explícitas en robots.txt para bloquear bots identificados de scraping o recolección de datos no deseada, manteniendo el acceso permitido a buscadores legítimos y a los bots que decidas permitir. Qué no hace: robots.txt es una directriz que los bots bien identificados respetan voluntariamente, no una barrera técnica infranqueable -un bot malicioso puede ignorarla-, así que no sustituye medidas de bloqueo a nivel de servidor si la protección necesita ser estricta. Tampoco decide por ti qué bots de IA o de terceros quieres permitir; esa es una decisión de negocio que debes confirmar antes de aplicar el archivo.","precio":1.99,"blueprint":{"quePuedeHacer":"Genera el archivo robots.txt del sitio con reglas explícitas de bloqueo para bots de scraping conocidos, reglas de permiso para buscadores legítimos, y la referencia al sitemap del sitio.","modo":"Generación de archivo","pasos":["Reunir la lista de bots que se quieren bloquear explícitamente y la lista de buscadores/bots que deben mantenerse permitidos, según la decisión de negocio del cliente.","Redactar las reglas de bloqueo (Disallow) específicas para cada bot no deseado identificado por su user-agent.","Redactar las reglas de permiso (Allow) para los bots legítimos que deben conservar acceso.","Añadir la referencia al sitemap.xml del sitio dentro del archivo.","Validar que el archivo generado sea sintácticamente correcto y no bloquee por error a buscadores legítimos."],"reglas":["Nunca bloquear por error a los buscadores legítimos que el negocio necesita para su visibilidad (a menos que se indique explícitamente lo contrario).","No presentar robots.txt como una medida de seguridad infalible: es una directriz que solo respetan los bots que la cumplen voluntariamente.","Confirmar con el cliente la lista de bots de IA o terceros a bloquear o permitir antes de aplicar el archivo, ya que es una decisión de negocio."],"prompt":"Actúa como técnico SEO especializado en configuración de rastreo. Trabaja sobre el proyecto en [ruta del proyecto].\n\nObjetivo: generar un archivo robots.txt que bloquee explícitamente a bots de scraping no deseados y mantenga el acceso de los buscadores legítimos.\n\nPasos:\n1. Confirma conmigo la lista de bots a bloquear explícitamente (por ejemplo, bots de scraping masivo de contenido o de entrenamiento de IA que no quiero permitir) y la lista de buscadores/bots que deben mantenerse permitidos.\n2. Redacta las reglas User-agent / Disallow específicas para cada bot no deseado, usando su user-agent identificado públicamente por ese proveedor.\n3. Redacta las reglas de permiso explícito para los buscadores legítimos que deben conservar acceso completo.\n4. Añade la línea Sitemap apuntando a la URL absoluta del sitemap.xml del sitio.\n5. Revisa el archivo resultante línea por línea para confirmar que ninguna regla bloquea por error a un buscador legítimo que sí queremos permitir.\n6. Entrega el archivo robots.txt final junto con una tabla que explique qué bloquea cada regla y por qué.\n\nRestricciones: no bloquees ningún bot sin que yo confirme la lista primero. Deja explícito en tu respuesta que robots.txt es una directriz voluntaria, no una barrera técnica garantizada, y que un bot malicioso puede ignorarla."}},
  {"id":"gr16","catalogo":"growth","grupo":"SEO","tema":"Monitorización y limpieza técnica","titulo":"Una alarma temprana cuando tu visibilidad en buscadores cae de golpe","beneficio":"Revisa periódicamente los datos de impresiones y clics de Search Console y te avisa cuando detecta una caída notable, para que puedas investigar la causa (un cambio técnico, una actualización del buscador, un problema de indexación) antes de que se acumule el impacto.","alcance":"Qué sí hace: compara periódicamente los datos de Search Console con el histórico reciente y avisa cuando identifica una caída relevante en impresiones o clics, señalando las páginas o consultas más afectadas. Qué no hace: no diagnostica automáticamente la causa de la caída -eso requiere investigación humana con el contexto del negocio-, no puede prevenir caídas causadas por cambios en el algoritmo del buscador, que están fuera de tu control, y no sustituye la revisión manual periódica de Search Console. Las fluctuaciones normales de tráfico no siempre indican un problema; usa este aviso como punto de partida para investigar, no como una alarma de fallo garantizado.","precio":1.99,"blueprint":{"quePuedeHacer":"Extrae periódicamente los datos de impresiones y clics de Search Console, los compara contra el histórico reciente, y genera un aviso cuando detecta una caída relevante, identificando las páginas o consultas donde se concentra.","modo":"Monitorización recurrente","pasos":["Extraer los datos de impresiones y clics de Search Console para el periodo más reciente y para un periodo de referencia anterior comparable.","Calcular la variación entre ambos periodos a nivel de sitio, y también desglosada por página y por consulta principal.","Identificar las caídas que se salen claramente del rango de variación habitual observado en el histórico del propio sitio.","Generar un aviso con las páginas o consultas donde se concentra la caída, sin diagnosticar la causa.","Registrar el aviso junto con la fecha y los datos comparados, para poder consultar el histórico de avisos anteriores."],"reglas":["No diagnosticar automáticamente la causa de una caída (por ejemplo, atribuirla a una actualización de algoritmo sin evidencia); solo reportar el hecho y los datos afectados.","Comparar siempre contra el histórico propio del sitio para definir qué es una variación habitual, en vez de usar un umbral fijo genérico.","No enviar avisos por fluctuaciones que estén dentro del rango de variación normal observado previamente en el propio sitio."],"prompt":"Actúa como analista de monitorización SEO. Trabaja con los datos de Search Console de la propiedad [dominio o propiedad de Search Console], a los que tienes acceso mediante [API/exportación de datos disponible].\n\nObjetivo: detectar caídas relevantes de impresiones o clics y avisar con el detalle necesario para investigar, sin diagnosticar la causa por tu cuenta.\n\nPasos:\n1. Extrae los datos de impresiones y clics del periodo más reciente disponible y de un periodo de referencia anterior comparable (por ejemplo, la semana o el mes previo).\n2. Calcula la variación a nivel de sitio completo, y desglosada por página y por consulta principal.\n3. Compara esta variación contra el rango de fluctuación habitual que ha mostrado este mismo sitio en periodos anteriores (no uses un umbral fijo genérico; usa el propio histórico como referencia).\n4. Cuando detectes una caída que se sale claramente de ese rango habitual, genera un aviso indicando: qué páginas y consultas concentran la caída, la magnitud de la variación, y el periodo comparado.\n5. No intentes determinar la causa de la caída (no afirmes que se debe a una actualización de algoritmo, un problema técnico u otra causa sin evidencia directa); limítate a señalar el hecho y los datos.\n6. Guarda el aviso con fecha para poder comparar con avisos futuros.\n\nRestricciones: no generes avisos por variaciones que estén dentro del rango de fluctuación normal ya observado en el histórico de este sitio. No diagnostiques la causa raíz; eso requiere revisión humana con contexto adicional del negocio."}},
  {"id":"gr17","catalogo":"growth","grupo":"SEO","tema":"Monitorización y limpieza técnica","titulo":"Que el contenido real de tu página pese más que el código que lo envuelve","beneficio":"Revisa la proporción entre el texto real que lee un visitante y el código que lo envuelve, y avisa cuando el marcado resulta excesivo en relación al contenido, una señal que suele acompañar a páginas con exceso de código innecesario o poco contenido sustancial.","alcance":"Qué sí hace: calcula la proporción entre el texto visible y el HTML total de una página, y avisa cuando esa proporción se aleja notablemente de lo observado en el resto del sitio o en páginas comparables. Qué no hace: esta proporción no es en sí misma un factor de posicionamiento confirmado por los buscadores ni predice una mejora si se corrige; es un indicador de higiene técnica que puede señalar código innecesario, plantillas infladas o contenido escaso, pero requiere revisión humana para decidir qué hacer en cada caso. No reduce el código automáticamente ni reescribe el contenido.","precio":1.99,"blueprint":{"quePuedeHacer":"Calcula, para cada página, la proporción entre el texto visible y el volumen total de HTML, la compara contra el resto del sitio o páginas equivalentes, y avisa cuando una página se aleja notablemente de ese patrón.","modo":"Auditoría técnica","pasos":["Extraer el HTML completo de cada página y separar el texto realmente visible para el usuario del resto del marcado.","Calcular la proporción entre el peso o volumen del texto visible y el peso total del HTML de la página.","Comparar esa proporción contra el promedio observado en páginas equivalentes del mismo sitio (por ejemplo, otras fichas de producto o artículos del mismo tipo).","Señalar las páginas cuya proporción se aleja notablemente del patrón habitual del sitio, indicando si el problema es exceso de marcado o escasez de contenido.","Entregar el listado de páginas señaladas para revisión editorial o técnica, sin aplicar cambios automáticamente."],"reglas":["No presentar esta proporción como un factor de posicionamiento confirmado; es un indicador de higiene técnica, no una métrica de ranking.","Comparar siempre contra páginas equivalentes del mismo sitio, no contra un umbral genérico externo.","No modificar código ni contenido automáticamente; solo señalar los casos para revisión humana."],"prompt":"Actúa como auditor técnico de SEO. Trabaja sobre el proyecto en [ruta del proyecto].\n\nObjetivo: calcular la proporción entre texto visible y HTML total de las páginas, y señalar las que se alejan del patrón habitual del sitio.\n\nPasos:\n1. Para una muestra representativa de páginas (o todas las páginas indexables), extrae el HTML completo y separa el texto realmente visible para el usuario (sin contar etiquetas, scripts, estilos ni comentarios) del resto del marcado.\n2. Calcula, para cada página, la proporción entre el peso del texto visible y el peso total del HTML.\n3. Agrupa las páginas por tipo (ficha de producto, artículo, categoría, etc.) y calcula el promedio de esa proporción dentro de cada grupo.\n4. Señala las páginas cuya proporción se aleja notablemente del promedio de su propio grupo, indicando si el motivo aparente es un exceso de marcado (mucho código, poco texto) o una escasez real de contenido.\n5. Entrega el listado de páginas señaladas junto con su proporción, el promedio de su grupo, y una hipótesis (marcada como tal, no como conclusión) del motivo de la desviación.\n\nRestricciones: no afirmes que esta proporción es un factor de posicionamiento confirmado por los buscadores; preséntalo como un indicador de higiene técnica. No modifiques código ni contenido de forma automática; tu salida es un informe para que una persona decida qué acción tomar."}},
  {"id":"gr18","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Contenido preparado para IA","titulo":"Que la IA pueda citar cada parte de tu contenido sin perder el hilo","beneficio":"Cuando un asistente de IA busca una respuesta, procesa tu contenido en trozos, no de una sola vez. Si cada trozo se explica a sí mismo, es más fácil que ese fragmento tenga sentido aislado y pueda usarse como fuente de una respuesta.","alcance":"Sí hace: reestructura un texto ya escrito en fragmentos temáticos autocontenidos, cada uno con un encabezado de contexto explícito (\"Contexto: Tema > Subtema\"), sin depender de lo dicho antes o después. No hace: no garantiza que ChatGPT, Perplexity o Gemini elijan citar tu contenido en vez del de un competidor, ni sustituye una buena arquitectura de información en el resto del sitio. La visibilidad en IA es un terreno cambiante y esto es una buena práctica razonable, no una fórmula garantizada.","precio":1.99,"blueprint":{"quePuedeHacer":"Toma un artículo, ficha o página larga y la reorganiza en una serie de bloques autocontenidos, cada uno encabezado con un contexto explícito, de forma que un sistema de recuperación de información (RAG) o un asistente de IA pueda procesar cada bloque por separado sin perder de vista de qué está hablando.","modo":"Revisión editorial puntual sobre un texto existente; no es un proceso automático continuo, conviene repetirlo cuando el contenido cambie de forma sustancial.","pasos":["Lee el texto completo e identifica los bloques de significado que podrían entenderse de forma independiente.","Escribe, para cada bloque, un encabezado de contexto con el formato 'Contexto: Tema general > Subtema específico'.","Reescribe la primera frase de cada fragmento para que no dependa de referencias previas (evita 'como vimos antes', 'esto', 'dicho lo anterior').","Revisa que cada fragmento conteste, por sí solo, una pregunta implícita completa.","Confirma que el orden de los fragmentos siga teniendo sentido de lectura para una persona, no solo para una máquina."],"reglas":["Nunca recortes información relevante solo para acortar un fragmento si eso lo deja incompleto o ambiguo.","Cada fragmento debe poder leerse de forma aislada, fuera de contexto, sin perder su significado esencial."],"prompt":"Actúa como editor especializado en preparar contenido para sistemas de recuperación de información (RAG) y asistentes de IA conversacional. Te voy a pegar un texto largo. Tu tarea: 1) Divide el texto en fragmentos temáticos autocontenidos, cada uno centrado en una sola idea o pregunta. 2) Antepón a cada fragmento una línea con el formato 'Contexto: [Tema general] > [Subtema específico]'. 3) Reescribe la primera frase de cada fragmento para que no dependa de fragmentos anteriores (evita expresiones como 'como se mencionó antes', 'esto', 'dicho esto'). 4) No inventes información nueva ni elimines datos relevantes del original; si un fragmento queda demasiado corto para tener sentido solo, únelo con el fragmento vecino más relacionado. 5) Entrega el resultado como una lista numerada de fragmentos, cada uno con su encabezado de contexto en la primera línea. Texto a procesar: [PEGA AQUÍ EL TEXTO COMPLETO]"}},
  {"id":"gr19","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Contenido preparado para IA","titulo":"Limpia tu contenido de lo que confunde a los robots de IA (y no aporta nada a tus lectores)","beneficio":"Elimina de la lectura automática el ruido que rodea a tu contenido real: menús repetidos, avisos de cookies, textos de widgets. Así un asistente de IA que analiza tu página llega antes a la información que de verdad importa.","alcance":"Sí hace: revisa el HTML o el texto extraído de una página y separa el contenido informativo del ruido estructural (navegación, JavaScript en línea, popups, banners). No hace: no modifica el código de tu web por ti (eso lo aplica quien mantenga el sitio) ni garantiza cómo procesa tu página cada bot de IA en particular, ya que cada uno indexa de forma distinta y ese comportamiento no es público ni estable.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza el texto o HTML de una página y separa el contenido informativo real del ruido estructural (menús, pies de página repetidos, banners de cookies, scripts, textos de interfaz) que no aporta valor a un lector humano ni a un sistema de indexación automática.","modo":"Auditoría manual sobre una página a la vez; conviene pasarla antes de publicar contenido nuevo o al revisar las páginas más visitadas del sitio.","pasos":["Pega el HTML o el texto ya extraído de la página que quieres revisar.","Identifica bloques de navegación, pies de página repetidos, avisos de cookies y widgets dinámicos (chats, carruseles, formularios flotantes).","Marca los fragmentos de JavaScript en línea o textos de interfaz que no son contenido legible para un lector.","Genera una versión 'limpia' que conserve solo el contenido sustantivo de la página.","Señala qué elementos convendría quitar del flujo principal o mover fuera del bloque de contenido cuando alguien edite la plantilla."],"reglas":["No elimines contenido editorial real aunque esté mal ubicado en la página; señálalo para reubicarlo, no para borrarlo.","Distingue con claridad entre 'ruido de interfaz' y contenido de apoyo legítimo (un aviso legal breve, por ejemplo), que puede quedarse donde está."],"prompt":"Actúa como auditor técnico especializado en preparar páginas web para que su contenido sea legible tanto por humanos como por sistemas automáticos de indexación. Te voy a pegar el HTML o el texto extraído de una página. Tu tarea: 1) Identifica y lista los bloques que son ruido estructural: menús de navegación, pies de página repetidos, avisos de cookies, banners promocionales, widgets de chat o carruseles, y fragmentos de JavaScript en línea sin contenido legible. 2) Genera una versión limpia del texto que conserve únicamente el contenido sustantivo (el que un lector humano vino a buscar). 3) Para cada elemento de ruido detectado, indica en una frase por qué no aporta valor informativo. 4) No elimines contenido editorial legítimo aunque esté mal posicionado: señálalo aparte como 'reubicar', no como 'eliminar'. Entrega el resultado en dos bloques: 'Contenido limpio' y 'Ruido detectado (con motivo)'. HTML o texto a analizar: [PEGA AQUÍ EL HTML O TEXTO]"}},
  {"id":"gr20","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Contenido preparado para IA","titulo":"Escribe para que la IA sepa quién hace qué, sin pronombres sueltos que confundan","beneficio":"Sustituye frases pasivas y palabras ambiguas como 'esto' o 'ello' por sujetos y nombres explícitos, para que un modelo de lenguaje no tenga que adivinar de qué o de quién estás hablando cuando analiza tu contenido.","alcance":"Sí hace: reescribe frases pasivas o ambiguas en voz activa, con sujetos claros y nombres propios en vez de referencias vagas. No hace: no cambia el significado ni la intención editorial del texto original, y sigue haciendo falta una revisión humana final para conservar el tono de marca.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa un texto y localiza construcciones pasivas ('fue implementado por', 'se decidió que') y pronombres o referencias ambiguas ('esto', 'ello', 'dicha función'), proponiendo una reescritura en voz activa con sujetos y nombres explícitos que faciliten el análisis automático del texto.","modo":"Revisión de estilo sobre un texto ya redactado; se aplica antes de publicar o al actualizar contenido existente.","pasos":["Lee el texto e identifica cada frase en voz pasiva o con sujeto implícito.","Localiza pronombres o referencias ambiguas que dependan de una frase anterior para entenderse ('esto', 'ello', 'el mismo').","Reescribe cada frase en voz activa, nombrando explícitamente quién realiza la acción.","Sustituye los pronombres ambiguos por el nombre concreto al que se refieren, aunque se repita más de lo habitual en redacción tradicional.","Compara la versión final con el original para confirmar que el significado y el tono no cambiaron."],"reglas":["No alteres el significado ni los datos del texto original: el objetivo es la claridad del sujeto, no reescribir el contenido.","Si la voz pasiva es una elección deliberada de estilo editorial (por ejemplo, para suavizar un tono), señálalo como duda en vez de cambiarlo automáticamente."],"prompt":"Actúa como editor de estilo especializado en redacción clara para lectura automática por modelos de lenguaje. Te voy a pegar un texto. Tu tarea: 1) Identifica cada construcción en voz pasiva o con sujeto ambiguo. 2) Identifica cada uso de pronombres vagos ('esto', 'ello', 'el mismo', 'dicha función') que dependan de contexto previo para entenderse. 3) Reescribe esas frases en voz activa, nombrando explícitamente quién o qué realiza cada acción, y sustituye los pronombres ambiguos por el nombre concreto al que se refieren. 4) No cambies el significado, los datos ni el tono general del texto: solo la claridad del sujeto. 5) Entrega el resultado en dos columnas o bloques: 'Original' y 'Reescrito', frase por frase, solo para las frases que cambiaste. Si alguna frase pasiva parece una elección de estilo deliberada, señálala aparte con una nota en vez de reescribirla directamente. Texto a revisar: [PEGA AQUÍ EL TEXTO]"}},
  {"id":"gr21","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Contenido preparado para IA","titulo":"Convierte un manual largo en un resumen que un asistente de IA pueda leer de un vistazo","beneficio":"Comprime documentación extensa (manuales, políticas, fichas técnicas) en bloques compactos con la información esencial, para que un asistente de IA pueda procesarla en una sola lectura en vez de perderse en un documento larguísimo.","alcance":"Sí hace: resume y prioriza la información clave de un documento extenso, organizada en bloques compactos y jerarquizados. No hace: no reemplaza el documento original, que debe seguir disponible como fuente completa y de referencia, ni garantiza que un asistente de IA use el resumen en vez del documento íntegro cuando ambos estén disponibles.","precio":1.99,"blueprint":{"quePuedeHacer":"Toma un documento extenso (manual, política interna, ficha técnica) y genera una versión condensada, organizada por bloques temáticos compactos, que conserve los datos esenciales y elimine relleno, repeticiones y ejemplos redundantes.","modo":"Síntesis puntual sobre un documento ya existente; se repite cuando el documento fuente cambia de forma relevante.","pasos":["Lee el documento completo e identifica sus secciones temáticas principales.","Extrae, de cada sección, los datos, condiciones o pasos que son imprescindibles para entender esa parte.","Elimina ejemplos redundantes, repeticiones y frases de relleno que no aportan información nueva.","Organiza el resumen en bloques compactos, cada uno con un título claro que identifique de qué trata.","Verifica que ningún dato crítico (una condición, una excepción, un requisito) se haya perdido en la compresión."],"reglas":["No sacrifiques una condición, excepción o requisito importante solo por acortar el texto; prioriza la fidelidad sobre la brevedad cuando haya conflicto.","Deja explícito en el resumen que existe un documento original más completo como fuente de referencia, sin sustituirlo."],"prompt":"Actúa como sintetizador técnico especializado en condensar documentación extensa sin perder información crítica. Te voy a pegar un documento largo. Tu tarea: 1) Identifica las secciones temáticas principales del documento. 2) Para cada sección, extrae únicamente los datos, condiciones, pasos o excepciones imprescindibles para entenderla, eliminando ejemplos redundantes y frases de relleno. 3) Organiza el resultado en bloques compactos, cada uno con un título claro. 4) No omitas ninguna condición, excepción o requisito que cambie el significado práctico del original, aunque eso haga el bloque un poco más largo. 5) Al final, añade una línea que indique que este es un resumen y que el documento original completo debe seguir disponible como referencia. Entrega el resultado como una lista de bloques temáticos numerados, cada uno con su título y su contenido condensado. Documento a resumir: [PEGA AQUÍ EL DOCUMENTO]"}},
  {"id":"gr22","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Reputación y precisión en respuestas de IA","titulo":"Descubre qué dicen ChatGPT y Perplexity de tu marca cuando tú no estás mirando","beneficio":"Te da un método para revisar cómo distintos asistentes de IA describen tu marca frente a tu competencia, y si el tono de esa descripción es positivo, neutro o negativo, para que sepas dónde reforzar tu mensaje.","alcance":"Sí hace: estructura una batería de preguntas para hacerle a distintos asistentes de IA y una plantilla para registrar y comparar sus respuestas a lo largo del tiempo. No hace: no consulta ChatGPT, Perplexity o Gemini en tiempo real de forma automática por ti (las preguntas se hacen manualmente), ni garantiza que las respuestas se mantengan iguales en el futuro o entre distintos usuarios: las respuestas de los asistentes de IA cambian y no son las mismas para todo el mundo.","precio":1.99,"blueprint":{"quePuedeHacer":"Diseña un conjunto de preguntas representativas sobre tu marca y tu categoría de negocio para hacerle a varios asistentes de IA, y una plantilla para registrar, comparar y clasificar el tono de cada respuesta (positivo, neutro, negativo) frente a la competencia mencionada.","modo":"Auditoría manual periódica; requiere que una persona haga las consultas a cada asistente y registre las respuestas, no es una conexión automática a las APIs de esos asistentes.","pasos":["Redacta una lista de preguntas que un cliente potencial podría hacerle a un asistente de IA sobre tu categoría de negocio (qué es, quién lo ofrece, cómo comparar opciones).","Haz esas preguntas, una por una, a varios asistentes de IA distintos, guardando la respuesta textual de cada uno.","Clasifica cada respuesta según si menciona tu marca, si la compara con competidores, y el tono general (positivo, neutro, negativo).","Registra afirmaciones concretas sobre tu marca que aparezcan en las respuestas, para revisarlas por separado.","Repite el ejercicio con una frecuencia razonable para detectar cambios en cómo te describen con el tiempo."],"reglas":["No presentes una sola consulta puntual como si fuera una medición definitiva: registra fecha, asistente usado y la pregunta exacta para poder comparar en el tiempo.","Distingue claramente entre lo que el asistente afirma como hecho y lo que presenta como opinión o generalización."],"prompt":"Actúa como analista de reputación de marca en respuestas de asistentes de IA. Te voy a dar el nombre de mi marca, mi categoría de negocio y hasta tres competidores. Tu tarea: 1) Redacta una lista de 8 a 12 preguntas que un cliente potencial haría a un asistente de IA para decidir entre proveedores de esa categoría (qué es, cómo elegir, comparaciones, opiniones). 2) Para cada pregunta, indícame exactamente cómo formularla de forma neutral, sin sesgar la respuesta a favor de mi marca. 3) Genera una plantilla en formato tabla para registrar, por cada pregunta y cada asistente de IA consultado: la respuesta textual resumida, si mencionó mi marca, si mencionó competidores, y el tono detectado (positivo/neutro/negativo). 4) Incluye una columna de fecha de consulta, porque las respuestas de los asistentes de IA cambian con el tiempo y no debe tratarse como un dato fijo. Marca: [NOMBRE DE MARCA]. Categoría de negocio: [CATEGORÍA]. Competidores a comparar: [LISTA DE COMPETIDORES]."}},
  {"id":"gr23","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Reputación y precisión en respuestas de IA","titulo":"Encuentra los datos falsos que la IA está inventando sobre tu negocio","beneficio":"Te ayuda a registrar de forma sistemática cada vez que un asistente de IA le atribuye a tu marca datos, precios o características que no son ciertos, para que puedas identificar de dónde viene la confusión y corregir la fuente.","alcance":"Sí hace: da una plantilla y un método para documentar y clasificar afirmaciones falsas sobre tu marca encontradas en respuestas de asistentes de IA. No hace: no elimina la información incorrecta directamente de los modelos de IA (eso no está bajo tu control ni tiene un proceso garantizado), ni asegura que corregir tu propia web haga que el asistente deje de repetir el error de inmediato; los modelos se actualizan con calendarios y procesos que no controlas.","precio":1.99,"blueprint":{"quePuedeHacer":"Estructura un proceso para hacerle preguntas específicas sobre tu marca a distintos asistentes de IA, comparar cada afirmación de la respuesta contra la realidad verificada de tu negocio, y registrar las discrepancias (alucinaciones) encontradas junto con una hipótesis de la fuente que pudo originarlas.","modo":"Auditoría manual periódica, con una lista de verificación de hechos propios de tu negocio como referencia contra la que comparar cada respuesta.","pasos":["Prepara una lista corta de hechos verificados sobre tu negocio (qué ofreces, dónde operas, desde cuándo, qué NO ofreces).","Haz preguntas directas sobre esos mismos hechos a distintos asistentes de IA y guarda la respuesta textual de cada uno.","Compara cada afirmación de la respuesta contra tu lista de hechos verificados y marca las que no coincidan.","Para cada discrepancia encontrada, anota una hipótesis de dónde pudo salir ese dato incorrecto (una página desactualizada, una mención de terceros, una confusión con otra marca).","Prioriza corregir primero las fuentes propias que puedas controlar directamente (tu web, tus fichas en directorios) antes de otras hipótesis."],"reglas":["Registra siempre la pregunta exacta, la respuesta completa y la fecha; una alucinación aislada no es aún un patrón, y solo el registro repetido lo confirma.","No confundas una opinión o generalización del asistente con una alucinación factual: solo cuenta como tal una afirmación verificable y objetivamente falsa."],"prompt":"Actúa como auditor de precisión factual sobre cómo los asistentes de IA describen marcas. Te voy a dar una lista de hechos verificados sobre mi negocio y las respuestas textuales que distintos asistentes de IA dieron a preguntas sobre mi marca. Tu tarea: 1) Compara cada afirmación de las respuestas contra la lista de hechos verificados que te doy. 2) Señala cada afirmación que sea objetivamente falsa o inconsistente con esos hechos (no marques opiniones o generalizaciones subjetivas). 3) Para cada alucinación detectada, propón una hipótesis razonable de dónde pudo originarse el dato incorrecto (página web desactualizada, confusión con otra marca, información de terceros). 4) Organiza el resultado en una tabla: Afirmación del asistente | Asistente y fecha | Por qué es incorrecta | Hipótesis de origen | Prioridad de corrección (alta si la fuente es propia y controlable, baja si no lo es). Hechos verificados de mi negocio: [LISTA DE HECHOS]. Respuestas a analizar: [PEGA AQUÍ LAS RESPUESTAS DE LOS ASISTENTES]."}},
  {"id":"gr24","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Reputación y precisión en respuestas de IA","titulo":"Asegúrate de que tu marca y tu categoría de negocio aparezcan siempre juntas en tus textos","beneficio":"Revisa que el nombre de tu marca se mencione cerca del término de tu categoría de negocio en tus propios contenidos, para reforzar con el tiempo la asociación que los modelos de IA pueden aprender entre ambos conceptos.","alcance":"Sí hace: analiza tus propios textos (web, fichas de directorio, redes sociales) y señala dónde falta esa asociación explícita entre marca y categoría. No hace: no controla cómo los modelos de IA que ya fueron entrenados asocian tu marca hoy, ni produce un cambio inmediato; es una acción preventiva orientada al mediano plazo, sin garantía de resultado.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa un conjunto de textos propios (páginas, fichas, publicaciones) y detecta en cuáles aparece el nombre de la marca sin mencionar cerca la categoría de negocio a la que pertenece, señalando dónde conviene reforzar esa asociación de forma natural.","modo":"Auditoría de contenido existente; se aplica sobre las páginas y perfiles que la marca ya controla.","pasos":["Reúne los textos propios más relevantes: página de inicio, páginas 'sobre nosotros', fichas en directorios, biografías de redes sociales.","Localiza cada mención del nombre de la marca en esos textos.","Para cada mención, comprueba si la categoría de negocio (o un término equivalente reconocible) aparece en la misma frase o en una cercana.","Señala los textos donde el nombre de marca aparece aislado, sin contexto de categoría, como candidatos a reforzar.","Propón una reescritura natural de esas frases que incluya la categoría sin sonar forzada ni repetitiva."],"reglas":["No repitas la categoría de negocio de forma forzada o antinatural solo por incluirla; la frase debe seguir leyéndose bien para una persona.","Prioriza los textos de mayor visibilidad (página de inicio, biografías públicas, fichas de directorio) sobre contenido secundario."],"prompt":"Actúa como consultor de posicionamiento de marca para IA. Te voy a pegar varios textos propios de mi negocio (web, fichas, biografías de redes). Mi categoría de negocio es: [CATEGORÍA DE NEGOCIO]. Mi nombre de marca es: [NOMBRE DE MARCA]. Tu tarea: 1) Localiza cada mención de mi marca en los textos. 2) Indica si en esa misma frase o en una cercana aparece mi categoría de negocio o un término equivalente reconocible. 3) Lista los fragmentos donde la marca aparece sin esa asociación de categoría cercana. 4) Para cada uno, propón una reescritura natural que incluya la categoría de forma fluida, sin sonar repetitiva ni forzada. 5) Entrega el resultado como una tabla: Fragmento original | ¿Tiene categoría cerca? (sí/no) | Reescritura propuesta (si aplica). Textos a revisar: [PEGA AQUÍ LOS TEXTOS]."}},
  {"id":"gr25","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Infraestructura técnica para bots de IA","titulo":"Crea el mapa que orienta a los asistentes de IA sobre qué contenido tuyo es el importante","beneficio":"Genera un archivo llms.txt con enlaces limpios a tus páginas más relevantes, siguiendo una convención emergente que algunos asistentes de IA usan para orientarse rápidamente en un sitio.","alcance":"Sí hace: redacta la estructura y el contenido de un archivo llms.txt a partir del mapa de tu sitio, listando tus páginas clave con una breve descripción. No hace: no garantiza que todos los asistentes de IA lean o prioricen ese archivo hoy, porque es un estándar todavía en adopción y no universal, ni sustituye un sitemap XML tradicional (ambos pueden coexistir).","precio":1.99,"blueprint":{"quePuedeHacer":"A partir de la lista de páginas de un sitio y una breve descripción de cada una, redacta un archivo llms.txt bien estructurado, con enlaces limpios y organizados por relevancia, siguiendo la convención de este formato emergente para orientar a asistentes de IA.","modo":"Generación de un archivo de configuración a partir de información que aportas sobre tu sitio; se revisa y actualiza cuando cambien tus páginas principales.","pasos":["Reúne la lista de páginas más importantes de tu sitio (inicio, servicios principales, sobre nosotros, contacto, contenido de referencia).","Escribe para cada página una descripción breve y honesta de qué contiene.","Organiza la lista por orden de relevancia, agrupando por secciones si el sitio es grande.","Redacta el archivo siguiendo la estructura habitual de llms.txt: un título, un resumen breve del sitio, y la lista de enlaces con su descripción.","Revisa que todos los enlaces sean correctos y apunten a URLs reales y accesibles."],"reglas":["No incluyas páginas privadas, de administración o irrelevantes para un visitante externo; el archivo debe reflejar solo contenido público de valor.","Mantén las descripciones honestas y breves: no uses el archivo como espacio publicitario con lenguaje exagerado."],"prompt":"Actúa como especialista en infraestructura técnica para visibilidad en IA. Te voy a dar la lista de páginas principales de mi sitio web con una breve descripción de cada una. Tu tarea: 1) Redacta un archivo llms.txt siguiendo la convención habitual de este formato: un título con el nombre del sitio, un resumen breve de qué es el negocio, y luego una lista organizada de enlaces con su descripción. 2) Agrupa los enlaces por sección si hay más de diez páginas (por ejemplo: Servicios, Sobre nosotros, Recursos). 3) Mantén cada descripción en una frase clara y honesta, sin lenguaje publicitario exagerado. 4) No inventes páginas ni descripciones que no te haya dado: si falta información de alguna página, usa un marcador [completar descripción]. 5) Entrega el resultado como el contenido final del archivo, listo para copiar en un archivo de texto plano. Nombre del sitio: [NOMBRE]. Resumen del negocio: [RESUMEN]. Páginas y descripciones: [LISTA DE PÁGINAS Y DESCRIPCIONES]."}},
  {"id":"gr26","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Infraestructura técnica para bots de IA","titulo":"Haz que tus respuestas de API sean más ligeras para los agentes de IA que las consultan","beneficio":"Limpia espacios, campos redundantes y metadatos innecesarios de las respuestas que entrega tu API, para reducir lo que un agente de IA (o cualquier sistema automático) tiene que procesar cada vez que la consulta.","alcance":"Sí hace: revisa un ejemplo de respuesta (JSON u otro formato) y propone una versión más compacta que conserve todos los campos necesarios. No hace: no modifica tu código de backend por ti (requiere que un desarrollador aplique el cambio), ni garantiza un ahorro de costo específico, ya que el impacto real depende del volumen de consultas y de cómo esté configurado tu sistema.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza un ejemplo real de respuesta de API y detecta espacios innecesarios, campos duplicados, metadatos que ningún consumidor usa y estructuras anidadas más complejas de lo necesario, proponiendo una versión equivalente más compacta sin perder información funcional.","modo":"Revisión puntual sobre un ejemplo de payload que aportas; el cambio real debe implementarlo quien mantenga la API.","pasos":["Pega un ejemplo representativo de la respuesta que devuelve tu API hoy.","Identifica campos que se repiten en distintos niveles de la respuesta sin necesidad, o metadatos de uso interno que no aportan valor a quien consulta.","Identifica espacios, indentación o formato que aumentan el tamaño del payload sin aportar legibilidad para un sistema automático.","Propón una versión compacta equivalente, marcando claramente qué campos se eliminaron o simplificaron y por qué.","Verifica que la versión compacta siga conteniendo todos los datos que un consumidor legítimo necesitaría."],"reglas":["No elimines ningún campo sin confirmar antes que no es usado por ningún consumidor real de la API; en caso de duda, márcalo como candidato en vez de quitarlo directamente.","Distingue claramente entre optimizar el formato (espacios, estructura) y cambiar el contrato de datos (qué campos existen), porque lo segundo puede romper integraciones existentes."],"prompt":"Actúa como ingeniero especializado en optimizar integraciones máquina-a-máquina. Te voy a pegar un ejemplo real de la respuesta que devuelve mi API. Tu tarea: 1) Identifica campos redundantes, duplicados en distintos niveles, o metadatos que probablemente no use ningún consumidor externo. 2) Identifica oportunidades de simplificar la estructura (anidamientos innecesarios, formato con espacios de más) sin perder legibilidad para un sistema automático. 3) Propón una versión compacta equivalente del payload. 4) Para cada campo o estructura que propongas eliminar o simplificar, explica por qué y márcalo como 'candidato a eliminar' en vez de quitarlo de forma definitiva, ya que solo quien mantiene la API sabe con certeza si algún consumidor lo usa. 5) Entrega: la versión original, la versión compacta propuesta, y una lista de cambios con su justificación. Payload de ejemplo: [PEGA AQUÍ EL JSON O FORMATO DE RESPUESTA]."}},
  {"id":"gr27","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Infraestructura técnica para bots de IA","titulo":"Distingue si quien visita tu web es una persona real, un asistente de IA o un bot que solo copia contenido","beneficio":"Te da un método para identificar, a partir de tus registros de acceso, patrones que diferencian el tráfico de asistentes de IA legítimos, bots de centros de datos y visitas humanas reales, para tomar mejores decisiones sobre qué contenido exponer y a quién.","alcance":"Sí hace: propone un método y una lista de señales (encabezado user-agent, patrones de navegación, origen de red) para clasificar el tráfico a partir de tus registros. No hace: no bloquea ni permite tráfico automáticamente (eso requiere configuración adicional en tu servidor o tu proveedor de CDN), ni identifica con certeza absoluta cada visita: algunos bots ocultan o falsifican su origen de forma deliberada.","precio":1.99,"blueprint":{"quePuedeHacer":"A partir de un conjunto de registros de acceso (logs), analiza patrones de encabezado user-agent, frecuencia de solicitudes y comportamiento de navegación para clasificar el tráfico en categorías aproximadas: humano, asistente de IA conocido, bot de centro de datos u origen no identificado.","modo":"Análisis manual sobre una muestra de logs que aportas; no es una herramienta de bloqueo en tiempo real.","pasos":["Reúne una muestra representativa de registros de acceso de tu servidor o CDN, con al menos el user-agent y la IP o el rango de origen.","Agrupa las solicitudes por user-agent y por patrón de comportamiento (velocidad entre peticiones, páginas visitadas, si ejecuta JavaScript).","Compara los user-agents contra los identificadores públicos conocidos de asistentes de IA y motores de búsqueda.","Señala los patrones que no coinciden con ningún identificador conocido pero muestran comportamiento no humano (peticiones muy rápidas, sin variación).","Clasifica el resultado en categorías aproximadas y documenta el nivel de confianza de cada clasificación."],"reglas":["Presenta siempre la clasificación como una aproximación con nivel de confianza, nunca como una certeza absoluta: el origen del tráfico se puede falsificar.","No recomiendes bloquear tráfico solo por parecer un bot; distingue entre bots que quieres permitir (asistentes de IA legítimos que citan tu contenido) y los que quieres restringir (copia masiva no autorizada)."],"prompt":"Actúa como analista de tráfico web especializado en distinguir accesos humanos de bots y asistentes de IA. Te voy a pegar una muestra de mis registros de acceso (logs), con user-agent, marca de tiempo y ruta solicitada. Tu tarea: 1) Agrupa las solicitudes por user-agent y describe el patrón de comportamiento de cada grupo (frecuencia, rutas visitadas, si parece seguir un patrón humano o automatizado). 2) Señala qué user-agents corresponden a asistentes de IA o motores de búsqueda conocidos. 3) Señala qué grupos muestran comportamiento no humano (peticiones muy rápidas y regulares, sin pausas, sin variación de rutas) pero no se identifican con un user-agent conocido. 4) Clasifica cada grupo en una de estas categorías con un nivel de confianza (alto/medio/bajo): humano, asistente de IA conocido, bot de centro de datos, origen no identificado. 5) Aclara que esta clasificación es aproximada porque el origen del tráfico puede falsificarse. Entrega el resultado como una tabla: User-agent o patrón | Categoría | Nivel de confianza | Evidencia. Logs a analizar: [PEGA AQUÍ LA MUESTRA DE LOGS]."}},
  {"id":"gr28","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Infraestructura técnica para bots de IA","titulo":"Marca qué parte de tu página es el contenido real, no el menú ni la barra lateral","beneficio":"Envuelve tu contenido de valor en etiquetas HTML semánticas (artículo, sección, encabezados jerárquicos), separándolo con claridad del menú, la barra lateral y el pie de página, para que un sistema automático identifique más fácilmente qué es lo importante.","alcance":"Sí hace: revisa la estructura de una página y propone el marcado semántico adecuado (article, section, nav, aside, encabezados en orden jerárquico). No hace: no reescribe la plantilla de tu sitio por ti, ya que eso requiere que un desarrollador aplique el cambio en el código, ni garantiza mejoras de posicionamiento por sí solo, porque el marcado semántico es una buena práctica entre muchas.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa el HTML de una página y evalúa si el contenido principal está envuelto en etiquetas semánticas apropiadas (article, section, main) frente a elementos de navegación o soporte (nav, aside, header, footer), proponiendo el marcado corregido cuando falte esa separación.","modo":"Auditoría de código HTML existente; el resultado es una propuesta de marcado que un desarrollador debe implementar.","pasos":["Pega el HTML de la página a revisar.","Identifica qué bloque contiene el contenido principal (el texto que el usuario vino a leer) frente a navegación, barra lateral y pie de página.","Verifica si esos bloques ya usan etiquetas semánticas correctas (main, article, section, nav, aside, footer) o solo divs genéricos.","Revisa que los encabezados (h1 a h6) sigan un orden jerárquico lógico dentro del contenido principal, sin saltos ni repeticiones de h1.","Propón el marcado HTML corregido, señalando exactamente qué etiquetas cambiar y dónde."],"reglas":["No cambies el contenido visible ni el diseño de la página; el objetivo es solo la estructura semántica del marcado.","Si la página ya usa un framework o componente que abstrae el HTML final, aclara que el cambio debe aplicarse en el código fuente del componente, no en el HTML renderizado."],"prompt":"Actúa como auditor de HTML semántico especializado en preparar páginas para lectura automática por buscadores y asistentes de IA. Te voy a pegar el HTML de una página. Tu tarea: 1) Identifica qué bloque contiene el contenido principal (el texto sustantivo) y cuáles son navegación, barra lateral y pie de página. 2) Evalúa si esos bloques ya usan las etiquetas semánticas adecuadas (main, article, section, nav, aside, header, footer) o si son divs genéricos sin significado estructural. 3) Revisa el orden jerárquico de los encabezados (h1 a h6) dentro del contenido principal y señala saltos de nivel o múltiples h1. 4) Propón el HTML corregido con el marcado semántico adecuado, indicando exactamente qué etiquetas cambiarías y por qué. 5) No alteres el contenido visible ni el diseño, solo la estructura semántica. Entrega el resultado en dos bloques: 'Problemas encontrados' (lista) y 'HTML propuesto' (bloque de código). HTML a revisar: [PEGA AQUÍ EL HTML]."}},
  {"id":"gr29","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Datos estructurados y entidad de marca","titulo":"Corrige los datos públicos de tu marca sin arriesgarte a que te los rechacen por falta de pruebas","beneficio":"Prepara una propuesta de edición para bases de datos de entidades públicas (como Wikidata), validando primero que existan fuentes de prensa u otras fuentes externas independientes que respalden el cambio, antes de proponerlo.","alcance":"Sí hace: estructura la propuesta de edición y la lista de fuentes externas necesarias para respaldarla. No hace: no edita la base de datos por ti ni garantiza que la edición sea aceptada; estas plataformas exigen fuentes independientes verificables y pueden rechazar cambios sin ese respaldo, sin importar lo correcta que sea la información.","precio":1.99,"blueprint":{"quePuedeHacer":"Ayuda a estructurar una propuesta de corrección o actualización de los datos públicos de una marca en una base de datos de entidades (como Wikidata), verificando primero qué afirmaciones tienen respaldo en fuentes de prensa u otras fuentes externas independientes y cuáles no.","modo":"Preparación manual de una propuesta de edición; la edición real en la plataforma la realiza una persona siguiendo las normas de esa plataforma.","pasos":["Lista los datos actuales sobre tu marca que quieres corregir o completar (categoría, fundación, ubicación, productos).","Para cada dato, busca si existe una fuente externa independiente (artículo de prensa, registro público, publicación de un tercero) que lo respalde.","Separa los datos que sí tienen respaldo externo verificable de los que solo constan en canales propios de la marca (tu web, tus redes).","Redacta la propuesta de edición citando explícitamente cada fuente externa junto al dato que respalda.","Señala los datos sin respaldo externo como pendientes: no deben proponerse hasta conseguir una fuente independiente."],"reglas":["No propongas ni redactes como 'hecho verificado' ningún dato cuya única fuente sea la propia marca; las bases de entidades exigen fuentes independientes.","Cita la fuente exacta (nombre de la publicación, fecha, enlace) junto a cada dato propuesto, no una referencia genérica."],"prompt":"Actúa como especialista en gestión de entidades de marca en bases de datos públicas como Wikidata. Te voy a dar una lista de datos sobre mi marca que quiero corregir o añadir, junto con las fuentes que tengo disponibles. Tu tarea: 1) Para cada dato, evalúa si la fuente que aporté es externa e independiente (prensa, registro público, publicación de terceros) o si es un canal propio de la marca (web, redes sociales propias). 2) Separa los datos en dos grupos: 'Con respaldo externo verificable, listos para proponer' y 'Sin respaldo externo, pendientes de conseguir fuente'. 3) Para el primer grupo, redacta la propuesta de edición citando explícitamente la fuente (publicación, fecha, enlace) junto a cada dato. 4) Para el segundo grupo, sugiere qué tipo de fuente externa ayudaría a respaldar ese dato en el futuro. 5) Recuérdame que la edición final debe hacerse siguiendo las normas de la plataforma y que puede ser rechazada si el respaldo no es suficiente. Datos y fuentes disponibles: [LISTA DE DATOS Y FUENTES]."}},
  {"id":"gr30","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Datos estructurados y entidad de marca","titulo":"Revisa si el nombre de tu marca se parte en pedazos que la IA no reconoce como una sola cosa","beneficio":"Analiza cómo es probable que un modelo de lenguaje procese el nombre de tu marca y detecta si tiende a dividirse en demasiadas piezas, lo que puede dificultar que se reconozca de forma consistente como una sola entidad.","alcance":"Sí hace: ofrece un método de revisión cualitativa y señales de alerta (nombres muy largos, con símbolos poco comunes, combinaciones de palabras inusuales) que suelen fragmentarse más al procesarse. No hace: no accede al tokenizador interno de cada modelo de IA en particular, ya que son distintos entre proveedores y no todos son públicos, ni ofrece una cifra exacta de fragmentación garantizada para todos los sistemas.","precio":1.99,"blueprint":{"quePuedeHacer":"Evalúa el nombre de una marca en busca de características que suelen aumentar la fragmentación al procesarse por un modelo de lenguaje (longitud inusual, símbolos no alfabéticos, combinaciones poco frecuentes de letras, mezcla de idiomas), y sugiere si el nombre es razonablemente reconocible como unidad o si conviene reforzar su asociación con contexto adicional.","modo":"Análisis cualitativo sobre el nombre de marca y su uso en textos propios; no accede a los tokenizadores reales de cada proveedor de IA.","pasos":["Analiza el nombre de la marca letra por letra y palabra por palabra en busca de rasgos poco comunes (símbolos, números intercalados, mezcla de mayúsculas inusual).","Compáralo con nombres de marca conocidos y de longitud similar para estimar si tiende a fragmentarse más de lo habitual.","Revisa si el nombre se usa siempre igual en los textos propios de la marca o si aparece con variaciones (con o sin espacio, con o sin símbolo).","Si el nombre parece propenso a fragmentarse, recomienda reforzarlo con contexto cercano (categoría de negocio, descripción breve) cada vez que aparezca.","Documenta el hallazgo como una hipótesis cualitativa, no como una medición exacta y verificada."],"reglas":["No presentes el resultado como una cifra técnica precisa de fragmentación; los tokenizadores varían entre modelos y no son todos públicos, así que el análisis es orientativo.","Recomienda mantener el nombre de marca siempre escrito de forma idéntica en los canales propios, como medida preventiva razonable."],"prompt":"Actúa como analista de identidad de marca aplicada a modelos de lenguaje. Te voy a dar el nombre de mi marca y algunos ejemplos de cómo lo escribo en distintos canales. Tu tarea: 1) Evalúa el nombre en busca de rasgos que suelen aumentar la fragmentación al procesarse por un modelo de lenguaje: longitud inusual, símbolos no alfabéticos, números intercalados, mezcla de idiomas o mayúsculas atípicas. 2) Compáralo cualitativamente con nombres de marca conocidos de longitud similar para estimar si parece más o menos propenso a fragmentarse que el promedio. 3) Revisa si lo escribo de forma consistente en los ejemplos que te doy o si varía (con espacio, sin espacio, con símbolo, sin símbolo) y señala las inconsistencias. 4) Si el nombre parece propenso a fragmentarse, recomiéndame cómo reforzar su reconocimiento (por ejemplo, acompañarlo siempre de mi categoría de negocio en la primera mención de un texto). 5) Deja claro que esto es un análisis cualitativo y orientativo, no una medición técnica exacta, porque no tengo acceso al tokenizador real de cada modelo. Nombre de marca: [NOMBRE]. Ejemplos de uso: [EJEMPLOS DE CÓMO SE ESCRIBE EN DISTINTOS CANALES]."}},
  {"id":"gr31","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Datos estructurados y entidad de marca","titulo":"Mantén tu catálogo de productos al día para que los asistentes de compra de IA no den información vieja","beneficio":"Define un proceso para mantener actualizado tu feed de productos (precio, stock, disponibilidad), de forma que los agentes de IA que comparan o recomiendan productos trabajen con datos vigentes en vez de desactualizados.","alcance":"Sí hace: define la estructura del feed y una rutina razonable de mantenimiento según con qué frecuencia cambia tu catálogo. No hace: no se conecta automáticamente a tu inventario real (requiere integración técnica con tu sistema de gestión), ni garantiza que un agente de compra de IA en particular use, lea o priorice tu feed sobre el de otro proveedor.","precio":1.99,"blueprint":{"quePuedeHacer":"Define la estructura de un feed de productos (nombre, precio, disponibilidad, categoría, identificador único) y una rutina de actualización adaptada a la frecuencia real con que cambian tus precios o tu stock, para que la información que exponen tus canales digitales no quede desactualizada frente a agentes de compra automatizados.","modo":"Definición de estructura y proceso; la actualización técnica real requiere conectar el feed a tu sistema de inventario o gestionarlo manualmente con disciplina.","pasos":["Lista los campos imprescindibles de tu catálogo: nombre del producto, precio, disponibilidad, categoría e identificador único.","Define con qué frecuencia cambia cada campo en tu negocio real (el precio puede cambiar poco, el stock puede cambiar todos los días).","Diseña una rutina de actualización del feed acorde a esa frecuencia de cambio, en vez de un calendario arbitrario.","Establece quién es responsable de actualizar el feed y qué pasa si detecta una discrepancia entre el feed y la realidad.","Define una revisión periódica que confirme que el feed sigue reflejando el catálogo real, no solo que se actualizó en la fecha prevista."],"reglas":["La frecuencia de actualización debe basarse en con qué rapidez cambia tu catálogo real, no en un número fijo asumido sin verificar.","Si detectas una discrepancia entre el feed publicado y el catálogo real, corrígela cuanto antes: un feed desactualizado es peor que no tener feed."],"prompt":"Actúa como consultor de operaciones de e-commerce especializado en mantener catálogos de producto listos para agentes de compra automatizados. Te voy a dar información sobre mi catálogo: cuántos productos tengo, con qué frecuencia cambian mis precios, y con qué frecuencia cambia mi disponibilidad o stock. Tu tarea: 1) Define la estructura mínima de campos que debería tener mi feed de productos (nombre, precio, disponibilidad, categoría, identificador único, y cualquier otro campo relevante para mi tipo de negocio). 2) Basándote en la frecuencia de cambio que te di, propón una rutina de actualización razonable (no un número arbitrario, sino ajustada a mi caso real). 3) Define quién debería ser responsable de cada actualización y qué proceso seguir si se detecta una discrepancia entre el feed y el catálogo real. 4) Propón una revisión periódica de verificación que confirme que el feed sigue siendo fiel a la realidad, no solo que se ejecutó en fecha. Entrega el resultado como un documento con: estructura de campos, rutina de actualización propuesta, responsables y proceso de verificación. Información de mi catálogo: [NÚMERO DE PRODUCTOS, FRECUENCIA DE CAMBIO DE PRECIO Y STOCK]."}},
  {"id":"gr32","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Datos estructurados y entidad de marca","titulo":"Explícale a la IA, en su propio idioma, qué es tu negocio, dónde está y qué servicios ofrece","beneficio":"Define las relaciones de tu marca (categoría de negocio, ubicación, servicios, marcas relacionadas) usando el vocabulario estándar de Schema.org, para que buscadores y asistentes de IA puedan entender tu negocio de forma estructurada, no solo a partir de texto libre.","alcance":"Sí hace: redacta el marcado estructurado (JSON-LD) con las relaciones clave de tu negocio según los tipos y propiedades estándar de Schema.org. No hace: no lo publica por ti en tu web, ya que requiere que alguien lo instale en el código del sitio, ni garantiza que un asistente de IA lo use como fuente principal de información sobre tu negocio.","precio":1.99,"blueprint":{"quePuedeHacer":"A partir de la información básica de un negocio (nombre, categoría, ubicación, servicios, marcas o entidades relacionadas), redacta el marcado JSON-LD correspondiente usando los tipos y propiedades estándar de Schema.org (Organization, LocalBusiness, Service u otros según aplique) para representar esas relaciones de forma estructurada.","modo":"Generación de marcado estructurado a partir de datos que aportas; la instalación en la web la realiza un desarrollador o quien administre el sitio.","pasos":["Reúne los datos básicos del negocio: nombre legal y comercial, categoría de negocio, ubicación o ubicaciones, servicios o productos principales.","Identifica el tipo de Schema.org más adecuado para el negocio (Organization, LocalBusiness, un tipo más específico si existe para la industria).","Redacta el bloque JSON-LD con las propiedades correspondientes a cada dato (name, address, areaServed, makesOffer u otras según aplique).","Verifica que el marcado sea sintácticamente válido y que use únicamente propiedades reconocidas por Schema.org.","Entrega el bloque de código listo para insertar en el sitio, junto con una nota de dónde suele colocarse (dentro de una etiqueta script en el head o antes del cierre del body)."],"reglas":["Usa únicamente tipos y propiedades que existan realmente en el vocabulario de Schema.org; no inventes propiedades personalizadas.","No incluyas en el marcado ningún dato que no puedas confirmar que es cierto (una ubicación, un servicio o una relación con otra marca); el marcado estructurado debe reflejar la realidad del negocio."],"prompt":"Actúa como especialista en datos estructurados y Schema.org para negocios locales y de servicios. Te voy a dar los datos básicos de mi negocio. Tu tarea: 1) Determina el tipo de Schema.org más adecuado para representarlo (Organization, LocalBusiness u otro tipo más específico si aplica a mi industria). 2) Redacta el marcado JSON-LD completo, usando las propiedades estándar correspondientes a cada dato que te doy (nombre, dirección, área de servicio, servicios ofrecidos, entidades relacionadas). 3) No inventes ningún dato, servicio o relación que no te haya dado; si falta información para una propiedad relevante, dejala como marcador [completar] en vez de inventarla. 4) Verifica que el JSON-LD resultante sea sintácticamente válido. 5) Añade una nota breve indicando dónde suele insertarse este bloque en el HTML de una página. Datos de mi negocio: nombre [NOMBRE], categoría [CATEGORÍA], ubicación(es) [UBICACIÓN], servicios principales [SERVICIOS], marcas o entidades relacionadas [RELACIONADAS SI APLICA]."}},
  {"id":"gr33","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Voz y seguridad conversacional","titulo":"Prepara respuestas a tus preguntas frecuentes para que suenen bien cuando un asistente las lee en voz alta","beneficio":"Redacta versiones breves y directas de las respuestas a tus preguntas frecuentes, pensadas para leerse en voz alta de forma natural, útiles para asistentes de voz o resúmenes hablados que genera un asistente de IA.","alcance":"Sí hace: reescribe respuestas ya existentes en un formato breve y con estructura pensada para sonar natural al leerse en voz alta. No hace: no garantiza que un asistente de voz elija leer exactamente esa respuesta en vez de otra fuente, ni sustituye la versión escrita completa de tu FAQ, que debe seguir existiendo junto a esta versión hablada.","precio":1.99,"blueprint":{"quePuedeHacer":"Toma una respuesta existente de preguntas frecuentes, generalmente escrita para lectura visual, y la reescribe en una versión breve, con frases cortas y directas, pensada para sonar natural cuando se lee en voz alta por un asistente de voz o se resume verbalmente.","modo":"Reescritura puntual sobre contenido de FAQ ya existente; conviene revisarla cuando la respuesta original cambie.","pasos":["Lee la respuesta original de la pregunta frecuente tal como está escrita hoy.","Identifica la idea central que un usuario necesita escuchar primero, antes de cualquier detalle secundario.","Reescribe la respuesta en frases cortas y directas, evitando subordinadas largas o listas que no suenan bien al leerse en voz alta.","Verifica leyendo la versión en voz alta (o pidiendo que se lea) que suene natural y no como un texto pensado solo para lectura visual.","Conserva la versión escrita original en la web junto a esta versión hablada, sin sustituirla."],"reglas":["Prioriza siempre la idea central al principio de la respuesta hablada; una persona escuchando no puede 'volver atrás' como al leer un texto.","No sacrifiques la exactitud de la información por brevedad: una respuesta hablada corta pero incorrecta es peor que una un poco más larga pero precisa."],"prompt":"Actúa como redactor especializado en adaptar contenido escrito para lectura en voz alta por asistentes de voz. Te voy a pegar la respuesta actual de una pregunta frecuente. Tu tarea: 1) Identifica la idea central que la persona necesita escuchar primero. 2) Reescribe la respuesta en frases cortas y directas, evitando subordinadas largas, paréntesis o listas que no se leen bien en voz alta. 3) Empieza con la idea central y añade detalles secundarios solo después, de forma que si el asistente de voz corta la respuesta a la mitad, lo esencial ya se haya dicho. 4) No sacrifiques ningún dato importante por acortar: si hace falta más de una frase para ser preciso, está bien, siempre que cada frase sea corta y clara. 5) Entrega dos versiones: la 'Versión hablada' (para asistentes de voz) y una nota recordando conservar la 'Versión escrita original' en la página, sin eliminarla. Pregunta frecuente y respuesta original: [PEGA AQUÍ LA PREGUNTA Y LA RESPUESTA ACTUAL]."}},
  {"id":"gr34","catalogo":"growth","grupo":"Visibilidad en IA","tema":"Voz y seguridad conversacional","titulo":"Pon a prueba a tu propio chatbot antes de que alguien más lo haga por ti","beneficio":"Simula intentos de manipulación (inyección de instrucciones, solicitudes fuera de política) contra tu chatbot de atención al cliente, para detectar huecos de seguridad y corregirlos antes de que un usuario real los aproveche.","alcance":"Sí hace: da un conjunto de intentos de prueba habituales y una plantilla para registrar qué falló y qué se sostuvo. No hace: no corrige el chatbot automáticamente (debes ajustar sus instrucciones, filtros o proveedor tú mismo), ni cubre todas las técnicas de manipulación posibles, ya que estas evolucionan constantemente; es una revisión periódica razonable, no una garantía de seguridad total.","precio":1.99,"blueprint":{"quePuedeHacer":"Diseña una batería de mensajes de prueba que simulan intentos habituales de manipular un chatbot de atención al cliente (pedirle que ignore sus instrucciones, hacerse pasar por un administrador, sacarlo de su tema o pedirle información que no debería revelar), y una plantilla para registrar cómo respondió el chatbot ante cada intento.","modo":"Prueba manual, ejecutada conversando directamente con tu propio chatbot y registrando los resultados; conviene repetirla cuando cambies las instrucciones o el proveedor del chatbot.","pasos":["Define qué información o comportamientos son 'zona prohibida' para tu chatbot (datos internos, descuentos no autorizados, opiniones sobre competidores, instrucciones del sistema).","Redacta una serie de mensajes de prueba que intenten manipularlo hacia esa zona prohibida, usando técnicas conocidas (fingir ser un administrador, pedirle que 'ignore instrucciones anteriores', pedirle que actúe 'sin restricciones').","Conversa con tu chatbot usando esos mensajes de prueba, uno por uno, y registra la respuesta textual completa.","Clasifica cada intento según si el chatbot mantuvo el límite, cedió parcialmente o reveló información o comportamiento no permitido.","Para cada fallo detectado, documenta el mensaje exacto que lo provocó, para que puedas ajustar las instrucciones o los filtros del chatbot con ese caso concreto en mente."],"reglas":["Registra siempre el mensaje exacto usado y la respuesta completa del chatbot; sin ese registro no se puede verificar ni repetir la prueba después de un ajuste.","No confundas una respuesta educada pero firme (el chatbot explica por qué no puede ayudar) con un fallo; el fallo real es cuando efectivamente cede a la manipulación."],"prompt":"Actúa como especialista en pruebas de seguridad conversacional (red-teaming) para chatbots de atención al cliente. Te voy a decir qué información o comportamientos son 'zona prohibida' para mi chatbot. Tu tarea: 1) Redacta de 8 a 12 mensajes de prueba que simulen técnicas habituales de manipulación de chatbots: fingir ser administrador o desarrollador, pedirle que 'ignore las instrucciones anteriores', pedirle que responda 'sin restricciones' o 'en modo desarrollador', intentar que revele su propio prompt de sistema, o desviarlo hacia temas fuera de su función para sonsacarle la información prohibida. 2) Para cada mensaje, indica qué técnica de manipulación representa y qué resultado constituiría un fallo real (no una simple respuesta educada de rechazo). 3) Dame una plantilla en tabla para registrar, tras probar cada mensaje contra mi chatbot real: Mensaje de prueba | Técnica | Respuesta del chatbot (resumen) | ¿Mantuvo el límite, cedió parcialmente o falló? | Ajuste recomendado si falló. 4) Recuérdame que debo ejecutar yo mismo estas pruebas conversando con mi chatbot, ya que esto no se conecta automáticamente a mi sistema. Zona prohibida de mi chatbot (información o comportamientos que nunca debe revelar o hacer): [DESCRIBE LA ZONA PROHIBIDA]."}},
  {"id":"gr35","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Precios y ofertas","titulo":"Ajusta tus precios a la competencia sin sacrificar tu margen","beneficio":"Evita quedarte fuera de mercado por desconocer los precios del rival y, al mismo tiempo, proteges tu rentabilidad al fijar de antemano un margen mínimo que nunca se debe cruzar.","alcance":"Compara precios publicados públicamente (web, catálogo, marketplace) con los tuyos y sugiere si conviene subir, bajar o mantener, dentro del rango de margen mínimo que tú definas. No accede a los costes internos del rival, no cambia precios de forma automática y no sustituye tu criterio de negocio sobre cuándo y cuánto ajustar.","precio":1.99,"blueprint":{"quePuedeHacer":"Recopila los precios visibles del rival en categorías comparables a las tuyas, los coteja con tu lista de precios y devuelve una recomendación de ajuste por producto, respetando siempre el margen mínimo que hayas definido y sin proponer nunca vender por debajo de ese límite.","modo":"Análisis asistido por IA a partir de datos que tú recopilas periódicamente (capturas de precios, exportaciones de catálogo); no es un rastreador automático en vivo, sino un analista que interpreta la información que le entregues.","pasos":["Define tu lista de productos o servicios equivalentes y el margen mínimo aceptable de cada uno.","Recopila los precios públicos del rival para los mismos productos, en el mismo momento.","Pide a la IA que compare ambas listas y clasifique cada producto como por encima, igual o por debajo del rival.","Revisa las sugerencias de ajuste y confirma que ninguna cruce tu margen mínimo.","Decide manualmente qué ajustes aplicar y en qué plazo.","Repite la comparación con la frecuencia que tenga sentido para tu categoría (semanal, quincenal o mensual)."],"reglas":["Nunca sugerir un precio por debajo del margen mínimo definido por el negocio.","Ignorar precios de liquidaciones puntuales o promociones muy cortas que no representan el precio de catálogo habitual.","Señalar cuando falte un producto comparable en vez de inventar un precio de referencia.","Presentar la recomendación como un insumo para decidir, nunca como una decisión automática."],"prompt":"Actúa como analista de pricing competitivo. Te voy a dar dos listas: (1) mis precios actuales por producto o servicio, con mi margen mínimo aceptable para cada uno, y (2) los precios públicos equivalentes de mi competidor [nombre], recopilados el [fecha]. Compara producto por producto y clasifica cada uno como 'por encima', 'igual' o 'por debajo' del rival. Para los que estén por debajo, sugiere si tiene sentido ajustar el precio, pero nunca propongas un valor por debajo del margen mínimo que te indico. Señala también los productos donde no tengas un equivalente claro para comparar. Devuelve el resultado en una tabla y un resumen breve con tu recomendación general, dejando claro que la decisión final es mía.\n\nMis precios y márgenes mínimos:\n[pega aquí tu lista]\n\nPrecios públicos del rival:\n[pega aquí lo recopilado]"}},
  {"id":"gr36","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Precios y ofertas","titulo":"Descubre qué promociones mantiene activas tu competencia","beneficio":"Te permite calibrar tu propio calendario de descuentos sabiendo qué tipo de promociones generales sostiene el rival de forma habitual, en vez de reaccionar a ofertas que en realidad son casos aislados.","alcance":"Registra cupones y descuentos publicados abiertamente en la web, redes sociales o newsletter del rival. No incluye códigos personalizados de un solo uso ni ofertas privadas enviadas a clientes concretos, porque esa información no es pública. Decidir si igualar, ignorar o superar un descuento sigue siendo tuyo.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta y agrupa los descuentos generales que el rival promociona abiertamente por tipo (porcentaje, envío gratis, 2x1, otros) y por frecuencia de aparición, para darte una idea de su presión promocional habitual.","modo":"Revisión periódica de canales públicos (web, redes, newsletter a la que estés suscrito con una cuenta propia), con la IA sintetizando patrones a partir de lo que le reportes.","pasos":["Sigue o suscríbete a los canales públicos del rival (newsletter, redes, web) con una cuenta propia y transparente.","Anota cada cupón o descuento general que veas publicado, con fecha y condiciones.","Pide a la IA que agrupe los descuentos por tipo y frecuencia a lo largo del tiempo.","Excluye del análisis cualquier código que parezca personal o de un solo uso.","Usa el patrón resultante para decidir si tu propio calendario promocional necesita ajustes."],"reglas":["Excluir siempre códigos de un solo uso o dirigidos a una persona concreta.","No usar identidades falsas ni métodos que violen los términos de uso del rival para acceder a sus canales.","Diferenciar entre un descuento estructural (aparece con frecuencia) y una oferta puntual (aparece una sola vez).","No convertir la observación en el disparador automático de una guerra de precios."],"prompt":"Actúa como analista de estrategia promocional. Te voy a compartir un registro de los cupones y descuentos que he visto publicados abiertamente por mi competidor [nombre] en su web, redes sociales o newsletter, con la fecha en que los vi y sus condiciones. Agrupa los descuentos por tipo (porcentaje, envío gratis, 2x1, otro) y señala cuáles aparecen con cierta frecuencia (probable política estructural) frente a los que parecen puntuales (una sola vez). Ignora cualquier código que parezca personalizado o de un solo uso si lo incluyo por error. Dame un resumen del patrón promocional general del rival y qué implicaciones podría tener para mi propio calendario de descuentos, sin sugerir una guerra de precios.\n\nRegistro de descuentos observados:\n[pega aquí tu registro con fechas y condiciones]"}},
  {"id":"gr37","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Precios y ofertas","titulo":"Compara el coste de envío de tu tienda con el de tu competencia","beneficio":"Te ayuda a saber si el envío es una ventaja o una desventaja frente al rival, para decidir si absorber parte del coste, ajustar tu umbral de envío gratis o comunicar mejor tu política actual.","alcance":"Simula compras de prueba con direcciones de referencia en ambas tiendas y compara las tarifas de envío mostradas públicamente en el proceso de compra. No accede a acuerdos privados de tarifas del rival con transportistas ni a información logística interna; es una fotografía puntual del checkout público.","precio":1.99,"blueprint":{"quePuedeHacer":"Ejecuta simulaciones de checkout con las mismas direcciones de referencia y un carrito equivalente en tu tienda y en la del rival, para extraer y comparar el coste y el plazo de envío mostrados al cliente antes de pagar.","modo":"Pruebas manuales periódicas del proceso de checkout, sin completar la compra, documentadas y luego analizadas por la IA para detectar diferencias relevantes.","pasos":["Define un conjunto fijo de direcciones de referencia que cubran tus zonas de interés (urbano, rural, internacional si aplica).","Simula un carrito equivalente (mismo tipo de producto, peso o volumen similar) en tu tienda y en la del rival.","Registra el coste y el plazo de envío mostrado antes de pagar, sin completar la transacción.","Pide a la IA que organice los resultados en una tabla comparativa por zona.","Repite la prueba cuando sospeches cambios (temporada alta, anuncios de cambios logísticos)."],"reglas":["Usar siempre direcciones de referencia reales o válidas, nunca datos de terceros sin su consentimiento.","No completar compras reales solo para obtener el dato; detenerse en el paso de checkout.","Señalar cuando el envío gratis dependa de un umbral de compra, no solo reportar el coste bruto.","Tratar el resultado como una fotografía puntual, no como una tarifa garantizada del rival a futuro."],"prompt":"Actúa como analista logístico. Te voy a dar los resultados de simulaciones de checkout que hice en mi tienda y en la de mi competidor [nombre], usando las mismas direcciones de referencia y un carrito equivalente. Para cada dirección, compara el coste de envío mostrado, el plazo estimado y si existe un umbral de envío gratis. Organiza todo en una tabla por zona con las diferencias más relevantes. Señala en qué zonas mi envío es más competitivo y en cuáles el rival tiene ventaja, y qué umbral de envío gratis parece usar cada uno. Aclara que estos datos son una fotografía puntual y pueden cambiar.\n\nResultados de mis simulaciones (dirección, coste, plazo, umbral gratis - mío y del rival):\n[pega aquí tus datos]"}},
  {"id":"gr38","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Publicidad y mensajes del rival","titulo":"Descubre qué mensajes publicitarios le están funcionando a tu competencia","beneficio":"Te da ideas fundamentadas sobre el gancho, la promesa y la llamada a la acción que usa el rival en los anuncios que más tiempo llevan corriendo — una señal pública de que probablemente le funcionan — para inspirar tu propia comunicación sin copiarla.","alcance":"Analiza anuncios que el propio rival hace públicos en bibliotecas de transparencia como la Biblioteca de anuncios de Meta o el Centro de Transparencia de Anuncios de Google, priorizando los que llevan más tiempo activos como indicio, no como prueba, de buen rendimiento. No tiene acceso a métricas reales de conversión ni de gasto, que son privadas.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa los anuncios públicos activos del rival en las bibliotecas de transparencia publicitaria, identifica cuáles llevan más tiempo corriendo y extrae de cada uno el gancho inicial, la promesa central y la llamada a la acción, para tu propio análisis de mensajes.","modo":"Consulta manual o semi-asistida de las bibliotecas públicas de anuncios (Meta Ad Library, Google Ads Transparency Center), con la IA resumiendo y estructurando lo que encuentres.","pasos":["Busca el nombre del rival en la Biblioteca de anuncios de Meta y/o el Centro de Transparencia de Anuncios de Google.","Identifica los anuncios con más tiempo activo continuo según la propia herramienta.","Copia el texto y describe brevemente el creativo de cada anuncio relevante.","Pide a la IA que extraiga el gancho, la promesa central y la llamada a la acción de cada uno.","Compara los patrones encontrados con tu propia comunicación actual.","Usa los hallazgos como inspiración de ángulos, nunca como plantilla para copiar texto o creatividad ajena."],"reglas":["Usar solo información que el propio anunciante hace pública en herramientas de transparencia.","No inferir presupuesto ni resultados reales de campaña a partir del tiempo activo; es solo un indicio.","Nunca copiar literalmente el texto o los activos visuales del rival.","Aclarar siempre que 'más tiempo activo' es una señal indirecta, no una certeza de rendimiento."],"prompt":"Actúa como estratega de mensajes publicitarios. Te voy a pegar el texto y una breve descripción del creativo de varios anuncios públicos de mi competidor [nombre], encontrados en la Biblioteca de anuncios de Meta o el Centro de Transparencia de Anuncios de Google, priorizando los que llevan más tiempo activos según la propia herramienta. Para cada anuncio, extrae: (1) el gancho de las primeras líneas o segundos, (2) la promesa central que ofrece, (3) la llamada a la acción. Luego identifica patrones comunes entre los anuncios de mayor duración y qué ángulos parecen repetirse. No propongas copiar ningún texto o creativo, solo úsalo para inspirar ángulos propios y diferenciados.\n\nAnuncios recopilados (texto + tiempo activo aproximado):\n[pega aquí cada anuncio con su antigüedad]"}},
  {"id":"gr39","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Publicidad y mensajes del rival","titulo":"Mide tu presencia en medios frente a tu competencia","beneficio":"Te da una perspectiva de qué tan visible es tu marca en la conversación pública de tu sector frente al rival, priorizando medios con autoridad real, para orientar tus esfuerzos de comunicación y relaciones públicas.","alcance":"Cuenta menciones de prensa y medios especializados de tu marca y la del rival, dando más peso a medios con trayectoria reconocida que a blogs personales o sitios sin editorial clara. No mide sentimiento con precisión garantizada ni sustituye un informe profesional de monitoreo de medios; es una fotografía orientativa.","precio":1.99,"blueprint":{"quePuedeHacer":"Busca y organiza las menciones públicas recientes de tu marca y la del rival en medios de prensa, clasificándolas por tipo de medio (autoridad reconocida frente a blog o sitio menor) para darte una idea comparativa de presencia mediática.","modo":"Búsqueda manual o asistida (buscador web, alertas, herramientas de monitoreo de menciones), con la IA organizando y clasificando los resultados que le entregues.","pasos":["Define la lista de medios que consideras de autoridad real en tu sector.","Busca menciones de tu marca y del rival en un mismo periodo de tiempo.","Clasifica cada mención como 'medio de autoridad' o 'blog/sitio menor'.","Pide a la IA que compile un conteo comparativo y resuma los temas más recurrentes de cada mención.","Usa el resultado como termómetro orientativo, no como métrica exacta de share of voice de la industria."],"reglas":["Priorizar siempre medios con autoridad reconocida sobre blogs personales o sitios sin trayectoria editorial.","No presentar el conteo como una cifra oficial de share of voice del mercado; es una aproximación cualitativa.","Evitar contar como independientes menciones duplicadas por sindicación del mismo artículo en varios sitios.","Distinguir menciones neutrales de menciones claramente positivas o negativas cuando sea evidente."],"prompt":"Actúa como analista de comunicación y relaciones públicas. Te voy a compartir una lista de menciones de prensa recientes sobre mi marca [nombre] y sobre mi competidor [nombre], cada una con el medio donde apareció. Clasifica cada medio como 'autoridad reconocida' o 'blog/sitio menor' según su trayectoria y audiencia conocida. Cuenta las menciones por marca en cada categoría, evitando contar duplicados de un mismo artículo sindicado en varios sitios. Resume los temas más recurrentes de las menciones de cada marca y dame una lectura cualitativa de quién tiene más presencia en medios de autoridad en este periodo, dejando claro que es una aproximación, no una métrica oficial de share of voice.\n\nMenciones recopiladas (medio, fecha, marca):\n[pega aquí tu lista]"}},
  {"id":"gr40","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Web y producto del rival","titulo":"Entérate cuando tu competencia lanza o retira páginas en su web","beneficio":"Te avisa de movimientos estructurales del rival — nuevas líneas de producto, nuevas landing pages, secciones retiradas — para que reacciones con contexto en vez de enterarte por casualidad.","alcance":"Compara el sitemap.xml público del rival (o su estructura de navegación pública) entre dos momentos, ignorando URLs que parecen entornos de prueba, staging o desarrollo. No accede a páginas privadas ni de acceso restringido.","precio":1.99,"blueprint":{"quePuedeHacer":"Descarga y compara el sitemap.xml (o la lista de URLs indexables) del rival en dos fechas distintas, señalando páginas nuevas y páginas eliminadas, y filtrando las que parecen de prueba o desarrollo interno.","modo":"Descarga periódica y manual del sitemap público, comparada por la IA entre versiones sucesivas que tú le proporciones.","pasos":["Localiza el sitemap.xml público del rival (habitualmente en dominio.com/sitemap.xml o enlazado en su robots.txt).","Guarda una copia con fecha.","Repite la descarga con la periodicidad que te interese (semanal, mensual).","Pide a la IA que compare ambas versiones y liste URLs nuevas y URLs desaparecidas.","Filtra manualmente cualquier URL que parezca de prueba, staging o desarrollo.","Revisa las páginas nuevas relevantes para entender qué está lanzando el rival."],"reglas":["Ignorar URLs con patrones típicos de entornos de prueba (staging, dev, test, sufijos de borrador).","No asumir intención estratégica sin visitar la página nueva y confirmar su contenido.","Trabajar solo con el sitemap público, nunca con accesos no autorizados a su servidor.","Reconocer que un sitemap desactualizado o incompleto puede dar una imagen parcial."],"prompt":"Actúa como analista de inteligencia web. Te voy a pegar dos versiones del sitemap.xml (o listado de URLs) de mi competidor [nombre], una de [fecha 1] y otra de [fecha 2]. Compáralas y dame: (1) lista de URLs nuevas, (2) lista de URLs eliminadas. Filtra y excluye de ambas listas cualquier URL que contenga patrones típicos de entornos de prueba o desarrollo (como 'staging', 'dev', 'test', subdominios internos). Para las URLs nuevas relevantes, indica en qué sección del sitio parecen estar según su ruta, para que pueda revisarlas manualmente.\n\nSitemap versión 1 (fecha):\n[pega aquí]\n\nSitemap versión 2 (fecha):\n[pega aquí]"}},
  {"id":"gr41","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Web y producto del rival","titulo":"Detecta cuándo tu competencia rediseña una página clave","beneficio":"Te permite ver cuándo el rival cambia de forma significativa una página importante (home, precios, producto estrella) para estudiar sus decisiones de diseño y mensaje, sin tener que revisar su web todos los días.","alcance":"Compara capturas de pantalla del sitio del rival tomadas en distintos momentos, descartando diferencias mínimas que son solo variaciones de renderizado. No detecta cambios en lo que no sea visible en la página (backend, lógica interna).","precio":1.99,"blueprint":{"quePuedeHacer":"Compara dos capturas de pantalla de la misma página del rival tomadas en fechas distintas y describe los cambios visuales relevantes (nueva sección, cambio de oferta destacada, rediseño de layout), descartando variaciones triviales de renderizado.","modo":"Capturas manuales periódicas (o con una herramienta de monitoreo de capturas) que se entregan a la IA para comparación y descripción de diferencias.","pasos":["Elige las páginas clave del rival que quieres vigilar (home, precios, producto principal).","Toma una captura de referencia y guárdala con fecha.","Repite la captura con la frecuencia que tenga sentido (semanal, mensual, o tras una campaña que detectes).","Pide a la IA que compare ambas capturas y describa los cambios de contenido y diseño relevantes.","Descarta del informe variaciones que sean solo ruido visual (fecha, contador, banner rotativo)."],"reglas":["No reportar como cambio variaciones que sean solo de renderizado dinámico normal (reloj, banner rotativo, cookies).","Enfocar el análisis en cambios de mensaje, oferta o estructura, no en detalles cosméticos irrelevantes.","Usar solo páginas públicas accesibles sin necesidad de login.","Ser explícito cuando la comparación sea ambigua en vez de forzar una conclusión."],"prompt":"Actúa como analista de diseño y mensajes web. Te voy a describir o adjuntar dos capturas de pantalla de la misma página de mi competidor [nombre]: una del [fecha 1] y otra del [fecha 2]. Compáralas y describe los cambios relevantes en contenido, oferta destacada, estructura o llamadas a la acción. Ignora diferencias que sean solo variaciones de renderizado dinámico (fecha/hora, banner rotativo, contador, pequeño reacomodo de elementos). Si la comparación es ambigua o no puedes distinguir un cambio real de ruido visual, dilo explícitamente en vez de forzar una conclusión.\n\nDescripción/captura 1 (fecha):\n[pega aquí]\n\nDescripción/captura 2 (fecha):\n[pega aquí]"}},
  {"id":"gr42","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Web y producto del rival","titulo":"Sigue de cerca qué actualiza realmente tu competencia en su producto","beneficio":"Te ayuda a entender hacia dónde evoluciona el producto del rival y a distinguir lanzamientos con peso real de simples retoques cosméticos, para calibrar tu propia hoja de ruta.","alcance":"Recopila y organiza las entradas del changelog o notas de versión que el rival publica públicamente, clasificando cada una según si describe una mejora funcional importante o un ajuste visual o menor, en base a lo que el propio texto anuncia. No tiene visibilidad de su roadmap interno ni de funciones aún no lanzadas.","precio":1.99,"blueprint":{"quePuedeHacer":"Reúne las entradas públicas del changelog del rival a lo largo del tiempo y las clasifica como cambio de impacto (nueva función, integración, cambio de precio o plan) o ajuste menor (retoque visual, corrección de errores menores), para darte una lectura rápida de su ritmo de desarrollo.","modo":"Seguimiento periódico manual del changelog o notas de versión públicas, con la IA resumiendo y clasificando las entradas que le entregues.","pasos":["Localiza la página pública de changelog, notas de versión o blog de producto del rival.","Recopila las entradas publicadas desde tu última revisión.","Pide a la IA que clasifique cada entrada como impacto real o ajuste menor, con su justificación.","Revisa la clasificación y ajústala si el contexto del sector te da información adicional.","Usa el resumen para alimentar tu propia planificación de producto o marketing."],"reglas":["Basar la clasificación de impacto real frente a menor en lo que el propio texto describe, no en suposiciones sin respaldo.","No presentar el resumen como conocimiento del roadmap futuro del rival, solo de lo ya publicado.","Señalar cuando una entrada sea ambigua en vez de forzarla a una categoría.","Trabajar únicamente con información que el rival decide hacer pública."],"prompt":"Actúa como analista de producto. Te voy a pegar las entradas de changelog o notas de versión públicas de mi competidor [nombre] publicadas desde [fecha]. Para cada entrada, clasifícala como 'cambio de impacto' (nueva función, integración, cambio de plan o precio) o 'ajuste menor' (retoque visual, corrección de errores) según lo que el propio texto describe. Si una entrada es ambigua, dilo en vez de forzar la clasificación. Al final, dame un resumen del ritmo y dirección de desarrollo que sugiere este periodo.\n\nEntradas de changelog (con fecha de cada una):\n[pega aquí]"}},
  {"id":"gr43","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Web y producto del rival","titulo":"Descubre qué herramientas usa tu competencia para operar su web","beneficio":"Te da pistas sobre en qué está invirtiendo el rival a nivel tecnológico (plataforma de e-commerce, CRM, chat, analítica, pagos) a partir de señales visibles en su propio sitio, útiles para evaluar si necesitas actualizar tu propia infraestructura.","alcance":"Identifica herramientas y plataformas a partir de señales públicas del código del sitio (scripts cargados, cookies visibles, cabeceras HTTP, metadatos). No accede a configuraciones internas, contratos ni al panel de administración del rival; es una inferencia razonable, no una confirmación oficial.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza el código fuente público y las peticiones de red visibles de la web del rival para identificar qué plataformas (e-commerce, CRM, analítica, chat, pagos, CDN) probablemente utiliza, a partir de scripts, cookies y cabeceras detectables.","modo":"Inspección manual del código fuente y las herramientas de desarrollador del navegador (o herramientas públicas de identificación de tecnologías), con la IA interpretando y organizando las señales encontradas.","pasos":["Abre la web del rival y revisa el código fuente y la pestaña de red de las herramientas de desarrollador.","Anota los scripts, dominios de terceros y cookies visibles que aparecen cargados.","Pide a la IA que identifique a qué categoría de herramienta corresponde cada señal (analítica, CRM, pagos, CDN, chat, etc.).","Contrasta el resultado con fuentes públicas de identificación tecnológica si tienes acceso a alguna.","Usa el perfil resultante como hipótesis razonable, no como hecho confirmado."],"reglas":["Presentar los hallazgos como inferencia a partir de señales públicas, nunca como confirmación oficial del stack del rival.","No intentar acceder a paneles, APIs privadas o áreas restringidas para verificar la hipótesis.","Actualizar el perfil periódicamente, ya que las herramientas usadas pueden cambiar sin aviso.","Aclarar que compartir el mismo stack no implica competir de la misma forma; la tecnología es solo una señal más."],"prompt":"Actúa como analista técnico. Te voy a describir las señales públicas que encontré al revisar el código fuente y la pestaña de red del navegador en la web de mi competidor [nombre]: scripts cargados, dominios de terceros, cookies visibles y cabeceras HTTP relevantes. A partir de esas señales, identifica a qué categoría de herramienta corresponde cada una (analítica, CRM, chat, pagos, CDN, plataforma de e-commerce, etc.) y arma un perfil probable de su stack tecnológico. Deja claro en tu respuesta que esto es una inferencia razonable a partir de señales públicas, no una confirmación oficial.\n\nSeñales encontradas (scripts, dominios, cookies, cabeceras):\n[pega aquí]"}},
  {"id":"gr44","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Web y producto del rival","titulo":"Relaciona las bajadas de valoración de la app rival con sus lanzamientos","beneficio":"Te ayuda a detectar si una nueva versión de la app del rival generó fricción con sus usuarios, un momento en el que podrías posicionar tu propia app como alternativa más estable.","alcance":"Compara el historial público de versiones de la app del rival (App Store, Google Play) con la evolución de sus valoraciones y reseñas visibles. Señala coincidencias temporales entre un lanzamiento y un cambio en la valoración, sin poder demostrar causalidad certera, solo correlación observable.","precio":1.99,"blueprint":{"quePuedeHacer":"Recopila el historial de versiones publicadas por el rival en las tiendas de apps y lo cruza con la evolución pública de su valoración media y comentarios recientes, señalando los periodos donde ambas cosas coinciden en el tiempo.","modo":"Revisión periódica manual de la ficha pública de la app del rival en App Store o Google Play, con la IA organizando el cruce entre fechas de versión y cambios en valoración o comentarios.","pasos":["Revisa la ficha pública de la app del rival y anota el historial de versiones con sus fechas.","Registra la valoración media visible y algunos comentarios recientes en cada revisión.","Pide a la IA que cruce ambas líneas de tiempo y señale coincidencias entre lanzamientos y variaciones en la valoración.","Lee los comentarios de las fechas señaladas para entender el motivo real de la queja, si lo mencionan.","Usa la coincidencia como pista a investigar, no como prueba definitiva de causa-efecto."],"reglas":["Tratar las coincidencias temporales como correlación observable, nunca como causalidad demostrada.","Usar solo información pública de la ficha de la app (versiones, valoración media, reseñas visibles).","No automatizar la extracción de datos de forma que viole los términos de servicio de las tiendas de apps.","Diferenciar quejas puntuales de patrones que se repiten en varias reseñas."],"prompt":"Actúa como analista de producto móvil. Te voy a dar el historial de versiones publicadas por la app de mi competidor [nombre] en [App Store/Google Play], con sus fechas, junto con la evolución de la valoración media y una muestra de comentarios recientes en cada periodo. Cruza ambas líneas de tiempo y señala en qué lanzamientos coincide una caída o subida notable en la valoración, o un aumento de quejas similares. Para cada coincidencia señalada, resume de qué se quejan los comentarios de ese periodo si lo mencionan. Aclara siempre que se trata de una correlación temporal observable, no de una prueba de causalidad.\n\nHistorial de versiones y valoraciones (versión, fecha, valoración media, comentarios de muestra):\n[pega aquí]"}},
  {"id":"gr45","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Clientes y mercado","titulo":"Encuentra en qué falla tu competencia según sus propios clientes","beneficio":"Te muestra en qué áreas (envío, calidad, precio, soporte) se queja más la clientela del rival, para que puedas reforzar justo esos puntos en tu propia propuesta y comunicarlo con honestidad.","alcance":"Agrupa y clasifica reseñas públicas del rival (tiendas de apps, marketplaces, Google Business, sitios de reseñas) por categoría de queja. No incluye reseñas privadas ni datos personales de quien reseña; trabaja solo con el texto público disponible.","precio":1.99,"blueprint":{"quePuedeHacer":"Reúne reseñas públicas del rival, las agrupa por categoría de queja (envío, calidad, precio, soporte, otras) y te da un resumen de cuáles son las quejas más recurrentes, como insumo para reforzar tu propia oferta en esos puntos.","modo":"Recopilación manual o semi-asistida de reseñas públicas, con la IA clasificando y resumiendo los textos que le entregues.","pasos":["Recolecta un conjunto de reseñas públicas recientes del rival (tienda de apps, marketplace, Google Business, sitio de reseñas del sector).","Pide a la IA que clasifique cada reseña por categoría de queja predominante.","Revisa el resumen de categorías más recurrentes.","Contrasta esas debilidades con tu propia propuesta: si ya las cubres mejor y si puedes comunicarlo.","Repite la recolección periódicamente para ver si el patrón de quejas cambia."],"reglas":["Usar solo reseñas públicas, sin extraer ni conservar datos personales de quien las escribió.","No presentar una queja aislada como un patrón generalizado sin más evidencia.","Distinguir quejas recientes de quejas antiguas que el rival pudo haber resuelto.","Usar el hallazgo para mejorar tu propia propuesta, no para atacar públicamente al rival."],"prompt":"Actúa como analista de experiencia de cliente. Te voy a pegar un conjunto de reseñas públicas recientes de mi competidor [nombre] (tienda de apps, marketplace, Google Business o sitio de reseñas del sector). Clasifica cada reseña por categoría de queja predominante (envío, calidad, precio, soporte, otra) y dame un resumen de las categorías más recurrentes con 2-3 ejemplos representativos de cada una, sin datos personales de quien las escribió. Señala también si algunas quejas parecen recientes o antiguas. Termina con una idea de en qué punto podría diferenciarse mejor mi propuesta frente a esas debilidades.\n\nReseñas recopiladas (sin datos personales):\n[pega aquí el texto de las reseñas]"}},
  {"id":"gr46","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Clientes y mercado","titulo":"Descubre qué búsquedas te disputas con tu competencia","beneficio":"Te permite priorizar tu contenido y tu SEO hacia los términos de búsqueda relevantes que también persigue el rival, excluyendo búsquedas de marca, en vez de repartir esfuerzo a ciegas.","alcance":"Compara los términos de búsqueda no relacionados con nombres de marca que aparecen para tu web y para la del rival, usando tus propios datos de Google Search Console y herramientas de investigación de palabras clave de terceros para estimar los del rival. No hay acceso a los datos exactos de Search Console del rival, que son privados; se trabaja con estimaciones de herramientas públicas de SEO.","precio":1.99,"blueprint":{"quePuedeHacer":"Cruza tus propios términos de búsqueda de Search Console con una estimación de los términos del rival obtenida de herramientas de investigación de palabras clave, y señala los términos genéricos, no de marca, donde ambos aparecen, para priorizar oportunidades de contenido.","modo":"Análisis manual o asistido que combina tus datos propios de Search Console con estimaciones de herramientas de terceros de investigación de palabras clave, sintetizado por la IA.","pasos":["Exporta tus términos de búsqueda desde Google Search Console del último periodo relevante.","Obtén una estimación de los términos de búsqueda del rival desde una herramienta de investigación de palabras clave.","Excluye de ambas listas las búsquedas de marca propia, tuya y del rival.","Pide a la IA que identifique los términos genéricos que aparecen en ambas listas y los que son exclusivos de cada uno.","Prioriza contenido o SEO hacia los términos de solapamiento con mayor relevancia para tu negocio."],"reglas":["Excluir siempre las búsquedas de marca propia, tuya y del rival, del análisis de solapamiento.","Aclarar que los datos del rival son una estimación de herramienta externa, no un acceso directo a su Search Console.","No tratar el volumen estimado como una cifra exacta garantizada.","Priorizar términos por relevancia de negocio, no solo por volumen aparente."],"prompt":"Actúa como analista SEO. Te voy a dar (1) mis términos de búsqueda exportados de Google Search Console del último periodo y (2) una estimación de términos de búsqueda de mi competidor [nombre] obtenida de una herramienta de investigación de palabras clave. Excluye de ambas listas cualquier búsqueda de marca (mi nombre o el del rival). Identifica: términos genéricos donde ambos aparecemos (solapamiento), términos donde solo aparezco yo, y términos donde solo aparece el rival. Prioriza los términos de solapamiento y los exclusivos del rival según su relevancia aparente para mi negocio, y aclara que los datos del rival son una estimación externa, no un acceso directo a su Search Console.\n\nMis términos (Search Console):\n[pega aquí]\n\nTérminos estimados del rival:\n[pega aquí]"}},
  {"id":"gr47","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Clientes y mercado","titulo":"Intuye hacia dónde invierte tu competencia según sus vacantes","beneficio":"Te da una lectura indirecta pero útil de las prioridades del rival, por ejemplo si está reforzando ventas, producto o un país nuevo, a partir de sus ofertas de empleo públicas, sin usar datos personales de candidatos.","alcance":"Revisa las vacantes que el rival publica abiertamente (su web de empleo, portales de empleo) y las agrupa por área y ubicación para detectar dónde está poniendo foco. No usa información personal de quienes aplican ni de empleados actuales; se limita al texto público de la oferta.","precio":1.99,"blueprint":{"quePuedeHacer":"Recopila las vacantes públicas activas del rival, las agrupa por departamento y ubicación geográfica, y señala patrones de concentración (por ejemplo, varias vacantes de un mismo tipo abiertas a la vez) como indicio de dónde está invirtiendo.","modo":"Revisión periódica manual de portales públicos de empleo y la propia web de carreras del rival, con la IA organizando y resumiendo los patrones.","pasos":["Revisa la página de empleo del rival y sus publicaciones en portales de vacantes.","Anota cada vacante activa con su departamento y ubicación.","Pide a la IA que agrupe las vacantes por área y ubicación y señale concentraciones relevantes.","Interpreta el patrón como una señal de dirección estratégica, no como un hecho confirmado.","Repite la revisión periódicamente para notar cambios de foco."],"reglas":["Usar únicamente el texto público de la oferta de empleo, nunca datos de candidatos o empleados.","Tratar los patrones de contratación como indicio de dirección, no como confirmación de una estrategia específica.","No contactar candidatos ni empleados del rival para obtener información adicional bajo pretextos falsos.","Actualizar el análisis con regularidad, ya que las vacantes se abren y cierran con rapidez."],"prompt":"Actúa como analista de inteligencia de mercado. Te voy a pegar la lista de vacantes públicas activas de mi competidor [nombre], con su departamento y ubicación, recopiladas de su web de empleo y portales como LinkedIn o Indeed. Agrupa las vacantes por departamento y ubicación, y señala si hay una concentración inusual en algún área (por ejemplo, varias vacantes similares abiertas al mismo tiempo). Interpreta esos patrones como una posible dirección estratégica del rival (expansión de ventas, nuevo mercado, refuerzo de producto), dejando claro que es una lectura indirecta y no una confirmación oficial.\n\nVacantes recopiladas (puesto, departamento, ubicación, fecha de publicación):\n[pega aquí]"}},
  {"id":"gr48","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Infraestructura y consolidación de datos","titulo":"Entiende qué datos expone públicamente la web de tu competencia","beneficio":"Te permite ver qué información devuelve públicamente la web o app del rival mientras la navegas normalmente (precios, catálogo, disponibilidad), útil para entender su estructura de datos sin necesidad de acceso privilegiado.","alcance":"Captura únicamente las respuestas que la propia web o app del rival envía a tu navegador mientras la usas normalmente como cualquier visitante. No registra ni intenta capturar tokens de sesión, cookies personales o credenciales de otros usuarios, y no intenta acceder a rutas privadas o protegidas.","precio":1.99,"blueprint":{"quePuedeHacer":"Analiza las respuestas públicas que el navegador recibe al navegar normalmente por la web o app del rival, como listados de producto, precios o disponibilidad expuestos en las llamadas a su interfaz pública, para entender qué datos hace visibles, descartando cualquier información de sesión o credenciales.","modo":"Inspección manual con las herramientas de desarrollador del navegador mientras navegas como usuario normal, con la IA interpretando y organizando las respuestas públicas capturadas.","pasos":["Navega la web o usa la app del rival como lo haría cualquier cliente, con la pestaña de red del navegador abierta.","Identifica las llamadas que devuelven datos de catálogo, precios o disponibilidad visibles en pantalla.","Descarta y elimina de tu registro cualquier token, cookie de sesión o dato de autenticación que aparezca.","Pide a la IA que organice los datos públicos capturados en una estructura legible.","Usa la información solo para entender la estructura de datos visible, no para acceder a nada restringido."],"reglas":["Nunca registrar, guardar ni intentar usar tokens de sesión, cookies personales o credenciales.","No intentar acceder a rutas, parámetros o endpoints que requieran autenticación o que no estén destinados a un visitante normal.","Limitarse a la información que el propio sitio expone a cualquier visitante en el uso normal de la interfaz.","Detener el análisis si se detecta que se está accediendo a datos que deberían ser privados."],"prompt":"Actúa como analista técnico. Te voy a pegar las respuestas públicas (JSON o texto) que capturé con las herramientas de desarrollador del navegador mientras navegaba normalmente la web o app de mi competidor [nombre]: listados de producto, precios o disponibilidad que la interfaz muestra a cualquier visitante. Ya eliminé de este registro cualquier token, cookie de sesión o dato de autenticación. Organiza estos datos públicos en una estructura legible (campos y valores) y descríbeme qué información de catálogo o negocio parece exponer su interfaz pública. Si detectas en el texto que pegué algo que parece un token, sesión o credencial, avísame para que lo elimine en vez de procesarlo.\n\nRespuestas públicas capturadas (ya sin tokens ni cookies):\n[pega aquí]"}},
  {"id":"gr49","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Infraestructura y consolidación de datos","titulo":"Descubre qué subdominios públicos mantiene activa tu competencia","beneficio":"Te da una visión de la superficie pública (subdominios de marketing, documentación, entornos de prueba olvidados) que el rival mantiene activa, útil para entender su estructura digital y detectar áreas que tú podrías cubrir mejor.","alcance":"Revisa subdominios públicos del rival mediante técnicas de descubrimiento no invasivas (certificados públicos, registros DNS públicos). No incluye escaneo de puertos agresivo, pruebas de intrusión ni ningún intento de acceder a sistemas protegidos; se limita a listar lo que ya es públicamente visible.","precio":1.99,"blueprint":{"quePuedeHacer":"Enumera los subdominios públicos conocidos del dominio del rival usando fuentes abiertas (registros de certificados públicos, DNS abierto), y los organiza por tipo aparente (marketing, documentación, entorno de prueba expuesto, etc.) para darte una foto de su superficie digital pública.","modo":"Consulta manual de herramientas públicas de descubrimiento de subdominios basadas en certificados y DNS públicos, con la IA organizando y clasificando el listado resultante.","pasos":["Usa una herramienta pública de descubrimiento de subdominios basada en registros de certificados o DNS abiertos.","Obtén el listado de subdominios visibles asociados al dominio del rival.","Pide a la IA que clasifique cada subdominio por tipo aparente según su nombre y lo que responde al visitarlo públicamente.","Señala cualquier subdominio que parezca un entorno de prueba expuesto por descuido, sin intentar explotarlo.","Usa el mapa resultante solo para entender su estructura digital pública."],"reglas":["Limitarse a técnicas no invasivas de descubrimiento; nunca escaneo de puertos agresivo ni pruebas de intrusión.","No intentar acceder, modificar ni explotar ningún subdominio o sistema que parezca mal configurado.","Si se detecta una exposición que parezca un descuido de seguridad del rival, no explotarla ni divulgarla públicamente.","Trabajar solo con fuentes de información ya públicas, nunca con accesos no autorizados."],"prompt":"Actúa como analista de infraestructura digital. Te voy a pegar el listado de subdominios públicos de mi competidor [nombre] que obtuve con una herramienta no invasiva de descubrimiento basada en certificados públicos o DNS abierto. Clasifica cada subdominio por tipo aparente según su nombre y lo que responde públicamente al visitarlo (marketing, documentación, entorno de prueba, tienda, blog, etc.). Señala cuáles parecen entornos de prueba o desarrollo expuestos por descuido, sin sugerir ninguna forma de acceder, explotar o probar su seguridad; solo repórtalo como observación.\n\nListado de subdominios:\n[pega aquí]"}},
  {"id":"gr50","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Clientes y mercado","titulo":"Compara el temario de formación de tu competencia con el tuyo","beneficio":"Te ayuda a identificar huecos o duplicidades en tu propia oferta formativa comparando la estructura pública de los cursos del rival, sin necesidad de comprar ni copiar su contenido.","alcance":"Resume el índice o temario público de cursos del rival, lo que normalmente se muestra antes de comprar: módulos, lecciones, duración. No accede ni reproduce el contenido protegido de las lecciones en sí, solo la estructura visible públicamente.","precio":1.99,"blueprint":{"quePuedeHacer":"Reúne el índice público de contenidos (módulos, lecciones, temario) de los cursos del rival y lo organiza en un esquema comparable con tu propia oferta formativa, sin extraer ni reproducir el material protegido de las lecciones.","modo":"Recopilación manual del temario público mostrado en la página de venta del curso, sintetizado por la IA en una estructura comparativa.","pasos":["Visita la página pública de venta del curso del rival y copia el índice de módulos y lecciones que se muestra antes de la compra.","Repite para cada curso relevante que quieras comparar.","Pide a la IA que organice los temarios en un esquema comparable (módulo, subtema, duración si está disponible).","Compáralo con el temario de tu propia oferta formativa.","Identifica huecos, duplicidades o énfasis distintos entre ambas ofertas."],"reglas":["Usar únicamente el índice o temario que el propio rival muestra públicamente como material promocional.","No comprar el curso solo para copiar el contenido protegido de las lecciones.","No reproducir textualmente el temario del rival en tu propio material de marketing; usarlo solo como referencia interna.","Distinguir entre la estructura del curso, que es pública, y el contenido de las lecciones, que está protegido."],"prompt":"Actúa como analista de producto educativo. Te voy a pegar el índice público (módulos y lecciones) que muestra la página de venta de un curso de mi competidor [nombre], junto con el índice de mi propio curso equivalente. Organiza ambos temarios en un esquema comparable (módulo, subtema, duración si está disponible) y señala: temas que el rival cubre y yo no, temas que yo cubro y el rival no, y temas donde ambos coincidimos con un énfasis distinto. No reproduzcas el temario del rival tal cual en ningún material de marketing, úsalo solo como referencia interna para mejorar mi propia oferta.\n\nÍndice del curso del rival:\n[pega aquí]\n\nÍndice de mi curso:\n[pega aquí]"}},
  {"id":"gr51","catalogo":"growth","grupo":"Inteligencia competitiva","tema":"Infraestructura y consolidación de datos","titulo":"Reúne toda tu inteligencia competitiva en un solo panel","beneficio":"Te ahorra tiempo y errores al unificar en un único lugar las distintas fuentes de vigilancia competitiva que ya usas (precios, anuncios, reseñas, menciones), con nombres de columna estandarizados para poder comparar de un vistazo.","alcance":"Organiza y estandariza los datos que tú mismo recopilas de las distintas fuentes de inteligencia competitiva en un panel unificado. No crea ni conecta automáticamente accesos a sistemas privados de terceros; consolida lo que tú ya reúnes de fuentes públicas.","precio":1.99,"blueprint":{"quePuedeHacer":"Toma los datos que recopilas de distintas fuentes de vigilancia competitiva (precios, anuncios, reseñas, menciones, vacantes) y los une en una única estructura de panel, estandarizando nombres de columnas y formatos para que sean comparables y fáciles de mantener.","modo":"Consolidación manual o semi-asistida de hojas de cálculo o exportaciones ya recopiladas por ti, con la IA proponiendo una estructura estandarizada de columnas y unificando los formatos.","pasos":["Reúne las distintas fuentes de datos de inteligencia competitiva que ya recopilas.","Identifica qué columnas o campos usa cada fuente y dónde hay inconsistencias de nombre o formato.","Pide a la IA que proponga una estructura de columnas estandarizada válida para todas las fuentes.","Unifica los datos en un panel central (hoja de cálculo o herramienta de BI) siguiendo esa estructura.","Actualiza el panel con la periodicidad de cada fuente y revisa que los nombres se mantengan consistentes."],"reglas":["Consolidar solo datos que tú ya recopilaste de fuentes públicas legítimas, nunca crear accesos nuevos a sistemas privados.","Mantener nombres de columna estandarizados y documentados para que cualquier persona del equipo entienda el panel.","Señalar cuándo un dato está desactualizado en vez de dejarlo como si fuera vigente.","Tratar el panel como un resumen para apoyar decisiones humanas, no como un sistema que decide automáticamente acciones de negocio."],"prompt":"Actúa como analista de datos. Te voy a describir las distintas fuentes de inteligencia competitiva que ya recopilo por separado (por ejemplo: hoja de precios del rival, registro de anuncios, resumen de reseñas, menciones de prensa, vacantes) y los nombres de columna que usa cada una. Propón una estructura de columnas estandarizada que permita unificar todas estas fuentes en un único panel (por ejemplo: fecha, fuente, categoría, dato, marca, notas). Indica cómo debería mapearse cada columna actual a la estructura nueva. Recuérdame señalar en el panel cuándo un dato quedó desactualizado.\n\nMis fuentes actuales y sus columnas:\n[pega aquí cada fuente con sus columnas actuales]"}},
  {"id":"gr52","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Medición y atribución","titulo":"Define qué momentos de compra debes medir de verdad","beneficio":"Sabrás exactamente qué acciones de tus clientes contar (ver, añadir al carrito, pagar, comprar) y qué datos mínimos necesita cada una, para que tus informes de campañas se apoyen en datos completos y no en huecos.","alcance":"Sirve para ordenar qué medir antes de configurar píxeles o etiquetas; no reemplaza la implementación técnica en tu plataforma de anuncios o analítica, ni garantiza que las conversiones reportadas mejoren automáticamente — depende de cómo actives después esos eventos en cada herramienta.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a definir un esquema de eventos de conversión para tu embudo (por ejemplo: vista de producto, añadir al carrito, inicio de pago, compra), proponiendo qué datos mínimos debería llevar cada evento (valor, moneda, identificador de producto, identificador de usuario si aplica) para que sirvan tanto a tu plataforma de anuncios como a tu analítica interna.","modo":"Asistido: la IA propone el esquema de eventos y sus campos a partir de la descripción de tu negocio; una persona del equipo (o tu agencia o desarrollador) lo revisa y lo implementa en la web y en las plataformas de medición.","pasos":["Describe a la IA las etapas reales de tu proceso de compra o contratación, desde que alguien llega a la web hasta que paga o firma.","Pide que proponga un evento por cada etapa relevante, con un nombre claro y consistente entre plataformas.","Pide que liste, para cada evento, los datos mínimos que debería llevar: valor, moneda, categoría, identificador de producto u otros que apliquen a tu negocio.","Revisa el esquema con quien vaya a implementarlo técnicamente (desarrollador, agencia o la propia plataforma de anuncios) para confirmar que es viable.","Documenta el esquema final como referencia para futuras campañas o integraciones."],"reglas":["No incluyas datos personales identificables (nombre, email, teléfono) sin cifrar en los eventos que viajan a plataformas publicitarias.","Usa nombres de evento consistentes entre plataformas (web, app, servidor) para poder comparar datos más adelante.","Revisa el esquema con alguien técnico antes de implementarlo; la IA propone la estructura, no sustituye la validación humana.","No prometas que este esquema por sí solo mejorará el rendimiento de las campañas: solo ordena qué medir."],"prompt":"Actúa como consultor de medición digital. Te voy a describir mi negocio y el proceso que sigue un cliente desde que nos conoce hasta que compra o contrata. Con esa información, propón un esquema de eventos de conversión para mi embudo: nombra cada evento de forma clara y consistente, indica en qué etapa ocurre, y lista los datos mínimos que debería llevar cada uno (valor, moneda, identificador de producto o servicio, categoría u otros campos relevantes). No inventes eventos que no correspondan a mi proceso real. Aquí está la descripción de mi negocio y mi embudo: [pega aquí la descripción de tu proceso de venta o contratación, paso a paso]."}},
  {"id":"gr53","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Medición y atribución","titulo":"Envía tus datos de conversión aunque el navegador los bloquee","beneficio":"Configura el envío de tus eventos de conversión también desde tu propio servidor, no solo desde el navegador del visitante, para que bloqueadores de anuncios, navegadores restrictivos o cookies desactivadas no te dejen ciego sobre qué campañas funcionan.","alcance":"Ayuda a diseñar y documentar una implementación de medición del lado del servidor, por ejemplo mediante una Conversions API; no sustituye el trabajo de un desarrollador para integrarla en tu web, ni garantiza que tus informes de campañas mejoren — depende de tu volumen de datos y de cómo la configures.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a planificar el envío de eventos de conversión desde tu servidor hacia las plataformas publicitarias, además del envío habitual desde el navegador, explicando qué evento debe enviarse, con qué datos, y cómo evitar duplicados cuando el mismo evento llega por las dos vías.","modo":"Asistido: la IA diseña el plan de implementación (qué eventos, qué datos, cómo deduplicar); un desarrollador o tu agencia técnica lo implementa en el servidor.","pasos":["Identifica junto con la IA qué eventos de conversión ya envías desde el navegador y cuáles se están perdiendo por bloqueadores o restricciones de cookies.","Pide un plan de qué datos debe llevar cada evento cuando se envía desde el servidor: identificador de evento, marca de tiempo, datos de contacto cifrados si aplica, valor de la compra.","Pide que explique cómo usar un identificador común de evento para deduplicar cuando el mismo evento llega por el navegador y por el servidor.","Entrega el plan a tu desarrollador o agencia para la implementación técnica en tu servidor o plataforma de comercio electrónico.","Verifica junto con quien lo implemente que las plataformas publicitarias confirman la recepción correcta de los eventos, antes de darlo por cerrado."],"reglas":["Cualquier dato personal (email, teléfono) que se envíe debe ir cifrado, por ejemplo con SHA-256, nunca en texto plano.","Define siempre un identificador único de evento para poder deduplicar entre navegador y servidor; sin esto, tus informes contarán conversiones dos veces.","No actives el envío en producción sin que un desarrollador revise la implementación y las plataformas confirmen la recepción.","No presentes esto como una garantía de mejor rendimiento: mejora la calidad de la medición, no el resultado de las campañas por sí solo."],"prompt":"Actúa como consultor técnico de medición digital. Quiero enviar mis eventos de conversión también desde mi servidor, no solo desde el navegador, para no depender únicamente del píxel del navegador. Te voy a decir qué plataforma de anuncios uso y qué eventos ya mido desde el navegador. Con esa información: 1) dime qué eventos deberían enviarse también desde el servidor, 2) qué datos mínimos debe llevar cada uno, 3) cómo evitar que el mismo evento se cuente dos veces, una desde el navegador y otra desde el servidor, y 4) qué debo pedirle a mi desarrollador para implementarlo. Mi contexto: [plataforma de anuncios], [lista de eventos que mides hoy desde el navegador], [plataforma de comercio electrónico o CMS que usas]."}},
  {"id":"gr54","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Medición y atribución","titulo":"Entiende qué canales realmente ayudan a cerrar una venta","beneficio":"Calcula qué peso tuvo cada canal (anuncio, email, redes sociales, búsqueda) en una compra que pasó por varios puntos de contacto antes de cerrarse, para que no le des todo el crédito, ni todo el presupuesto, al último clic.","alcance":"Es un modelo de reparto de crédito entre canales, útil para decidir dónde invertir con más contexto; no es una medición exacta ni universal — distintos modelos de atribución dan pesos distintos, y el resultado depende de qué datos de contacto tengas disponibles y de la longitud real del recorrido de tus clientes.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a definir y calcular un modelo de atribución multi-touch, por ejemplo reparto igualitario entre puntos de contacto o con más peso al primer y último contacto, a partir de los datos de recorrido de cliente que le proporciones, para estimar la contribución relativa de cada canal a una conversión.","modo":"Asistido: tú aportas los datos de los puntos de contacto por conversión, de tu CRM, analítica o plataforma de email; la IA aplica el modelo de reparto que elijas y explica los resultados.","pasos":["Reúne, para un conjunto de conversiones recientes, la secuencia de canales que tocó cada cliente antes de comprar: anuncio, email, redes, búsqueda orgánica, directo.","Con la IA, elige un modelo de reparto de crédito adecuado a tu negocio, por ejemplo reparto equitativo entre todos los puntos de contacto, o con más peso al primero y al último.","Pide que calcule, con los datos que aportaste, qué porcentaje de crédito recibe cada canal en conjunto.","Pide una explicación en lenguaje simple de qué significa el resultado y qué limitaciones tiene: datos incompletos, recorridos no capturados, etc.","Usa el resultado como un dato más, no el único, para decidir cómo repartir tu presupuesto entre canales."],"reglas":["Deja claro qué modelo de reparto se usó (equitativo, con más peso al primero o al último, u otro) porque cada uno da resultados distintos con los mismos datos.","No trates el resultado como una cifra exacta de retorno de inversión: es una estimación de contribución relativa, limitada a los datos que capturaste.","Si te faltan datos de algún canal, por ejemplo no rastreas email, dilo explícitamente en vez de asumir que ese canal no participó.","No uses este modelo como única base para eliminar de golpe un canal de tu mezcla de marketing; combínalo con otras señales del negocio."],"prompt":"Actúa como analista de atribución de marketing. Te voy a compartir los puntos de contacto (canal y fecha aproximada) que tocaron varios clientes antes de completar una compra o contratación. Aplica un modelo de atribución multi-touch con reparto equitativo entre todos los puntos de contacto, y si te lo pido, prueba también un reparto con más peso al primer y al último contacto. Calcula qué porcentaje de crédito recibe cada canal en conjunto, explica las limitaciones del resultado (datos incompletos, canales no rastreados) y evita presentarlo como una cifra exacta de retorno. Aquí están los recorridos: [pega la lista de conversiones con su secuencia de canales]."}},
  {"id":"gr55","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Creatividad y personalización de anuncios","titulo":"Sube muchas variantes de anuncios sin errores de formato","beneficio":"Prepara y sube variaciones de tus anuncios de forma masiva a tu plataforma publicitaria, comprobando antes que cada una cumple los requisitos de formato, tamaño y peso, para no perder tiempo con rechazos o rebotes de creatividades.","alcance":"Ayuda a organizar y validar el proceso de carga masiva de anuncios; no crea las imágenes o videos por ti ni garantiza la aprobación de la plataforma publicitaria — cada plataforma revisa el contenido y sus políticas por separado.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a preparar una hoja de control con todas tus variantes de anuncio (texto, referencia de archivo, formato, plataforma de destino) y a revisar, a partir de las especificaciones que le indiques, si cada archivo cumple los requisitos técnicos (dimensiones, peso, duración, relación de aspecto) antes de subirlos por lotes.","modo":"Asistido: la IA organiza y valida la lista contra las especificaciones técnicas que tú le proporciones; la carga final a la plataforma la hace una persona o una herramienta de gestión de campañas.","pasos":["Reúne las especificaciones técnicas de tu plataforma publicitaria (formatos aceptados, peso máximo, dimensiones, duración de video) y compártelas con la IA.","Entrega la lista de tus variantes de creatividad: nombre de archivo, texto asociado, formato, plataforma de destino.","Pide que revise cada variante contra las especificaciones y marque cuáles cumplen y cuáles no, indicando el motivo.","Corrige las variantes marcadas antes de iniciar la carga por lotes.","Sube el lote ya validado a tu plataforma o herramienta de gestión de campañas."],"reglas":["Verifica siempre las especificaciones técnicas actuales de la plataforma antes de validar, porque cambian con el tiempo.","La validación de formato no sustituye la revisión de contenido y políticas publicitarias de la plataforma, que decide aparte.","Revisa una muestra del lote manualmente antes de subir todo, aunque la validación automática indique que está correcto.","No subas creatividades sin confirmar los derechos de uso de imágenes, videos o música incluidos."],"prompt":"Actúa como asistente de operaciones de campañas publicitarias. Te voy a dar las especificaciones técnicas de mi plataforma de anuncios (formatos, peso máximo, dimensiones, duración) y una lista de mis variantes de creatividad con su nombre de archivo, texto y formato previsto. Revisa cada variante contra las especificaciones, indica cuáles cumplen y cuáles no y por qué, y organiza el resultado en una tabla que pueda usar para la carga por lotes. Especificaciones: [pega las especificaciones]. Lista de variantes: [pega tu lista]."}},
  {"id":"gr56","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Creatividad y personalización de anuncios","titulo":"Personaliza el texto de tus anuncios sin arriesgarte a errores","beneficio":"Inserta variables como la ciudad del usuario o el producto que vio en el texto del anuncio, pero solo cuando el valor está dentro de una lista de términos que tú apruebas antes, para evitar anuncios con errores, huecos en blanco o textos fuera de tono.","alcance":"Sirve para diseñar la lista de términos aprobados y las reglas de reemplazo; la ejecución técnica del texto dinámico depende de las funciones de personalización de tu plataforma publicitaria, y su efecto en el rendimiento varía según tu audiencia y oferta.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a construir y mantener una lista de términos aprobados (ciudades, categorías de producto, nombres) para usar en texto dinámico de anuncios, y a redactar las reglas de una plantilla de anuncio que solo inserte la variable cuando el valor coincide con esa lista, dejando un texto alternativo por defecto en cualquier otro caso.","modo":"Asistido: la IA propone la lista de términos aprobados y el texto por defecto de respaldo; una persona la revisa y la configura en la plataforma de anuncios.","pasos":["Comparte con la IA las variables que quieres personalizar (ciudad, producto visto, categoría) y de dónde provienen esos datos.","Pide que redacte una lista inicial de términos aprobados para cada variable, basada en tu catálogo o zonas de servicio reales.","Pide un texto alternativo de respaldo para cuando el valor no está en la lista aprobada o llega vacío.","Revisa la lista y el texto de respaldo antes de configurarlos en tu plataforma publicitaria.","Actualiza la lista de términos aprobados cada vez que amplíes tu catálogo o zonas de servicio."],"reglas":["Nunca insertes una variable directamente sin comprobarla contra la lista aprobada: un valor inesperado puede generar un anuncio con errores o fuera de tono.","Define siempre un texto de respaldo genérico para cuando el valor no esté aprobado o llegue vacío.","Revisa periódicamente la lista de términos aprobados; un catálogo desactualizado genera anuncios que ya no corresponden a tu oferta real.","No uses esta técnica para personalizar con datos sensibles o inferencias sobre las personas; limítala a atributos de producto o ubicación general."],"prompt":"Actúa como redactor publicitario especializado en texto dinámico. Te voy a dar el tipo de variable que quiero insertar en mis anuncios, por ejemplo ciudad del visitante o categoría de producto visto, y la lista de valores reales que manejo. Con eso: 1) confirma o depura la lista de términos aprobados para esa variable, 2) redacta el texto del anuncio con el hueco para la variable, y 3) redacta un texto alternativo de respaldo para cuando el valor no esté en la lista o llegue vacío. No inventes valores fuera de la lista que te doy. Variable: [ciudad, producto o categoría]. Lista de valores reales: [pega tu lista]. Estructura del anuncio: [pega tu plantilla o ejemplo de texto]."}},
  {"id":"gr57","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Creatividad y personalización de anuncios","titulo":"Activa o pausa anuncios según el clima de cada zona","beneficio":"Pausa o activa tus campañas según las condiciones meteorológicas de la zona a la que apuntan, por ejemplo pausar anuncios de terrazas si llueve o activar anuncios de calefacción si baja la temperatura, para que tu presupuesto no se gaste en anuncios que no encajan con el momento.","alcance":"Diseña la lógica de reglas clima-campaña; la ejecución automática requiere conectar un servicio de datos meteorológicos con tu plataforma publicitaria, directamente o mediante una herramienta intermedia, y su impacto en resultados depende de qué tan relevante sea el clima para tu producto concreto.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a definir las reglas de negocio que conectan una condición meteorológica con una acción sobre una campaña (pausar, activar, ajustar presupuesto), y a documentar esa lógica para que se implemente con un servicio de datos de clima conectado a tu plataforma de anuncios.","modo":"Asistido: la IA ayuda a diseñar las reglas condición-acción; la conexión técnica entre el servicio meteorológico y la plataforma publicitaria la implementa un desarrollador o una herramienta de automatización.","pasos":["Identifica junto con la IA qué condiciones meteorológicas afectan de verdad la demanda de tu producto o servicio, y en qué rango.","Pide que redacte reglas claras del tipo condición-acción, por ejemplo: si hay lluvia prevista en la zona X, pausar la campaña Y.","Define con la IA qué pasa por defecto si el dato de clima no está disponible en el momento de decidir, para no dejar la campaña en un estado indefinido.","Entrega las reglas a quien vaya a implementar la conexión técnica entre el servicio de clima y tu plataforma de anuncios.","Revisa el comportamiento real de la automatización durante las primeras semanas antes de confiar en ella sin supervisión."],"reglas":["Define siempre un comportamiento por defecto para cuando falten datos de clima, en vez de dejar la campaña en un estado ambiguo.","No bases la regla en pronósticos a demasiados días vista; el clima previsto puede cambiar antes de que llegue el momento.","Revisa manualmente la automatización durante un tiempo antes de dejarla sin supervisión, especialmente en campañas con presupuestos altos.","Documenta las reglas activas para que cualquier persona del equipo entienda por qué una campaña se pausó o activó."],"prompt":"Actúa como estratega de campañas publicitarias. Mi negocio es [describe tu negocio] y quiero que ciertas campañas se pausen o activen según el clima de la zona a la que apuntan. Ayúdame a definir reglas claras del tipo 'si ocurre [condición meteorológica] en [zona], entonces pausar, activar o ajustar el presupuesto de la campaña [nombre]'. Incluye qué hacer por defecto si el dato de clima no está disponible en el momento de decidir. No asumas condiciones que no te haya confirmado. Dame la lógica en una tabla que luego pueda entregar a mi desarrollador o herramienta de automatización."}},
  {"id":"gr58","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Creatividad y personalización de anuncios","titulo":"Muestra el precio correcto según el país de cada visitante","beneficio":"Muestra el precio en la moneda y con los impuestos correspondientes a la ubicación detectada del visitante, para que quien vea tu anuncio o tu página no se lleve una sorpresa de precio al llegar al pago.","alcance":"Diseña la lógica de qué moneda e impuesto mostrar por región; no calcula por ti las tasas de impuestos vigentes de cada país, que cambian y debes confirmar con una fuente fiscal u oficial, ni sustituye la integración técnica con tu plataforma de comercio electrónico.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a definir la lógica de qué moneda y qué tipo de impuesto mostrar según el país o región detectada del visitante, y a redactar los textos de aviso, por ejemplo 'precio final, impuestos incluidos' o 'impuestos calculados en el pago', para cada caso.","modo":"Asistido: la IA ayuda a diseñar la lógica y los textos; los datos de tasas de impuesto vigentes debes confirmarlos con una fuente fiscal actualizada, y la implementación técnica corre por cuenta de tu plataforma de comercio electrónico.","pasos":["Comparte con la IA en qué países o regiones vendes y en qué moneda facturas hoy en cada uno.","Pide que proponga la lógica de qué moneda mostrar según el país detectado del visitante, incluyendo un valor por defecto para países no contemplados.","Confirma con una fuente fiscal o contable las tasas de impuesto vigentes por país; no le pidas a la IA que las invente o las dé por buenas sin verificar.","Pide textos claros para mostrar al visitante si el precio incluye o no impuestos, y en qué momento se calculan si depende del destino final.","Verifica con tu plataforma de comercio electrónico que la lógica de moneda e impuestos se puede implementar tal como se diseñó."],"reglas":["Nunca uses tasas de impuestos que te proponga la IA sin verificarlas contra una fuente fiscal oficial o tu contable; cambian por país y por producto.","Define siempre un valor por defecto de moneda e impuesto para visitantes de países no contemplados en tu lógica.","Sé explícito en la página sobre si el precio mostrado incluye impuestos o se calculan después, para evitar sorpresas en el pago.","Revisa la lógica con quien gestione el cumplimiento fiscal de tu negocio antes de publicarla, especialmente si vendes en varios países."],"prompt":"Actúa como consultor de experiencia de compra internacional. Vendo en los siguientes países: [lista de países] y facturo en [moneda o monedas]. Ayúdame a diseñar la lógica de qué moneda mostrar según el país detectado del visitante, incluyendo un valor por defecto para otros países, y redacta los textos que debería mostrar en la página de precio para dejar claro si el impuesto está incluido o se calcula en el pago. No me des tasas de impuesto concretas: solo la lógica y los textos; las tasas las voy a confirmar con mi contable."}},
  {"id":"gr59","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Optimización de conversión (CRO)","titulo":"Descubre en qué paso del formulario se te van los clientes","beneficio":"Detecta en qué campo de tu formulario la gente abandona con más frecuencia, fijándose solo en el comportamiento (en qué campo se detienen o salen), sin guardar lo que escribieron, para que sepas qué parte del formulario simplificar o corregir.","alcance":"Identifica patrones de abandono por campo a partir de los datos de comportamiento que ya recojas; no diagnostica la causa exacta del abandono, que puede ser el diseño, la pregunta, la confianza u otro motivo, ni garantiza que simplificar el campo mejore la conversión final.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a definir qué eventos de comportamiento registrar por campo de formulario, por ejemplo campo enfocado, campo abandonado sin completar, o error de validación mostrado, sin capturar el contenido que la persona escribió, y a interpretar los datos agregados de abandono por campo una vez los recojas.","modo":"Asistido: la IA ayuda a diseñar qué medir y a interpretar los resultados agregados; la implementación técnica del registro de eventos corre por cuenta de tu desarrollador o herramienta de analítica de formularios.","pasos":["Define con la IA la lista de campos de tu formulario y qué evento de comportamiento registrar en cada uno: foco, abandono, error de validación.","Confirma que el diseño solo registra comportamiento (qué campo, en qué orden, si hubo error) y nunca el contenido escrito por la persona.","Implementa el registro con tu desarrollador o herramienta de analítica de formularios.","Una vez tengas datos agregados de varias semanas, pide a la IA que identifique en qué campo se concentra el abandono.","Prioriza con tu equipo qué campo revisar primero (simplificar la pregunta, cambiar el tipo de campo, mover su posición) y vuelve a medir después del cambio."],"reglas":["Nunca registres ni guardes el contenido que la persona escribió en el formulario; solo el comportamiento (campo, orden, si hubo error, si abandonó).","Informa en tu política de privacidad que registras comportamiento de uso del formulario, si así lo exige tu marco legal aplicable.","No concluyas la causa del abandono solo con estos datos; úsalos para priorizar qué campo investigar, no como diagnóstico definitivo.","Espera a tener un volumen de datos razonable antes de sacar conclusiones sobre un campo puntual; un solo día de datos no es representativo."],"prompt":"Actúa como especialista en optimización de formularios. Mi formulario tiene los siguientes campos, en este orden: [lista de campos]. Ayúdame a definir qué evento de comportamiento registrar en cada campo, por ejemplo foco, abandono sin completar o error de validación mostrado, sin capturar en ningún caso el contenido escrito por la persona. Después, cuando te comparta los datos agregados de abandono por campo de varias semanas, ayúdame a identificar en qué campo se concentra el abandono y qué hipótesis razonables, no definitivas, podrían explicarlo."}},
  {"id":"gr60","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Optimización de conversión (CRO)","titulo":"Muestra tus ventanas emergentes solo a quien de verdad está leyendo","beneficio":"Retrasa la aparición de ventanas emergentes (ofertas, boletines, descuentos) hasta que el visitante demuestre que está leyendo con calma, por ejemplo tras avanzar un tramo razonable de la página o pasar un tiempo mínimo, en vez de lanzarlas apenas entra.","alcance":"Diseña la lógica de cuándo mostrar la ventana emergente según el comportamiento de lectura; no garantiza que reduzca el rechazo de la página ni que aumente las conversiones — depende del contenido de la oferta y de cómo la reciba tu audiencia.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a definir reglas de activación de ventanas emergentes basadas en el comportamiento de lectura, por ejemplo mostrar tras avanzar cierto tramo del contenido, tras un tiempo mínimo en la página, o cuando el visitante muestra intención de salir, en lugar de mostrarlas de inmediato al cargar.","modo":"Asistido: la IA propone las reglas de activación; la implementación técnica en tu web o herramienta de ventanas emergentes corre por cuenta de tu desarrollador o de la configuración de la herramienta que uses.","pasos":["Describe a la IA el objetivo de tu ventana emergente (captar email, mostrar un descuento, retener antes de salir) y en qué página aparece hoy.","Pide que proponga dos o tres reglas de activación basadas en comportamiento de lectura, en vez de un disparador inmediato al cargar la página.","Elige la regla que mejor encaje con el tipo de contenido de esa página: un artículo largo se comporta distinto a una página de producto corta.","Configura la regla elegida en tu herramienta de ventanas emergentes o con tu desarrollador.","Compara el comportamiento de los visitantes antes y después del cambio para decidir si mantienes la nueva regla o pruebas otra."],"reglas":["No muestres la ventana emergente antes de que el visitante haya tenido oportunidad real de leer algo de contenido; eso anula el propósito del retraso.","Evita combinar varios disparadores agresivos a la vez; elige uno o dos criterios claros para no saturar al visitante.","Asegura que la ventana emergente sea fácil de cerrar y no bloquee el contenido en dispositivos móviles.","No prometas una mejora concreta de conversión por este cambio; el efecto depende del contenido, la oferta y la audiencia."],"prompt":"Actúa como especialista en experiencia de usuario y CRO. Tengo una ventana emergente en mi página con el objetivo de [objetivo de la ventana emergente], que hoy aparece [cuándo aparece actualmente]. Ayúdame a diseñar dos o tres reglas alternativas de activación basadas en comportamiento de lectura, por ejemplo tras avanzar un tramo del contenido, tras un tiempo mínimo en la página, o al detectar intención de salida, explicando en qué tipo de página funciona mejor cada una y qué debo tener en cuenta para que no resulte intrusiva en móvil."}},
  {"id":"gr61","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Optimización de conversión (CRO)","titulo":"Compara dos versiones de tu página de forma fiable","beneficio":"Reparte el tráfico de tu página entre dos versiones de forma estable por visitante, gracias a una cookie que hace que la misma persona vea siempre la misma versión, para poder comparar con confianza cuál convierte mejor sin contaminar los resultados.","alcance":"Diseña la lógica de reparto y persistencia del experimento; la implementación técnica en el borde (edge) de tu infraestructura requiere a un desarrollador, y la validez del resultado depende de tener suficiente tráfico y tiempo antes de sacar conclusiones.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a diseñar la lógica de un test A/B ejecutado en el borde de tu infraestructura: cómo asignar cada visitante nuevo a una versión de forma aleatoria pero estable, usando una cookie para que siempre vea la misma, y qué métricas de conversión comparar al final entre ambas versiones.","modo":"Asistido: la IA diseña la lógica de reparto y medición; un desarrollador la implementa en la capa de borde (edge) de tu hosting o CDN.","pasos":["Define con la IA qué dos versiones de la página vas a comparar y qué métrica de conversión decide cuál gana.","Pide que diseñe la lógica de asignación: aleatoria en la primera visita, y guardada en una cookie para que el mismo visitante vea siempre la misma versión.","Confirma con la IA qué reparto de tráfico usar entre ambas versiones, por ejemplo un reparto equilibrado, y durante cuánto tiempo mantenerlo antes de evaluar.","Entrega la lógica a tu desarrollador para implementarla en la capa de borde de tu infraestructura o CDN.","Evalúa los resultados solo cuando tengas suficiente tráfico y tiempo acumulado, no en los primeros días del experimento."],"reglas":["Usa siempre una cookie u otro mecanismo persistente para que el mismo visitante no salte entre versiones en visitas distintas; esto invalida el experimento.","No cierres el experimento con pocos días de datos o poco tráfico; el resultado puede deberse al azar y no a una diferencia real.","Define de antemano la métrica que decide el ganador, para no elegir después la métrica que más convenga.","Documenta ambas versiones y la fecha de inicio y fin del experimento para poder auditarlo después."],"prompt":"Actúa como ingeniero de experimentación (A/B testing). Quiero comparar dos versiones de mi página, [describe brevemente las dos versiones], usando como métrica de éxito [métrica de conversión]. Diséñame la lógica para: 1) asignar a cada visitante nuevo una de las dos versiones de forma aleatoria, 2) guardar esa asignación en una cookie para que el mismo visitante vea siempre la misma versión en visitas futuras, y 3) qué reparto de tráfico usar entre las versiones y durante cuánto tiempo mantener el experimento antes de evaluar resultados. Explica la lógica en pasos que mi desarrollador pueda implementar en la capa de borde (edge) de nuestra infraestructura."}},
  {"id":"gr62","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Optimización de conversión (CRO)","titulo":"Detecta cuándo tu pasarela de pago empieza a fallarle a tus clientes","beneficio":"Vigila los tiempos de respuesta de tu pasarela de pago y te avisa cuando empiezan a volverse notablemente lentos, para que puedas reaccionar antes de que esa lentitud le cueste ventas a tu negocio.","alcance":"Ayuda a diseñar el sistema de vigilancia y aviso; no acelera tu pasarela de pago ni resuelve el problema de fondo, que depende de tu proveedor de pagos o tu infraestructura, y qué se considera lento varía según tu negocio y su histórico habitual.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a diseñar un sistema de monitoreo que registre los tiempos de respuesta de tu pasarela de pago en el checkout y dispare un aviso cuando la respuesta se aleje de forma notable de tu comportamiento habitual, en vez de esperar a que un cliente se queje.","modo":"Asistido: la IA ayuda a diseñar qué medir y cómo definir un umbral de aviso basado en tu propio histórico; la implementación técnica del monitoreo corre por cuenta de tu desarrollador o de una herramienta de observabilidad.","pasos":["Identifica junto con la IA en qué punto exacto del checkout se debe medir el tiempo de respuesta, por ejemplo desde que se envía el pago hasta que la pasarela confirma.","Registra el tiempo de respuesta habitual de tu pasarela durante un periodo normal, para tener una referencia propia de lo que es normal en tu negocio.","Pide a la IA que ayude a definir cuándo un tiempo de respuesta se considera notablemente lento en comparación con esa referencia propia, en vez de usar un número fijo genérico.","Configura, con tu desarrollador, un aviso automático (correo, mensaje al equipo) cuando se detecte esa lentitud sostenida.","Define un protocolo de qué hacer cuando llega el aviso: contactar al proveedor de pagos, revisar el estado del servicio, avisar a soporte."],"reglas":["Basa el umbral de aviso en el comportamiento histórico real de tu propio checkout, no en una cifra genérica tomada de otro negocio.","Evita avisos por picos aislados de un instante; busca patrones sostenidos de lentitud antes de generar una alerta.","Define quién recibe el aviso y qué debe hacer con él; un sistema de alertas sin protocolo de respuesta no sirve de nada.","No prometas que este sistema evita todas las pérdidas de venta por checkout lento: solo acorta el tiempo hasta que alguien se entera del problema."],"prompt":"Actúa como ingeniero de confiabilidad especializado en comercio electrónico. Mi pasarela de pago es [nombre de la pasarela] y el punto del checkout que quiero vigilar es [describe el paso, por ejemplo desde que el cliente confirma el pago hasta que la pasarela responde]. Ayúdame a diseñar un sistema de monitoreo que: 1) registre el tiempo de respuesta en ese punto, 2) establezca qué se considera una lentitud notable comparado con el comportamiento histórico de mi propio negocio, no un número genérico, y 3) dispare un aviso a mi equipo cuando eso ocurra de forma sostenida, no por un pico aislado. Indícame también qué protocolo básico debería seguir mi equipo al recibir ese aviso."}},
  {"id":"gr63","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Rentabilidad y control de gasto","titulo":"Descubre a qué clientes vale la pena dirigirte primero","beneficio":"Agrupa a tus clientes según cuánto valen y con qué frecuencia compran, para que puedas priorizar tus campañas y tu presupuesto hacia quienes más aportan a tu negocio, en vez de tratar a todos los clientes por igual.","alcance":"Es un modelo de segmentación basado en los datos históricos que le proporciones, como compras, fechas e importes; su utilidad depende de la calidad y cantidad de esos datos, y no predice con certeza el comportamiento futuro de un cliente concreto.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a segmentar tu base de clientes usando un modelo de recencia, frecuencia y valor monetario (RFM) a partir del historial de compras que le compartas, agrupándolos en categorías útiles, por ejemplo clientes de alto valor recientes, clientes valiosos que dejaron de comprar, o clientes ocasionales, para priorizar a quién dirigir tus campañas.","modo":"Asistido: tú aportas el historial de compras (fecha, cliente, importe); la IA calcula los segmentos y explica qué significa cada uno y cómo podrías priorizarlos.","pasos":["Exporta el historial de compras de tus clientes con, al menos, fecha de compra, identificador de cliente e importe.","Comparte esos datos con la IA y pide que calcule para cada cliente su recencia (hace cuánto compró), frecuencia (cuántas veces) y valor monetario (cuánto gastó en total).","Pide que agrupe a los clientes en segmentos claros, por ejemplo alto valor activo, alto valor en riesgo de irse, ocasional o nuevo, según esas tres dimensiones.","Pide una explicación de qué acción de marketing tendría sentido para cada segmento, no que la ejecute, sino que la sugiera.","Usa la segmentación para priorizar presupuesto y mensajes, revisándola de nuevo cada cierto tiempo porque los clientes cambian de segmento."],"reglas":["Los segmentos son una foto del pasado, no una garantía de comportamiento futuro; revísalos periódicamente en vez de fijarlos una sola vez.","Verifica que el historial de compras esté limpio, sin duplicados y con importes correctos, antes de segmentar; datos sucios producen segmentos poco útiles.","No compartas datos personales de clientes más allá de lo necesario para el cálculo; usa identificadores internos en vez de nombres o correos si es posible.","No prometas un aumento de ventas concreto por segmentar; la segmentación ayuda a priorizar, el resultado depende de qué hagas después con cada grupo."],"prompt":"Actúa como analista de valor de cliente. Te voy a compartir el historial de compras de mis clientes con fecha, identificador de cliente e importe. Calcula para cada cliente su recencia, frecuencia y valor monetario (modelo RFM), agrúpalos en segmentos claros y con nombres entendibles para el negocio, por ejemplo alto valor activo, alto valor en riesgo, ocasional o nuevo, y sugiere, sin prometer resultados, qué tipo de mensaje o prioridad de presupuesto tendría sentido para cada segmento. Aquí está el historial: [pega o adjunta los datos]."}},
  {"id":"gr64","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Rentabilidad y control de gasto","titulo":"Calcula si una campaña gana dinero de verdad, no solo factura","beneficio":"Resta los costes variables (envío, coste del producto, comisiones de pago) antes de calcular el retorno real de una campaña publicitaria, para que sepas si de verdad te deja margen y no solo ingreso bruto.","alcance":"Calcula un margen de contribución a partir de los costes y precios que tú le indiques; no incluye automáticamente costes fijos ni de estructura, y su precisión depende por completo de que le des cifras de coste reales y actualizadas.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a calcular el margen de contribución de una campaña publicitaria restando al ingreso generado los costes variables asociados a la venta, como coste del producto, envío, comisión de la pasarela de pago u otros que tú definas, y a comparar ese margen con la inversión publicitaria para estimar el retorno real, no solo el ingreso bruto.","modo":"Asistido: tú aportas ingresos, inversión publicitaria y costes variables; la IA hace el cálculo y explica el resultado en términos claros.","pasos":["Lista, junto con la IA, todos los costes variables reales que aplican a cada venta generada por la campaña: producto, envío, comisión de pago, empaque u otros.","Aporta el ingreso total generado por la campaña y la inversión publicitaria del mismo periodo.","Pide a la IA que calcule el margen de contribución, ingreso menos costes variables, y lo compare con la inversión publicitaria.","Pide que muestre el cálculo paso a paso, no solo el resultado final, para poder verificarlo y ajustarlo si falta algún coste.","Repite el cálculo periódicamente, porque los costes variables como envío y comisiones pueden cambiar con el tiempo."],"reglas":["Incluye todos los costes variables reales de la venta, no solo el coste del producto; omitir envío o comisiones infla artificialmente el margen aparente.","No mezcles costes fijos, como alquiler, sueldos o herramientas, en este cálculo; el margen de contribución es solo sobre costes variables asociados a la venta.","Verifica que las cifras de coste e ingreso correspondan al mismo periodo y a la misma campaña, para no comparar cosas distintas.","No presentes el resultado como el retorno total y definitivo del negocio; es el retorno real de esa campaña sobre costes variables, no la rentabilidad completa de la empresa."],"prompt":"Actúa como analista financiero de marketing. Te voy a dar los datos de una campaña publicitaria: ingreso total generado, inversión publicitaria, y los costes variables asociados a cada venta, como coste del producto, envío, comisión de pasarela de pago y cualquier otro coste variable real. Calcula el margen de contribución (ingreso menos costes variables) y compáralo con la inversión publicitaria para estimar el retorno real de la campaña, mostrando el cálculo paso a paso. No incluyas costes fijos de la empresa en este cálculo. Datos: [pega ingreso, inversión y costes variables]."}},
  {"id":"gr65","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Rentabilidad y control de gasto","titulo":"Entérate a tiempo si una campaña se está comiendo el presupuesto","beneficio":"Avisa cuando una campaña está gastando su presupuesto diario mucho más rápido de lo previsto, para que puedas frenarla o revisarla a tiempo en vez de descubrirlo al final del día.","alcance":"Diseña la lógica de comparación entre gasto real y ritmo esperado; requiere conectar los datos de gasto de tu plataforma publicitaria, directamente o mediante una herramienta, y qué se considera un ritmo acelerado depende del patrón normal de cada campaña, no de una cifra universal.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a diseñar una lógica de vigilancia que compare, a lo largo del día, cuánto debería haberse gastado una campaña a esa hora según su presupuesto diario frente a cuánto se ha gastado realmente, y que dispare un aviso cuando el ritmo se acelera claramente por encima de lo esperado.","modo":"Asistido: la IA diseña la lógica de comparación y aviso; la conexión con los datos de gasto en tiempo real de tu plataforma publicitaria requiere una integración técnica, ya sea con la API de la plataforma o una herramienta de gestión de campañas.","pasos":["Define con la IA, para cada campaña relevante, cuál es su presupuesto diario y qué ritmo de gasto sería razonable a distintas horas del día.","Pide que diseñe la lógica que compara el gasto real de la campaña a cada hora contra ese ritmo esperado.","Pide que defina cuándo esa diferencia se considera un ritmo notablemente acelerado, no una cifra fija, sino en relación al comportamiento habitual de la propia campaña.","Implementa, con tu desarrollador o herramienta de gestión de campañas, la conexión con los datos de gasto en tiempo real de tu plataforma publicitaria.","Define qué debe pasar cuando llega el aviso: quién lo revisa y si la campaña se pausa automáticamente o solo se notifica para revisión manual."],"reglas":["Compara siempre el gasto contra el ritmo esperado de esa misma campaña, no contra un porcentaje fijo genérico que no considera su historial.","Decide de antemano si el aviso solo notifica o si además pausa la campaña automáticamente; ambas opciones tienen riesgos distintos y deben ser una decisión consciente.","Ten en cuenta que picos de gasto legítimos, como una promoción puntual o un evento, pueden parecer una aceleración anómala; revisa el contexto antes de actuar solo por la alerta.","No dependas únicamente de este aviso para el control de presupuesto; revisa tus campañas con regularidad de todos modos."],"prompt":"Actúa como especialista en gestión de presupuestos publicitarios. Te voy a dar el presupuesto diario de una campaña y su patrón habitual de gasto por hora. Ayúdame a diseñar una lógica que compare el gasto real de la campaña a lo largo del día contra ese ritmo esperado, y que identifique cuándo el gasto se acelera de forma notable en comparación con el comportamiento habitual de esa misma campaña, no un umbral genérico. Indica también qué opciones tengo para reaccionar, solo notificar o pausar automáticamente, y qué riesgos tiene cada una. Datos: presupuesto diario [monto], patrón habitual de gasto por hora [descripción o datos]."}},
  {"id":"gr66","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Protección e infraestructura","titulo":"Protege tu presupuesto de clics que no son clientes reales","beneficio":"Detecta patrones de clics repetidos y sospechosos sobre un mismo anuncio, por ejemplo desde el mismo origen en muy poco tiempo, y ayuda a bloquearlos, para que tu presupuesto se gaste en visitantes reales y no en tráfico inválido.","alcance":"Identifica patrones sospechosos según reglas que definas, no un listado infalible de fraude; ninguna herramienta detecta la totalidad del clic fraudulento, y la implementación del bloqueo depende de las funciones antifraude de tu plataforma publicitaria o de una herramienta especializada conectada a ella.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a definir reglas para identificar patrones de clics sospechosos, como repetición desde el mismo origen en poco tiempo sin actividad posterior en la página, y a documentar cómo actuar sobre ellos usando las funciones de exclusión o reporte de fraude que ofrece tu plataforma publicitaria.","modo":"Asistido: la IA ayuda a definir las reglas de detección y el protocolo de respuesta; el bloqueo técnico se ejecuta con las herramientas antifraude propias de tu plataforma de anuncios o un servicio especializado conectado a ella.","pasos":["Revisa junto con la IA qué datos de clics puedes obtener de tu plataforma publicitaria: origen, frecuencia, comportamiento posterior en la página.","Pide que proponga reglas para identificar un patrón de clics repetido y sospechoso, por ejemplo muchos clics del mismo origen en poco tiempo sin ninguna otra interacción.","Define con la IA qué acción tomar cuando se detecta ese patrón: excluir el origen, reportarlo a la plataforma, o ambas cosas.","Configura las exclusiones o reportes usando las herramientas antifraude que ofrezca tu plataforma publicitaria.","Revisa periódicamente si las reglas siguen siendo útiles, porque los patrones de clic fraudulento cambian con el tiempo."],"reglas":["No presentes esto como detección infalible de fraude; es una identificación de patrones sospechosos que reduce el riesgo, no lo elimina.","Evita bloquear orígenes basándote en un solo clic aislado; busca un patrón repetido antes de tomar acción.","Usa los mecanismos oficiales de reporte de fraude de tu plataforma publicitaria en vez de depender solo de bloqueos manuales.","Documenta las reglas y revisa su efecto para no terminar bloqueando también tráfico legítimo por error."],"prompt":"Actúa como especialista en protección contra fraude publicitario. Te voy a describir qué datos de clics puedo obtener de mi plataforma de anuncios: origen, frecuencia, comportamiento posterior. Ayúdame a definir reglas claras para identificar un patrón de clics repetido y sospechoso sobre un mismo anuncio, y a documentar qué pasos seguir cuando se detecta ese patrón, ya sea excluir el origen, reportarlo a la plataforma, o ambos, usando las herramientas antifraude que ofrece mi plataforma. No me digas que esto elimina el fraude por completo; explica también sus límites. Datos disponibles: [describe qué datos de clics tienes]."}},
  {"id":"gr67","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Protección e infraestructura","titulo":"Evita que registros falsos ensucien tu CRM","beneficio":"Descarta automáticamente los registros que usan correos temporales o de dominios conocidos de usar y tirar antes de que entren a tu CRM, para que tu equipo de ventas no pierda tiempo con contactos que nunca van a responder.","alcance":"Filtra por patrones de dominio de correo conocidos como temporales; no detecta todo tipo de lead de mala calidad, ya que una persona con correo real también puede no tener interés real, y las listas de dominios temporales deben mantenerse actualizadas porque aparecen nuevos con frecuencia.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a construir y mantener una lista de dominios de correo conocidos como temporales o de usar y tirar, y a definir la lógica de validación que revisa el correo de cada nuevo registro contra esa lista antes de que se guarde en tu CRM.","modo":"Asistido: la IA ayuda a construir la lista y la lógica de validación; la implementación técnica en tu formulario o CRM corre por cuenta de tu desarrollador o de la configuración nativa de tu herramienta.","pasos":["Pide a la IA una lista inicial de dominios de correo conocidos como temporales o de usar y tirar, para usar como base de exclusión.","Define con la IA la lógica de validación: si el dominio del correo coincide con la lista, el registro se marca o se descarta según lo que decidas.","Decide si los registros descartados se eliminan directamente o se guardan aparte para revisión manual, en vez de perderlos sin dejar rastro.","Implementa la validación en tu formulario o CRM con tu desarrollador o mediante la configuración de tu herramienta.","Actualiza la lista de dominios periódicamente, porque aparecen dominios temporales nuevos con el tiempo."],"reglas":["No descartes leads solo por sospecha; basa el filtro en una lista concreta de dominios conocidos como temporales, no en suposiciones sobre el nombre del correo.","Guarda los registros descartados en un lugar revisable en vez de borrarlos sin rastro, por si el filtro comete un error.","Actualiza la lista de dominios con regularidad; un dominio temporal nuevo que no está en tu lista pasará el filtro sin problema.","Este filtro reduce ruido evidente, pero no valida el interés real del lead; sigue existiendo la posibilidad de correos reales sin intención de compra."],"prompt":"Actúa como especialista en calidad de datos de CRM. Ayúdame a: 1) elaborar una lista de dominios de correo conocidos como temporales o de usar y tirar, y 2) definir la lógica de validación para revisar el dominio del correo de cada nuevo registro de mi formulario contra esa lista, decidiendo si se descarta directamente o se guarda aparte para revisión manual. Indícame también con qué frecuencia debería actualizar la lista y qué limitaciones tiene este filtro, por ejemplo que no detecta leads de baja calidad con correos reales."}},
  {"id":"gr68","catalogo":"growth","grupo":"Publicidad y conversión","tema":"Protección e infraestructura","titulo":"Comprueba que tu web aguanta antes de lanzar una gran campaña","beneficio":"Simula picos de tráfico sobre tu embudo de conversión, desde la llegada hasta el pago, para comprobar si tu web resiste antes de lanzar una campaña grande, evitando que una caída o lentitud te arruine justo el día de más inversión.","alcance":"Ayuda a planificar y estructurar una prueba de carga; la ejecución técnica requiere una herramienta de pruebas de carga y la coordinación con tu proveedor de hosting, y el resultado depende de la infraestructura real de tu web en el momento de la prueba, no de la simulación en sí.","precio":1.99,"blueprint":{"quePuedeHacer":"La IA puede ayudarte a planificar una prueba de carga de tu embudo de conversión: qué pasos del recorrido simular, como la llegada a la página, la navegación o el checkout, qué volumen de tráfico simulado sería razonable según la campaña que vas a lanzar, y qué señales de fallo observar durante la prueba, como tiempos de respuesta, errores o caídas.","modo":"Asistido: la IA ayuda a planificar el escenario de la prueba y a interpretar los resultados; la ejecución técnica de la prueba de carga corre por cuenta de una herramienta especializada y, si aplica, con coordinación previa con tu proveedor de hosting.","pasos":["Describe a la IA el recorrido completo de tu embudo, páginas y pasos de checkout, y la magnitud de la campaña que vas a lanzar, para estimar un volumen de tráfico razonable a simular.","Pide que proponga un escenario de prueba de carga: qué pasos simular, con qué volumen aproximado y durante cuánto tiempo.","Coordina con tu proveedor de hosting o infraestructura antes de ejecutar la prueba, para evitar que se interprete como un ataque o afecte a otros clientes del mismo servidor.","Ejecuta la prueba con una herramienta especializada de pruebas de carga, fuera del horario de mayor tráfico real si es posible.","Pide a la IA que te ayude a interpretar los resultados, tiempos de respuesta, errores, punto donde empieza a fallar, y a priorizar qué corregir antes de lanzar la campaña real."],"reglas":["Coordina siempre con tu proveedor de hosting antes de simular tráfico alto; una prueba no avisada puede interpretarse como un ataque o afectar a otros servicios.","No ejecutes la prueba de carga contra tu entorno de producción en horario de tráfico real sin evaluar el riesgo; considera un entorno de pruebas si es posible.","El volumen de tráfico a simular debe basarse en una estimación razonable de la campaña real, no en una cifra arbitraria.","Los resultados reflejan el estado de tu infraestructura en el momento de la prueba; una prueba exitosa hoy no garantiza el mismo resultado si cambias de hosting o de código después."],"prompt":"Actúa como ingeniero de rendimiento web. Te voy a describir el recorrido de mi embudo de conversión, páginas y pasos de checkout, y la magnitud de la campaña publicitaria que voy a lanzar. Ayúdame a planificar un escenario de prueba de carga: qué pasos del embudo simular, qué volumen de tráfico simulado sería razonable dado el tamaño de la campaña, y qué señales debería observar durante la prueba, como tiempos de respuesta, errores o punto de caída. Recuérdame también que debo coordinar la prueba con mi proveedor de hosting antes de ejecutarla. Datos: recorrido del embudo [descríbelo], magnitud estimada de la campaña [describe alcance o inversión prevista]."}},
  {"id":"gr69","catalogo":"growth","grupo":"Redes sociales","tema":"Contenido y distribución","titulo":"Convierte un mismo contenido en publicaciones nativas para cada red","beneficio":"Ahorra el trabajo de reescribir desde cero cada vez que quieres publicar la misma idea en varias redes: a partir de un solo texto o guion de origen, obtienes una versión para LinkedIn con párrafos cortos y espaciados para lectura fácil, un hilo para X/Twitter dividido en bloques breves que se sostienen por sí solos, y un guion para vídeo corto con las indicaciones visuales necesarias para grabarlo, todo manteniendo la misma idea central y la voz de tu marca.","alcance":"Adapta el formato, la extensión y el tono a las convenciones de cada red, pero no garantiza alcance, interacción ni que el contenido rinda igual en todas las plataformas: cada red prioriza señales distintas en su algoritmo y esas reglas cambian sin aviso previo, así que cada versión debe revisarse antes de publicar y ajustarse según cómo responde tu audiencia real.","precio":1.99,"blueprint":{"quePuedeHacer":"Un asistente de IA puede tomar un contenido de origen (artículo, transcripción, apuntes de una idea) y generar tres adaptaciones distintas: una publicación de LinkedIn con gancho en la primera línea y párrafos de una a tres frases con espaciado generoso; un hilo de X/Twitter dividido en bloques cortos numerados donde cada bloque contiene una idea completa; y un guion de vídeo corto que combina lo que se dice con indicaciones visuales entre corchetes para cada corte de plano.","modo":"Generación asistida, con revisión humana antes de publicar","pasos":["Pegar el contenido de origen junto con una frase que resuma el objetivo de la publicación y el público al que se dirige.","Pedir la versión para LinkedIn: gancho en la primera línea, párrafos breves con espaciado entre ideas y un cierre que invite a comentar.","Pedir la versión para X/Twitter: el mismo mensaje dividido en bloques cortos numerados, cada uno legible de forma aislada.","Pedir el guion de vídeo corto: el texto que se dice y, entre corchetes, la indicación visual o el corte de plano para cada bloque.","Revisar las tres versiones buscando afirmaciones exageradas, cifras sin respaldo o promesas que la marca no pueda sostener, y corregirlas antes de programar la publicación."],"reglas":["El asistente no debe añadir datos, cifras o resultados que no estén presentes en el contenido de origen.","La adaptación cambia el formato y la extensión según la red, no el mensaje central: la idea de fondo debe ser la misma en las tres versiones.","Una persona del equipo aprueba cada versión antes de publicarla; el asistente no programa ni publica de forma automática."],"prompt":"Actúa como editor de contenido para redes sociales de una PyME. Te paso un texto de origen (artículo, transcripción o apuntes) y el objetivo de la publicación. A partir de ese contenido, genera tres versiones: 1) Una publicación para LinkedIn: gancho en la primera línea, párrafos de una a tres frases con espaciado entre ideas, tono profesional cercano, y un cierre que invite a comentar o compartir una experiencia. 2) Un hilo para X/Twitter: divide el mismo mensaje en bloques cortos numerados (máximo un par de frases por bloque), donde cada bloque tenga sentido por sí solo aunque alguien lo lea sin ver el resto del hilo. 3) Un guion para vídeo corto (Reels/TikTok/Shorts): escribe lo que se dice en cada bloque y, entre corchetes, una indicación visual o de corte de plano (por ejemplo [corte a primer plano], [texto en pantalla: dato clave]). No inventes cifras, resultados ni afirmaciones que no estén en el texto de origen. Mantén la misma idea central en las tres versiones y adapta solo el formato y el tono a las convenciones de cada red. Texto de origen: [pegar aquí]. Objetivo de la publicación: [pegar aquí]."}},
  {"id":"gr70","catalogo":"growth","grupo":"Redes sociales","tema":"Contenido y distribución","titulo":"Convierte un vídeo largo en clips verticales listos para redes","beneficio":"Encuentra los momentos con más potencial dentro de un vídeo largo (una entrevista, un webinar, una grabación de evento) y los prepara como clips cortos con un encuadre pensado para pantalla vertical, manteniendo a la persona que habla centrada en el cuadro, para que no tengas que revisar todo el material a mano y decidir plano a plano dónde cortar.","alcance":"Propone momentos candidatos y un encuadre orientado a mantener a la persona centrada, pero no garantiza que un clip concreto vaya a funcionar mejor que otro, ni que las redes lo muestren a más personas: el algoritmo de cada plataforma decide qué distribuir y cambia sin aviso previo, así que el resultado depende también del tema, el momento de publicación y la audiencia, no solo del recorte.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede analizar la transcripción y las marcas de tiempo de un vídeo largo para señalar los tramos con mayor densidad de ideas completas (una pregunta y su respuesta, una anécdota con inicio y cierre), proponer los puntos de entrada y salida de cada clip, y describir un encuadre centrado en la persona que habla para adaptarlo a formato vertical 9:16.","modo":"Selección asistida de momentos + edición humana final","pasos":["Aportar la transcripción con marcas de tiempo del vídeo largo, o generarla a partir del audio si no existe.","Pedir que se identifiquen los tramos con una idea completa y autocontenida (pregunta-respuesta, anécdota, dato con contexto) de duración corta.","Para cada tramo candidato, pedir el punto exacto de entrada y salida, y una frase que resuma por qué ese momento funciona de forma aislada.","Pedir una descripción del encuadre recomendado para formato vertical, priorizando mantener centrada a la persona que habla durante los cortes de plano.","Revisar cada clip candidato en vídeo antes de publicar, confirmando que el corte no saca la frase de contexto ni tergiversa lo dicho originalmente."],"reglas":["El corte no debe alterar el sentido de lo que dijo la persona ni sacar una frase de su contexto de forma engañosa.","El encuadre vertical debe revisarse a ojo antes de publicar: una recomendación de encuadre no sustituye la comprobación visual del resultado final.","No se garantiza alcance ni interacción por aplicar este proceso; es una ayuda para priorizar qué recortar, no una promesa de resultado."],"prompt":"Tengo la transcripción con marcas de tiempo de un vídeo largo (pegada abajo). Actúa como editor de vídeo para redes sociales y encuentra entre 5 y 8 tramos que funcionen como clips independientes de corta duración, cada uno con una idea completa (una pregunta y su respuesta, una anécdota con inicio y cierre, o un dato explicado con contexto). Para cada tramo candidato dame: el minuto y segundo de entrada, el minuto y segundo de salida, una frase que resuma de qué trata, y por qué crees que se sostiene solo sin el resto del vídeo. Después, para cada clip, describe brevemente cómo debería encuadrarse en formato vertical (9:16) para mantener a la persona que habla centrada en el cuadro durante los cambios de plano. No propongas cortes que saquen una frase de contexto o cambien lo que la persona quiso decir. Transcripción: [pegar aquí]."}},
  {"id":"gr71","catalogo":"growth","grupo":"Redes sociales","tema":"Contenido y distribución","titulo":"Revisa si tu vídeo capta la atención desde el inicio","beneficio":"Examina el arranque de un vídeo para comprobar si ocurre algo que dé al espectador un motivo para seguir viendo (un cambio de plano, un subtítulo o texto en pantalla, una pregunta directa) antes de que tenga ocasión de saltarse el contenido, y señala si el inicio se siente lento o repetitivo comparado con el resto del vídeo.","alcance":"Da una lectura cualitativa del ritmo de apertura del vídeo a partir de la transcripción y las marcas de tiempo disponibles; no mide la atención real de las personas que lo ven, no puede predecir si el vídeo retendrá audiencia, y el comportamiento de cada red frente a la retención cambia con el tiempo, así que esto es una revisión editorial, no una garantía de que el vídeo funcione mejor.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede revisar la transcripción y las marcas de tiempo de un vídeo para identificar cuándo aparece el primer cambio de plano, el primer subtítulo o texto en pantalla, y la primera frase que plantea una pregunta o una promesa de contenido, y comparar ese ritmo de apertura con el resto del vídeo para señalar si el inicio se siente más lento de lo necesario.","modo":"Revisión editorial asistida","pasos":["Aportar la transcripción con marcas de tiempo y, si existen, las marcas de los cortes de plano y de la aparición de subtítulos.","Pedir que se identifique el momento del primer cambio de plano, del primer subtítulo o texto en pantalla y de la primera frase con gancho.","Pedir una comparación cualitativa: si el arranque tarda notablemente más en tener uno de esos elementos que el resto del vídeo en llegar a sus propios cambios de ritmo.","Pedir sugerencias concretas para adelantar el gancho (recortar una introducción larga, mover una frase clave al principio, añadir un corte de plano temprano).","Volver a revisar el vídeo editado para confirmar que el cambio propuesto no rompe el sentido de la introducción."],"reglas":["No se debe presentar ningún umbral de segundos como un estándar verificado; el análisis usa términos cualitativos como 'pronto' o 'con retraso respecto al resto del vídeo', no cifras exactas.","La recomendación es editorial: la decisión final de recortar o reordenar la introducción la toma una persona, revisando el vídeo resultante.","No se garantiza que adelantar el gancho mejore la retención; el comportamiento de la audiencia y del algoritmo de cada red varía y no es predecible con certeza."],"prompt":"Actúa como editor de vídeo especializado en el arranque de contenido para redes sociales. Te paso la transcripción con marcas de tiempo de un vídeo (y, si las tengo, las marcas de cortes de plano y apariciones de subtítulos). Dime: 1) en qué momento ocurre el primer cambio de plano, el primer subtítulo o texto en pantalla, y la primera frase que plantea una pregunta o gancho claro; 2) si ese arranque se siente lento o repetitivo comparado con el ritmo del resto del vídeo, explicando por qué en términos cualitativos (no inventes cifras de segundos como si fueran un estándar); 3) dos o tres sugerencias concretas para adelantar el gancho, como recortar la introducción, adelantar una frase clave o añadir un corte de plano temprano. Transcripción: [pegar aquí]."}},
  {"id":"gr72","catalogo":"growth","grupo":"Redes sociales","tema":"Contenido y distribución","titulo":"Detecta sonidos y canciones en auge relevantes para tu marca","beneficio":"Ahorra el tiempo de revisar manualmente qué audios están ganando tracción dentro de tu nicho, para que puedas decidir con más rapidez si alguno encaja con el tono de tu marca y con el mensaje que quieres transmitir en un vídeo corto.","alcance":"Identifica sonidos o canciones que están en auge según la información pública disponible en el momento de la consulta; las tendencias de audio cambian muy rápido y de forma distinta en cada red, así que un audio detectado como 'en auge' puede perder tracción en poco tiempo, y usar un sonido en tendencia no garantiza mayor alcance ni interacción; además, antes de usar cualquier audio hay que verificar los derechos de uso comercial según la plataforma.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede rastrear listados públicos de sonidos y canciones en auge disponibles en cada red o en herramientas de terceros, filtrarlos por relevancia temática para el nicho de la marca (a partir de palabras clave del sector, del tono de la marca y de ejemplos de contenido previo), y presentar una lista corta con el motivo por el que cada uno podría encajar.","modo":"Monitoreo de tendencias, sin publicación automática","pasos":["Definir las palabras clave del nicho y el tono de marca que se quiere respetar (por ejemplo, evitar audios humorísticos si la marca es más formal).","Consultar los listados públicos de audios en tendencia disponibles para la red objetivo en el momento de la consulta.","Filtrar la lista descartando los audios que no encajan con el tono de marca o que pertenecen a un contexto ajeno al nicho, aunque estén en auge.","Para cada audio preseleccionado, verificar si su uso comercial está permitido en la plataforma antes de recomendarlo.","Entregar una lista corta con el nombre del audio, por qué podría encajar y la fecha de la consulta, dejando claro que la tendencia puede cambiar."],"reglas":["No presentar una tendencia detectada en un momento dado como una recomendación permanente: las tendencias de audio caducan rápido y hay que indicar la fecha de la consulta.","No recomendar un audio sin señalar que debe verificarse su licencia de uso comercial antes de publicarlo.","No prometer mayor alcance ni interacción por usar un audio en tendencia; el algoritmo de cada red decide la distribución y cambia sin aviso."],"prompt":"Ayúdame a identificar sonidos o canciones en tendencia relevantes para mi nicho. Mi negocio es: [descripción del negocio/nicho]. El tono de mi marca es: [formal / cercano / humorístico / técnico, etc.]. A partir de los listados públicos de audios en auge disponibles hoy para [red social], dame una lista corta de audios que puedan encajar con mi nicho y mi tono, explicando en una frase por qué cada uno podría funcionar. Señala también si el uso comercial de cada audio requiere verificación adicional en la plataforma, y aclara que se trata de una tendencia del momento de la consulta, no de una recomendación permanente."}},
  {"id":"gr73","catalogo":"growth","grupo":"Redes sociales","tema":"Contenido y distribución","titulo":"Elige pocos hashtags, muy específicos, en vez de saturar la publicación","beneficio":"Te ayuda a pasar de una lista larga de hashtags genéricos a un puñado de etiquetas realmente específicas de tu nicho, evitando el efecto de saturar la publicación con etiquetas que no aportan nada porque son demasiado amplias o demasiado usadas.","alcance":"Recomienda una densidad baja de hashtags específicos en lugar de una cifra fija de cuántos usar, porque no existe un número universal que funcione igual en todas las redes o nichos; el criterio de cada plataforma sobre hashtags cambia con el tiempo, así que esto es una guía de calidad sobre la etiqueta, no una fórmula garantizada de mayor alcance.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede revisar una lista de hashtags candidatos para una publicación, distinguir los que son demasiado genéricos (con volumen enorme y poca relación directa con el nicho) de los que son específicos del sector o del tema exacto de la publicación, y proponer un conjunto reducido priorizando especificidad sobre cantidad.","modo":"Recomendación editorial, no autopublicación","pasos":["Aportar el texto de la publicación y una lista inicial de hashtags candidatos, si ya existe una.","Pedir que se clasifiquen los hashtags entre genéricos (temas muy amplios, poco relacionados con el contenido concreto) y específicos (nicho, tema exacto, comunidad concreta).","Pedir que se descarten los hashtags genéricos que no aportan contexto real sobre el contenido de la publicación.","Pedir una selección final reducida, priorizando pocos hashtags muy específicos por encima de una lista larga de etiquetas amplias.","Revisar la selección final para confirmar que cada hashtag elegido realmente describe el contenido de la publicación."],"reglas":["No recomendar un número fijo de hashtags como si fuera un estándar universal; la cifra concreta depende del contenido y de la red, y debe describirse como 'pocos y específicos', no como un máximo exacto.","Priorizar siempre la relación real entre el hashtag y el contenido de la publicación por encima del volumen de uso del hashtag.","No prometer mayor alcance por aplicar esta selección; es una mejora de calidad de la etiqueta, no una garantía de resultado."],"prompt":"Actúa como estratega de contenido en redes sociales. Te paso el texto de una publicación y una lista de hashtags candidatos (si no tengo lista, sugiere tú candidatos a partir del texto). Clasifica los hashtags en dos grupos: genéricos (temas muy amplios, con poca relación directa con el contenido concreto) y específicos (relacionados con mi nicho exacto, mi comunidad o el tema puntual de la publicación). Después, dame una selección final reducida priorizando pocos hashtags muy específicos por encima de una lista larga de etiquetas genéricas, explicando en una frase por qué cada uno elegido describe realmente el contenido. No me des un número fijo como regla universal; adapta la cantidad al contenido concreto. Texto de la publicación: [pegar aquí]. Hashtags candidatos: [pegar aquí, opcional]."}},
  {"id":"gr74","catalogo":"growth","grupo":"Redes sociales","tema":"Escucha y reputación","titulo":"Agrupa las menciones de tu marca y filtra el ruido automatizado","beneficio":"Reúne en un solo lugar las menciones de tu marca dispersas en redes sociales, agrupándolas por volumen y por tema, y descarta las que vienen de cuentas que no muestran interacción humana real (perfiles sin publicaciones propias, sin seguidores reales o con patrones de repetición automatizada), para que dediques tu atención a las conversaciones que sí vienen de personas.","alcance":"Ayuda a priorizar qué menciones revisar primero, pero no sustituye una herramienta de escucha social con acceso a API completas de cada red, ni puede garantizar que capte el cien por cien de las menciones existentes; distinguir una cuenta automatizada de una cuenta real con poca actividad es una estimación basada en señales públicas, no una certeza, así que los casos dudosos requieren revisión humana.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede tomar un listado de menciones exportado de una herramienta de monitoreo o de una búsqueda manual, agruparlas por tema y por volumen, y señalar cuáles muestran señales típicas de cuentas automatizadas o sin actividad real (fecha de creación reciente, ausencia de publicaciones propias, patrones de texto repetitivo) para que se prioricen las menciones de personas reales.","modo":"Escucha social agregada, solo lectura","pasos":["Exportar o recopilar el listado de menciones de la marca de las redes que se quieran monitorear en un periodo determinado.","Pedir que se agrupen las menciones por tema (producto, servicio, atención al cliente, precio, etc.) y por volumen dentro de cada tema.","Pedir que se señalen las cuentas con señales de automatización o de baja actividad humana real, explicando qué señal concreta llevó a esa marca.","Priorizar para revisión humana las menciones agrupadas con mayor volumen y las que vienen de cuentas con señales claras de actividad real.","Guardar un registro breve de los temas recurrentes detectados en cada periodo para comparar la evolución con el tiempo."],"reglas":["Marcar una cuenta como probable automatización es una estimación basada en señales públicas, no una acusación definitiva; debe presentarse como tal.","No descartar por completo una mención solo por señales ambiguas: en caso de duda, se marca para revisión humana en vez de eliminarla del listado.","No se garantiza cobertura completa de todas las menciones existentes en cada red; el alcance depende de las fuentes de datos disponibles."],"prompt":"Te paso un listado de menciones de mi marca recopiladas de redes sociales (usuario, texto, red, fecha, y si están disponibles: fecha de creación de la cuenta, número de publicaciones propias, número de seguidores). Agrupa las menciones por tema principal (producto, servicio, atención al cliente, precio, otro) y por volumen dentro de cada tema. Después, señala qué cuentas muestran señales de automatización o de baja actividad humana real (cuenta muy reciente, sin publicaciones propias, texto repetitivo idéntico en varias menciones), explicando la señal concreta en cada caso, sin presentarlo como una certeza absoluta. Prioriza para mi revisión las menciones de mayor volumen que vengan de cuentas con señales de actividad humana real. Listado de menciones: [pegar aquí]."}},
  {"id":"gr75","catalogo":"growth","grupo":"Redes sociales","tema":"Escucha y reputación","titulo":"Separa comentarios positivos, neutros y quejas que necesitan respuesta","beneficio":"Clasifica un volumen grande de comentarios en positivos, neutros y negativos, y dentro de los negativos, señala los que describen un problema concreto de soporte o de producto, para que el equipo de atención pueda responder primero a quien tiene un problema real en vez de perderlo entre el resto de comentarios.","alcance":"La clasificación de sentimiento es una aproximación basada en el lenguaje del comentario: el sarcasmo, las bromas internas de una comunidad o el contexto cultural pueden confundir la clasificación automática, así que los comentarios marcados como negativos o como quejas de soporte deben revisarse por una persona antes de decidir cómo responder, especialmente en casos sensibles.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede leer un lote de comentarios de una publicación o de varias, clasificarlos como positivos, neutros o negativos según el lenguaje usado, y dentro de los negativos, distinguir los que describen un problema concreto (algo no funciona, un pedido no llegó, una queja de atención al cliente) de los que son simplemente una opinión negativa general.","modo":"Clasificación asistida con revisión humana","pasos":["Exportar o recopilar el lote de comentarios que se quiere clasificar, con el texto completo de cada uno.","Pedir la clasificación en tres categorías: positivo, neutro y negativo, con una palabra o frase del comentario que justifique la clasificación.","Dentro de los comentarios negativos, pedir que se separen los que describen un problema concreto de soporte o producto de los que son solo una opinión negativa sin un problema puntual.","Priorizar para respuesta inmediata los comentarios marcados como quejas de soporte concretas, antes que el resto.","Revisar una muestra de los comentarios clasificados como neutros o positivos para confirmar que no se está pasando por alto sarcasmo o ironía mal clasificada."],"reglas":["La clasificación de sentimiento es una estimación de lenguaje, no una medición exacta; debe presentarse como tal y no como un veredicto definitivo.","Los comentarios marcados como quejas de soporte concretas deben ser revisados y respondidos por una persona del equipo, no de forma automática.","En caso de duda entre sarcasmo y una opinión genuina, marcar el comentario para revisión humana en vez de clasificarlo de forma forzada."],"prompt":"Te paso un lote de comentarios de redes sociales (texto de cada comentario, uno por línea). Clasifica cada uno como positivo, neutro o negativo, indicando brevemente qué parte del texto justifica la clasificación. Dentro de los comentarios negativos, separa los que describen un problema concreto de soporte o de producto (algo no funciona, un pedido no llegó, una queja de atención al cliente) de los que son solo una opinión negativa general sin un problema puntual que resolver. Al final, dame una lista priorizada de los comentarios que describen un problema concreto, para que el equipo de atención los responda primero. Si un comentario te parece ambiguo (posible sarcasmo o ironía), márcalo como 'revisar manualmente' en vez de forzar una clasificación. Comentarios: [pegar aquí]."}},
  {"id":"gr76","catalogo":"growth","grupo":"Redes sociales","tema":"Escucha y reputación","titulo":"Detecta señales de audiencia sospechosa antes de pagar a un influencer","beneficio":"Revisa la actividad pública de la cuenta de un influencer con el que estás considerando trabajar y señala si tiene una proporción de comentarios o seguidores que resulta inusualmente alta viniendo de perfiles sin foto, sin publicaciones propias o sin actividad real, para que tengas una alerta antes de comprometer presupuesto en una colaboración pagada.","alcance":"Aporta señales de alerta basadas en patrones públicos visibles, no una prueba definitiva de fraude: una proporción alta de perfiles con poca actividad puede tener explicaciones legítimas, y algunas cuentas fraudulentas usan perfiles que parecen reales. Esta revisión complementa, pero no sustituye, otras formas de verificación (pedir métricas propias del influencer, revisar campañas anteriores, contrastar con otras herramientas).","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede revisar una muestra de comentarios y, cuando estén disponibles, de perfiles de seguidores de una cuenta de influencer, identificar la proporción de perfiles sin foto, sin publicaciones propias o con patrones de actividad mínima, y compararla con lo que suele observarse en cuentas similares del mismo nicho para señalar si el resultado se sale de lo esperado.","modo":"Análisis de señales públicas, sin acusación automática","pasos":["Recopilar una muestra representativa de comentarios recientes de la cuenta del influencer, o de perfiles de seguidores si la herramienta lo permite.","Pedir que se identifique la proporción de perfiles en esa muestra sin foto de perfil, sin publicaciones propias visibles o con actividad mínima.","Pedir una comparación cualitativa con lo esperable en cuentas similares del mismo nicho y tamaño, señalando si la proporción observada se siente inusualmente alta.","Pedir que se listen ejemplos concretos de los perfiles con señales de baja actividad, para poder revisarlos manualmente antes de sacar una conclusión.","Combinar este análisis con al menos otra fuente de verificación (métricas propias del influencer, referencias de campañas anteriores) antes de decidir sobre la colaboración."],"reglas":["El resultado debe presentarse como una señal de alerta a revisar, nunca como una acusación de fraude confirmada.","No usar un porcentaje fijo como umbral universal de fraude; describir el hallazgo en términos cualitativos como 'proporción inusualmente alta comparada con cuentas similares'.","Recomendar siempre una verificación adicional antes de tomar una decisión de negocio basada solo en esta señal."],"prompt":"Estoy evaluando si colaborar de forma pagada con una cuenta de influencer y quiero una señal de alerta temprana sobre la calidad de su audiencia. Te paso una muestra de comentarios recientes de su cuenta (y de perfiles de seguidores, si están disponibles). Identifica qué proporción de esa muestra corresponde a perfiles sin foto de perfil, sin publicaciones propias visibles o con patrones de actividad mínima. Compara esa proporción, en términos cualitativos, con lo que suele verse en cuentas de tamaño y nicho similares, y dime si te parece inusualmente alta. Dame ejemplos concretos de los perfiles con señales de baja actividad para poder revisarlos yo mismo. Aclara que esto es una señal de alerta a contrastar con otras fuentes, no una prueba de fraude. Muestra de comentarios/seguidores: [pegar aquí]."}},
  {"id":"gr77","catalogo":"growth","grupo":"Redes sociales","tema":"Escucha y reputación","titulo":"Filtra enlaces sospechosos publicados por terceros en tu comunidad","beneficio":"Revisa los enlaces que terceros publican en los comentarios de tus redes o en tu comunidad (grupo, canal, servidor) y señala los que muestran patrones típicos de enlaces maliciosos o de suplantación, para que puedas eliminarlos antes de que un miembro de tu comunidad haga clic pensando que vienen de una fuente confiable.","alcance":"Detecta patrones conocidos de enlaces sospechosos (acortadores encadenados, dominios que imitan marcas conocidas, publicaciones repetidas de forma automatizada), pero no puede garantizar que capte todos los intentos de phishing o estafa, especialmente los más recientes o sofisticados; debe combinarse con las herramientas de moderación nativas de cada plataforma y con la revisión de un moderador humano en los casos dudosos.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede revisar un listado de enlaces publicados por terceros en comentarios o en canales de comunidad, señalar los que usan patrones típicos de riesgo (dominios que imitan marcas conocidas con pequeñas variaciones, acortadores de URL encadenados, publicación repetida del mismo enlace por varias cuentas en poco tiempo) y priorizarlos para eliminación y revisión.","modo":"Moderación asistida con aprobación humana","pasos":["Recopilar el listado de enlaces publicados por terceros en un periodo determinado, junto con la cuenta que los publicó y el canal o publicación donde aparecieron.","Pedir que se señalen los enlaces con patrones de riesgo conocidos (dominio que imita una marca, acortador encadenado, mismo enlace publicado por varias cuentas nuevas en poco tiempo).","Pedir que se prioricen para eliminación inmediata los enlaces con más de un patrón de riesgo presente.","Revisar manualmente los casos marcados antes de eliminarlos o de bloquear a la cuenta que los publicó, para evitar eliminar enlaces legítimos por error.","Llevar un registro de los patrones detectados con más frecuencia para ajustar las reglas de moderación del canal con el tiempo."],"reglas":["Ningún enlace se elimina de forma automática sin que una persona confirme el patrón de riesgo señalado; el asistente prioriza y explica, la decisión final es humana.","No se garantiza la detección de todos los enlaces maliciosos existentes; esto es una capa adicional de revisión, no un reemplazo de la moderación nativa de la plataforma.","Distinguir explícitamente entre 'patrón de riesgo detectado' y 'enlace confirmado como malicioso' para no exponer a la marca a acusaciones infundadas contra un usuario."],"prompt":"Te paso un listado de enlaces publicados por terceros en los comentarios o en el canal de mi comunidad (enlace, cuenta que lo publicó, fecha, canal o publicación donde apareció). Señala cuáles muestran patrones de riesgo conocidos: dominios que imitan marcas conocidas con pequeñas variaciones, uso de acortadores de URL encadenados, o el mismo enlace publicado por varias cuentas distintas en un periodo corto de tiempo. Prioriza para revisión inmediata los que combinan más de un patrón de riesgo. Para cada enlace señalado, explica qué patrón concreto detectaste, sin afirmar de forma definitiva que se trata de un enlace malicioso confirmado. Listado de enlaces: [pegar aquí]."}},
  {"id":"gr78","catalogo":"growth","grupo":"Redes sociales","tema":"Analítica social","titulo":"Encuentra las franjas horarias en que tu audiencia responde mejor","beneficio":"Analiza el historial de tus propias publicaciones orgánicas para identificar en qué días y franjas horarias suelen tener mejor respuesta (más interacción o alcance relativo a lo habitual), para que puedas priorizar esos momentos al programar contenido nuevo en lugar de publicar por costumbre.","alcance":"La recomendación se basa en el comportamiento histórico de tu propia cuenta, no en una regla universal válida para cualquier marca o red; el comportamiento de tu audiencia y el criterio del algoritmo de cada plataforma cambian con el tiempo, así que estas franjas conviene revisarlas cada cierto tiempo en vez de fijarlas como definitivas, y publicar en el horario sugerido no garantiza mejor resultado en cada publicación concreta.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede tomar el histórico de publicaciones exportado de una red (fecha, hora, métricas de interacción y alcance) y calcular, para cada franja horaria y día de la semana, cómo se compara el rendimiento promedio de las publicaciones hechas en ese momento frente al rendimiento promedio general de la cuenta, señalando las franjas que destacan por encima del resto.","modo":"Análisis de datos históricos propios","pasos":["Exportar el histórico de publicaciones orgánicas de la cuenta con fecha, hora de publicación y métricas de interacción y alcance disponibles.","Pedir que se agrupen las publicaciones por día de la semana y franja horaria de publicación.","Pedir el rendimiento promedio de cada grupo comparado con el promedio general de la cuenta en el mismo periodo.","Pedir que se señalen las franjas que destacan de forma consistente por encima del promedio, evitando sacar conclusiones de grupos con muy pocas publicaciones.","Repetir este análisis cada cierto tiempo (por ejemplo, trimestralmente) para confirmar si las franjas recomendadas siguen siendo válidas."],"reglas":["No tratar una franja con pocas publicaciones históricas como una conclusión sólida; señalar cuándo la muestra es demasiado pequeña para ser confiable.","Presentar el resultado como una tendencia observada en el historial propio, nunca como una regla válida para todas las marcas o cuentas.","No prometer que publicar en la franja recomendada mejorará el resultado de una publicación concreta; es una guía de priorización, no una garantía."],"prompt":"Te paso el histórico de mis publicaciones orgánicas en [red social] con fecha, hora de publicación y métricas de interacción/alcance de cada una. Agrupa las publicaciones por día de la semana y franja horaria de publicación, y calcula el rendimiento promedio de cada grupo comparado con el promedio general de mi cuenta en el mismo periodo. Señálame las franjas que destacan de forma consistente por encima del promedio, indicando cuántas publicaciones respaldan cada conclusión (y avísame si algún grupo tiene muy pocas publicaciones para ser confiable). Aclara que esto refleja el comportamiento histórico de mi cuenta, no una regla universal, y que conviene repetir el análisis dentro de unos meses. Histórico de publicaciones: [pegar aquí]."}},
  {"id":"gr79","catalogo":"growth","grupo":"Redes sociales","tema":"Analítica social","titulo":"Mide cuánto se comparte tu contenido, no solo los 'me gusta'","beneficio":"Calcula qué proporción de las personas que ven tu contenido lo comparten o repostean, y prioriza esa señal por encima de los 'me gusta' o los clics rápidos, porque compartir suele implicar un compromiso mayor con el mensaje que una reacción rápida, ayudándote a identificar qué contenido realmente resuena con tu audiencia.","alcance":"El dato de veces compartido no está disponible de la misma forma en todas las redes (algunas lo exponen en sus métricas nativas o de API, otras no), así que la comparación entre plataformas debe hacerse con cautela; además, la tasa de amplificación es una señal más entre varias, no una medida única y definitiva del éxito de una publicación.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede tomar las métricas exportadas de una o varias publicaciones (alcance o impresiones, veces compartido/repost, 'me gusta', clics) y calcular la proporción de veces compartido sobre alcance para cada publicación, ordenando el listado por esa tasa en vez de por el volumen bruto de 'me gusta', para identificar qué contenido generó más disposición a redifundirlo.","modo":"Cálculo agregado sobre métricas exportadas","pasos":["Exportar las métricas disponibles de un conjunto de publicaciones: alcance o impresiones, veces compartido o repost, 'me gusta' y clics, cuando estén disponibles.","Pedir el cálculo de la tasa de amplificación (veces compartido dividido por alcance) para cada publicación con datos suficientes.","Pedir que el listado se ordene por esa tasa, señalando también el volumen absoluto para dar contexto (una tasa alta con muy poco alcance pesa distinto que una tasa alta con alcance grande).","Comparar el contenido con mejor tasa de amplificación entre sí para identificar patrones de tema o formato que se repiten.","Marcar como no comparable cualquier publicación de una red que no exponga el dato de veces compartido, en vez de estimarlo."],"reglas":["No estimar ni inventar el número de veces compartido cuando la red no lo expone en sus métricas; señalar la publicación como 'sin dato disponible' en ese caso.","No comparar tasas de amplificación entre redes distintas como si fueran directamente equivalentes, dado que cada plataforma mide y expone el dato de forma diferente.","Presentar la tasa de amplificación como una señal más de resonancia del contenido, no como el único criterio de éxito de una publicación."],"prompt":"Te paso las métricas de un conjunto de publicaciones en [red social]: alcance o impresiones, veces compartido/repost, 'me gusta' y clics (cuando estén disponibles). Calcula la tasa de amplificación de cada publicación (veces compartido dividido por alcance) y ordena el listado de mayor a menor tasa, mostrando también el alcance absoluto de cada una para dar contexto. Si alguna publicación no tiene el dato de veces compartido disponible, márcala como 'sin dato' en vez de estimarlo. Al final, identifica qué tienen en común, en tema o formato, las publicaciones con mejor tasa de amplificación. Métricas: [pegar aquí]."}},
  {"id":"gr80","catalogo":"growth","grupo":"Redes sociales","tema":"Analítica social","titulo":"Unifica el rendimiento de tus redes en un solo informe por campaña","beneficio":"Reúne las métricas de tus distintas redes sociales (las que uses: Instagram, LinkedIn, X, TikTok, YouTube, etc.) en un solo informe, cruzando los datos por campaña o periodo, para que no tengas que revisar el panel nativo de cada plataforma por separado cada vez que quieras saber cómo fue una campaña de principio a fin.","alcance":"Depende de que puedas exportar o dar acceso a los datos de cada red, cuyos formatos y nombres de métrica no son iguales entre plataformas, así que homologar categorías (qué cuenta como 'interacción' en cada red, por ejemplo) requiere criterio y puede introducir aproximaciones; el informe describe lo que ya ocurrió, no predice el rendimiento de campañas futuras.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede tomar exportaciones de métricas de varias redes para el mismo periodo o campaña, homologar las categorías equivalentes entre plataformas (alcance, interacción, clics, veces compartido) documentando explícitamente cómo define cada red esos términos, y consolidar todo en un único informe estructurado por campaña.","modo":"Consolidación de reportes, solo lectura","pasos":["Exportar las métricas de cada red para el periodo o campaña que se quiere analizar, en el formato nativo de cada plataforma.","Definir, para cada categoría del informe final (alcance, interacción, clics, veces compartido), qué métrica nativa de cada red corresponde a esa categoría.","Consolidar los datos en una sola tabla o informe organizado por campaña, dejando explícita la fuente y la definición usada para cada dato.","Señalar cualquier métrica que no tenga un equivalente claro en alguna red, en vez de forzar una homologación poco fiel.","Presentar el informe con una sección de notas metodológicas que explique las homologaciones hechas, para que cualquiera que lo lea entienda las limitaciones de la comparación."],"reglas":["Nunca presentar una homologación de métricas entre redes distintas sin documentar explícitamente cómo se hizo esa equivalencia.","Si una métrica no tiene equivalente claro en alguna plataforma, señalarlo como dato faltante en vez de rellenarlo con una estimación.","El informe describe resultados pasados; no debe presentarse como una predicción de cómo rendirá una campaña futura."],"prompt":"Te paso las métricas exportadas de mis redes sociales ([lista de redes]) para la campaña o el periodo [nombre/fechas]. Cada exportación tiene sus propias columnas y nombres de métrica. Ayúdame a consolidar todo en un solo informe organizado por campaña, con estas categorías comunes: alcance, interacción, clics y veces compartido (cuando el dato exista). Para cada categoría, dime explícitamente qué métrica nativa de cada red usaste como equivalente, y si alguna red no tiene un dato equivalente para alguna categoría, indícalo como 'sin dato' en vez de estimarlo. Añade al final una nota metodológica breve explicando las homologaciones que hiciste. Datos: [pegar exportaciones aquí]."}},
  {"id":"gr81","catalogo":"growth","grupo":"Redes sociales","tema":"Conversación y comunidad","titulo":"Automatiza secuencias de mensajes directos con freno automático si alguien pide parar","beneficio":"Automatiza el envío de una secuencia de mensajes privados (por ejemplo, una bienvenida y uno o dos mensajes de seguimiento) a personas que ya iniciaron contacto con tu marca, deteniendo la secuencia de inmediato en cuanto la persona escribe una palabra de alto como 'stop', 'salir' o 'no me escribas más', para que la automatización no siga insistiendo después de que alguien pidió parar.","alcance":"Cada red social tiene sus propias reglas sobre mensajería automatizada (algunas la restringen o la prohíben en ciertos contextos), así que este blueprint debe adaptarse a los términos de uso vigentes de la plataforma donde se implemente; no sustituye una conversación humana genuina cuando el mensaje lo requiere, y necesita supervisión periódica de una persona para confirmar que el freno por palabra de alto funciona correctamente.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede definir la secuencia de mensajes (contenido y espaciado entre envíos), la lista de palabras de alto que detienen la secuencia de inmediato en cualquier idioma relevante para la audiencia, y la lógica que revisa cada respuesta entrante antes de continuar con el siguiente mensaje programado.","modo":"Automatización de mensajería con freno humano y por palabra clave","pasos":["Definir el objetivo de la secuencia de mensajes directos y el contenido de cada paso, dejando claro desde el primer mensaje que se trata de una comunicación automatizada si la plataforma o la normativa aplicable lo exige.","Definir la lista de palabras y frases de alto que deben detener la secuencia de inmediato ('stop', 'salir', 'no me escribas más', y variantes relevantes para la audiencia).","Configurar que, ante cualquier respuesta entrante, la secuencia se detenga y espere revisión humana si el mensaje contiene una palabra de alto o si no es una respuesta esperada por la lógica programada.","Probar la secuencia completa con casos de prueba internos, incluyendo enviar una palabra de alto en distintos puntos de la secuencia, antes de activarla con contactos reales.","Revisar periódicamente una muestra de conversaciones reales para confirmar que el freno por palabra de alto se está aplicando correctamente."],"reglas":["Detener la secuencia de inmediato ante cualquier palabra de alto es una regla dura, no opcional, sin excepciones por el paso de la secuencia en que se encuentre la persona.","No enviar mensajes automatizados a personas que no iniciaron contacto ni dieron ningún tipo de consentimiento previo; esto no es una herramienta de mensajería fría no solicitada.","Cumplir los términos de uso de la plataforma sobre mensajería automatizada y la normativa de comunicaciones comerciales aplicable en la región de la audiencia.","Revisar periódicamente conversaciones reales para confirmar que el sistema respeta el freno; un fallo detectado debe corregirse antes de seguir usando la secuencia."],"prompt":"Ayúdame a diseñar una secuencia de mensajes directos automatizada para personas que ya iniciaron contacto con mi marca en [red social]. El objetivo de la secuencia es: [objetivo, por ejemplo: dar la bienvenida y ofrecer ayuda para elegir un producto]. Dame: 1) el contenido de cada mensaje de la secuencia (máximo 3 pasos), con el espaciado recomendado entre cada envío; 2) una lista de palabras y frases de alto en español (y otros idiomas relevantes para mi audiencia si aplica) que deben detener la secuencia de inmediato, sin excepciones; 3) la lógica de qué hacer si la respuesta de la persona no es ni una palabra de alto ni la respuesta esperada (por ejemplo, marcar para atención humana en vez de continuar la secuencia programada). Aclara en el primer mensaje que se trata de una comunicación automatizada si la normativa o la plataforma lo requiere, y no incluyas nada dirigido a personas que no hayan iniciado contacto ni dado su consentimiento."}},
  {"id":"gr82","catalogo":"growth","grupo":"Redes sociales","tema":"Conversación y comunidad","titulo":"Descubre qué preguntas hace tu público en foros del sector","beneficio":"Recopila las preguntas que la gente hace en foros y comunidades públicas relevantes para tu sector, para que puedas detectar dudas frecuentes, ideas de contenido o necesidades de producto que todavía no estás cubriendo, sin tener que leer manualmente cada hilo uno por uno.","alcance":"Refleja únicamente lo que se discute públicamente en los foros revisados, no la totalidad del mercado ni de tu público objetivo; distintos foros atraen a distintos tipos de usuario, así que las preguntas recopiladas son una muestra parcial y conviene contrastarlas con otras fuentes antes de tomar decisiones de producto o de contenido basadas solo en ellas.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede revisar foros y comunidades públicas del sector, extraer las preguntas planteadas por los usuarios y agruparlas por tema recurrente, sin guardar ni asociar la pregunta a ningún dato que identifique a la persona que la hizo más allá de lo estrictamente necesario para entender la pregunta en su contexto.","modo":"Recolección agregada de datos públicos, sin PII","pasos":["Definir los foros o comunidades públicas relevantes para el sector y confirmar que sus normas de uso permiten este tipo de consulta y recopilación.","Recopilar las preguntas planteadas por usuarios en un periodo determinado, guardando el texto de la pregunta y el hilo o categoría donde aparece, sin nombre de usuario ni ningún dato personal asociado.","Agrupar las preguntas por tema recurrente, señalando cuántas veces aparece una duda similar dentro del periodo analizado.","Priorizar para revisión los temas que se repiten con más frecuencia como posibles ideas de contenido o señales de necesidad de producto.","Descartar y no almacenar cualquier dato que pudiera identificar a la persona que hizo la pregunta más allá del texto de la pregunta misma."],"reglas":["No guardar ni asociar nombres de usuario, enlaces a perfiles ni ningún otro dato personal de quien hace la pregunta; solo interesa el contenido de la pregunta y el tema, agregados.","Respetar las normas de uso y de scraping del foro consultado; no recopilar de comunidades que lo prohíban explícitamente.","Usar la información únicamente para entender temas e ideas, no para contactar directamente a quien hizo la pregunta ni para ningún otro fin distinto al de investigación de contenido o producto."],"prompt":"Ayúdame a identificar qué preguntas frecuentes hace la gente sobre [tema/sector] en foros y comunidades públicas como [nombrar foros, por ejemplo Reddit, foros especializados del sector]. Recopila las preguntas planteadas en un periodo reciente, agrúpalas por tema recurrente y dime cuántas veces aparece cada tema. No incluyas nombres de usuario, enlaces a perfiles ni ningún otro dato que identifique a quien hizo la pregunta: solo necesito el texto de la pregunta y el tema al que pertenece, de forma agregada. Al final, señala los tres o cuatro temas más repetidos que podrían convertirse en contenido nuevo o revelar una necesidad de producto no cubierta."}},
  {"id":"gr83","catalogo":"growth","grupo":"Redes sociales","tema":"Conversación y comunidad","titulo":"Detecta los temas que más se repiten en tu comunidad privada de marca","beneficio":"Analiza las conversaciones dentro de un canal privado que administra tu propia marca (un grupo o servidor de clientes, por ejemplo) para identificar los temas de conversación que más se repiten, ayudándote a entender qué le preocupa o le interesa a tu comunidad sin tener que leer cada conversación manualmente.","alcance":"Solo aplica a canales privados que administras y sobre los que tienes acceso legítimo, nunca a comunidades ajenas; el resultado es un patrón agregado de temas, no una vigilancia de personas concretas, y debe usarse respetando las normas de privacidad que la propia comunidad espera y la normativa de protección de datos aplicable.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede revisar el historial de conversaciones de un canal privado propio, agrupar los mensajes por tema recurrente y presentar un resumen agregado de qué temas aparecen con más frecuencia, sin citar ni atribuir fragmentos de conversación a una persona concreta en el resultado final.","modo":"Análisis agregado dentro de canales propios","pasos":["Confirmar que el canal analizado es propio, que se tiene acceso legítimo administrativo y que su reglamento o condiciones de uso permiten este tipo de análisis agregado.","Recopilar el historial de mensajes del periodo que se quiere analizar dentro del canal.","Pedir que se agrupen los mensajes por tema recurrente, contando cuántas veces aparece cada tema sin identificar a las personas autoras de cada mensaje en el resultado.","Revisar el resumen de temas resultante para detectar patrones útiles (dudas repetidas, quejas recurrentes, interés en un tema concreto).","Si se decide compartir hallazgos con el equipo, compartir solo el resumen agregado por tema, nunca capturas o citas textuales atribuidas a una persona sin su consentimiento."],"reglas":["No exponer ni citar conversaciones individuales atribuidas a una persona concreta sin su consentimiento explícito; el resultado debe ser siempre un agregado por tema.","Aplicar este análisis únicamente a canales propios y con acceso administrativo legítimo, nunca a comunidades o canales ajenos ni a conversaciones privadas fuera del canal analizado.","Informar a los miembros de la comunidad, según lo que exija la normativa de protección de datos aplicable, de que sus conversaciones pueden analizarse de forma agregada para entender temas de interés."],"prompt":"Tengo acceso administrativo legítimo a [canal/grupo privado de mi marca, por ejemplo un servidor de Discord de clientes]. Te paso el historial de mensajes de un periodo determinado. Agrupa los mensajes por tema recurrente (por ejemplo: dudas de uso, quejas de un problema concreto, peticiones de función nueva, elogios) y dime cuántas veces aparece cada tema. No cites ni atribuyas fragmentos de mensaje a ninguna persona concreta en el resultado: quiero solo el resumen agregado por tema, para poder compartirlo con mi equipo sin exponer conversaciones individuales. Historial: [pegar aquí]."}},
  {"id":"gr84","catalogo":"growth","grupo":"Redes sociales","tema":"Conversación y comunidad","titulo":"Identifica patrones de ritmo y estructura en los vídeos de tu competencia","beneficio":"Analiza los vídeos públicos de una cuenta competidora para identificar patrones de ritmo y estructura que se repiten (cómo abren, cuándo cambian de plano, cómo cierran), dándote ideas estructurales para mejorar tus propios vídeos sin necesidad de copiar el guion o el contenido de nadie.","alcance":"Solo analiza el patrón de ritmo y estructura de vídeos públicos, no el contenido protegido por derechos de autor ni la estrategia interna del competidor; identificar un patrón estructural no implica que replicarlo garantice un resultado similar, porque el rendimiento de cada vídeo depende también del contenido, la audiencia propia y el algoritmo de la plataforma en cada momento.","precio":1.99,"blueprint":{"quePuedeHacer":"El asistente puede revisar las transcripciones y marcas de tiempo de varios vídeos públicos de una cuenta competidora, identificar patrones recurrentes de estructura (duración típica de la apertura, momento del primer cambio de plano, tipo de cierre usado) y resumir esos patrones en términos generales de ritmo y forma, sin reproducir el guion original.","modo":"Análisis de contenido público de terceros, sin copia","pasos":["Reunir las transcripciones y marcas de tiempo de un conjunto de vídeos públicos de la cuenta competidora que se quiere estudiar.","Pedir que se identifiquen patrones recurrentes de estructura: cómo suelen abrir, en qué momento ocurre el primer cambio de plano o gancho, cómo organizan el cuerpo del vídeo y cómo suelen cerrar.","Pedir que el resultado se exprese como un patrón general de ritmo y forma (por ejemplo, 'suelen abrir con una pregunta directa antes de mostrar el tema'), nunca como una cita textual del guion original.","Usar ese patrón como referencia estructural para planificar el guion propio, redactando contenido original inspirado en la estructura, no en las palabras exactas del competidor.","Revisar el guion propio resultante para confirmar que no reproduce frases textuales ni el contenido específico de los vídeos analizados."],"reglas":["No reproducir ni citar de forma textual el guion o las frases exactas de los vídeos del competidor; el análisis se limita al patrón de ritmo y estructura.","El resultado debe usarse como inspiración estructural para producir contenido propio y original, nunca como plantilla para copiar el contenido de otro.","No prometer que replicar un patrón estructural detectado garantice un rendimiento similar al del competidor; el resultado de cada vídeo depende de múltiples factores fuera del guion."],"prompt":"Te paso las transcripciones con marcas de tiempo de varios vídeos públicos de una cuenta competidora en mi sector. Identifica los patrones recurrentes de estructura y ritmo: cómo suelen abrir el vídeo, en qué momento aproximado ocurre el primer cambio de plano o gancho, cómo organizan el cuerpo del contenido y cómo suelen cerrar. Preséntame el resultado como patrones generales de forma y ritmo (por ejemplo, tipo de apertura, estructura del cuerpo, tipo de cierre), sin citar ni reproducir frases textuales de sus guiones. Después, ayúdame a redactar un guion propio y original para mi próximo vídeo que siga una estructura de ritmo similar, pero con mi propio contenido y mensaje, dejando claro que no debe reutilizar frases ni contenido específico de los vídeos analizados. Transcripciones: [pegar aquí]."}},
  {"id":"gr85","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Accesibilidad","titulo":"Corrige el contraste de color y las etiquetas de accesibilidad que tu web está incumpliendo","beneficio":"Amplía tu web a personas con baja visión o que usan lector de pantalla, y reduce el riesgo de quejas o exigencias legales de accesibilidad en algunos países.","alcance":"Ajusta pares de color hasta alcanzar el contraste mínimo recomendado (ratio 4.5:1 para texto normal) y agrega roles ARIA a elementos interactivos que no los tengan. Los cambios de color deben revisarse visualmente antes de publicarse: un ajuste que cumple la norma técnica puede aun así verse distinto a la identidad visual de la marca.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa el código de estilos y HTML de tu web para encontrar textos con contraste insuficiente frente a su fondo, y detecta botones, menús u otros elementos interactivos sin un rol de accesibilidad asignado.","modo":"Agente con acceso de lectura al repositorio de código (CSS/HTML/Tailwind) que entrega los cambios propuestos en formato diff, sin escribir directo en los archivos de producción.","pasos":["Extraer todos los pares de color texto/fondo usados en el CSS o los tokens actuales.","Calcular el ratio de contraste de cada par y marcar los que no llegan a 4.5:1 en texto normal.","Proponer el ajuste mínimo de color (texto o fondo) necesario para cumplir el ratio, priorizando mantener el tono de marca.","Detectar elementos interactivos sin rol ARIA o HTML semántico explícito.","Añadir el rol correspondiente sin alterar la funcionalidad ni el estilo visual.","Entregar un diff con los cambios propuestos, no aplicarlos directamente."],"reglas":["Nunca reemplazar un color de marca por otro genérico solo para 'pasar' el contraste: ajustar el mínimo necesario y avisar si no es suficiente.","No asumir el rol ARIA correcto sin evidencia en el código: si es ambiguo, señalarlo en vez de adivinar.","Todo cambio de color debe entregarse como propuesta (diff), nunca aplicarse directo a producción.","Un cambio de contraste que cumple la norma técnica igual debe revisarse visualmente antes de publicar."],"prompt":"Eres un agente de accesibilidad web. Analiza el archivo de estilos (CSS/Tailwind) y el HTML de la página adjunta. Para cada combinación de color de texto y color de fondo, calcula el ratio de contraste y, si es menor a 4.5:1 para texto normal (o 3:1 para texto grande), propón un ajuste del color de texto o de fondo que sí cumpla el ratio, manteniendo el tono general de la marca lo más parecido posible. Además, identifica elementos interactivos (botones, enlaces con solo icono, menús) que no tengan un rol ARIA o un role HTML explícito, y añade el atributo role adecuado (button, navigation, menuitem, etc.). Entrega la lista de cambios propuestos con el selector CSS o la línea de código afectada, el valor anterior y el nuevo, y el ratio de contraste resultante. No apliques los cambios directamente al archivo de producción: entrega un diff para que un humano lo revise visualmente antes de fusionarlo."}},
  {"id":"gr86","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Accesibilidad","titulo":"Dale a cada icono y botón sin texto una descripción que los lectores de pantalla puedan entender","beneficio":"Los visitantes que usan lector de pantalla entienden qué hace cada botón o icono, en vez de encontrarse con silencio o etiquetas sin sentido.","alcance":"Detecta elementos sin texto visible (iconos, botones de solo imagen, campos sin etiqueta) y redacta una descripción para lectores de pantalla. Requiere revisión humana: la IA puede malinterpretar el propósito de un icono ambiguo o un botón con múltiples funciones.","precio":1.99,"blueprint":{"quePuedeHacer":"Encuentra iconos, botones e imágenes que no tienen ningún texto visible y redacta una descripción breve para que un lector de pantalla explique su función.","modo":"Agente con acceso de lectura al HTML/JSX del proyecto; entrega las descripciones propuestas como diff para revisión antes de aplicarlas.","pasos":["Recorrer el HTML/JSX en busca de elementos sin texto visible: iconos, botones de solo imagen, campos sin etiqueta.","Clasificar cada elemento según si es funcional (necesita descripción) o decorativo (puede marcarse como oculto para lectores de pantalla).","Redactar una descripción breve y clara para los elementos funcionales.","Señalar los casos donde el propósito del elemento no se puede determinar solo con el código.","Entregar los cambios como diff, indicando el atributo (aria-label, alt, aria-describedby) y el valor propuesto."],"reglas":["No inventar una descripción cuando el propósito del elemento es ambiguo: reportarlo para que una persona lo defina.","Los elementos puramente decorativos deben marcarse para ser ignorados por el lector de pantalla, no descritos.","Las descripciones deben ser breves y en español neutro, sin tecnicismos innecesarios.","Ningún cambio se aplica sin revisión de alguien que conozca el contexto real de cada elemento."],"prompt":"Eres un agente de accesibilidad. Recorre el HTML/JSX adjunto y encuentra todos los elementos que muestran información solo mediante un icono, imagen o botón sin texto visible (iconos de redes sociales, botones de cerrar 'X', imágenes de producto sin atributo alt, campos de formulario sin label asociado). Para cada uno, redacta una descripción breve y clara en español neutro que explique su función o contenido, y proponla como valor de aria-label, alt o aria-describedby según corresponda. Si el propósito del elemento es ambiguo a partir del código (por ejemplo, un icono decorativo vs. uno funcional), señálalo explícitamente en vez de inventar una descripción. Entrega los cambios en formato diff con el selector o la línea de código afectada, para que un humano confirme cada descripción antes de publicarla."}},
  {"id":"gr87","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Accesibilidad","titulo":"Detecta los botones y enlaces demasiado pequeños para tocar cómodo en el móvil","beneficio":"Reduce los toques accidentales en el botón equivocado en móvil, lo que mejora la experiencia y ayuda a que la gente complete lo que vino a hacer.","alcance":"Mide el área de toque de botones y enlaces en las plantillas móviles y señala los que quedan por debajo de un tamaño cómodo para el dedo (aprox. 44x44 píxeles). No corrige el diseño por sí solo: las sugerencias de ajuste deben validarse visualmente para no descuadrar el layout.","precio":1.99,"blueprint":{"quePuedeHacer":"Mide el tamaño del área de toque de botones y enlaces en las plantillas móviles y señala cuáles quedan por debajo de un tamaño cómodo para el dedo.","modo":"Agente con acceso al CSS/Tailwind de las plantillas móviles; entrega un informe de hallazgos priorizado, sin modificar el código directamente.","pasos":["Medir el área de toque efectiva (incluyendo padding) de cada botón, enlace e ícono clicable en las plantillas móviles.","Comparar cada área contra un tamaño mínimo cómodo de referencia (aprox. 44x44 píxeles).","Detectar elementos contiguos que, al agrandarse, podrían superponerse o quedar demasiado juntos.","Priorizar los hallazgos según qué tan usado es el elemento (navegación principal, checkout, formularios).","Entregar un informe con selector, tamaño estimado actual y sugerencia de ajuste."],"reglas":["No aplicar automáticamente los cambios de tamaño: son sugerencias que deben validarse visualmente.","Avisar explícitamente cuando agrandar un área de toque puede generar solapamiento con elementos vecinos.","Priorizar siempre los elementos de mayor uso (checkout, navegación) sobre los secundarios.","No inventar cifras de mejora de conversión: el informe se limita a señalar el cumplimiento del tamaño mínimo."],"prompt":"Eres un auditor de accesibilidad táctil. Revisa las plantillas o componentes móviles adjuntos (CSS/Tailwind) y mide el área de toque efectiva (ancho x alto, incluyendo padding) de cada botón, enlace e ícono clicable. Señala los elementos cuya área de toque quede por debajo de aproximadamente 44x44 píxeles, indicando el selector, el tamaño actual estimado y una sugerencia de padding o tamaño mínimo para corregirlo. Ten en cuenta elementos muy próximos entre sí (por ejemplo, iconos en una barra de acciones) donde un área de toque más grande podría hacer que se superpongan; en esos casos, avisa del conflicto en vez de proponer un cambio automático. Entrega un informe priorizado por elementos más usados (navegación principal, checkout, formularios) primero."}},
  {"id":"gr88","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Sistema de diseño y marca","titulo":"Organiza los colores y estilos sueltos de tu web en variables reutilizables","beneficio":"Cuando cambies un color o un tamaño de marca, lo haces en un solo lugar en vez de rastrearlo por decenas de archivos, con menos riesgo de dejar algo inconsistente.","alcance":"Agrupa los valores de color, tipografía y espaciado repetidos en variables (tokens) con nombres claros, sin decidir cuáles son 'correctos': mantiene los valores existentes, solo los centraliza. Un desarrollador debe revisar el diff antes de fusionarlo, ya que renombrar variables puede afectar estilos en cascada.","precio":1.99,"blueprint":{"quePuedeHacer":"Encuentra los colores, tipografías y espaciados que se repiten como valores sueltos en el código, y los organiza en variables (tokens) centralizadas.","modo":"Agente con acceso de lectura al código y salida en formato diff sugerido al CSS/Tailwind/SCSS del proyecto.","pasos":["Escanear el CSS/Tailwind/SCSS del proyecto en busca de valores de color, tipografía, espaciado y radios repetidos como valores sueltos.","Agrupar los valores repetidos por similitud y frecuencia de uso.","Definir nombres semánticos para cada token, organizados en niveles primitivo, semántico y (si aplica) de componente.","Generar el archivo de tokens propuesto sin alterar los valores originales.","Listar los archivos y líneas donde reemplazar el valor suelto por la variable correspondiente."],"reglas":["No modificar ni 'corregir' los valores de color o tamaño existentes: solo organizarlos en variables.","No renombrar tokens ya existentes en el proyecto sin señalarlo explícitamente, para evitar romper referencias.","Entregar los cambios como propuesta revisable, nunca aplicados directo a los archivos de producción.","Un desarrollador debe validar que ningún componente quedó roto tras el reemplazo antes de fusionar."],"prompt":"Eres un agente de organización de código de estilos. Analiza el CSS/Tailwind/SCSS del proyecto adjunto y detecta valores de color, tipografía, radios de borde y espaciados que se repiten como valores sueltos (hex codes, tamaños en px) en vez de variables. Agrupa los valores repetidos en tokens de diseño con nombres semánticos (ej. --color-primario, --espaciado-md, --radio-tarjeta) organizados en una jerarquía de tres niveles: primitivos (valores crudos), semánticos (uso, ej. color-fondo-boton) y de componente si aplica. No inventes ni 'mejores' colores nuevos: usa exactamente los valores ya presentes en el código, solo cámbialos de lugar. Entrega el archivo de tokens propuesto junto con la lista de archivos y líneas donde reemplazar los valores sueltos por la variable correspondiente, para que un desarrollador revise el diff antes de aplicarlo."}},
  {"id":"gr89","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Sistema de diseño y marca","titulo":"Detecta cuándo una página se desvía de las tipografías y espaciados de tu manual de marca","beneficio":"Mantiene una imagen de marca consistente entre páginas, evitando que una landing 'se vea de otra empresa' por una fuente o un espaciado fuera de lugar.","alcance":"Compara las tipografías y espaciados del sitio con lo indicado en el manual de marca o los tokens definidos, y reporta discrepancias. Es un chequeo comparativo, no un corrector automático: cada hallazgo debe evaluarlo una persona, porque a veces una variación es intencional.","precio":1.99,"blueprint":{"quePuedeHacer":"Compara las tipografías y espaciados usados en el sitio contra lo definido en el manual de marca o en los tokens oficiales, y reporta las diferencias.","modo":"Requiere el manual de marca o archivo de tokens como referencia, más acceso de lectura al código o capturas de las páginas a auditar.","pasos":["Leer el manual de marca o el archivo de tokens oficial con tipografías y espaciados definidos.","Recorrer las páginas o componentes del sitio y extraer las tipografías y espaciados realmente usados.","Comparar ambos conjuntos y listar las discrepancias encontradas.","Indicar, por cada discrepancia, la página, el elemento y el valor esperado según el manual.","Entregar los hallazgos como lista priorizada, sin aplicar correcciones automáticas."],"reglas":["No corregir automáticamente ninguna discrepancia: presentarla como hallazgo para que una persona decida.","Reconocer que algunas variaciones pueden ser intencionales (landings especiales, experimentos) y no marcarlas como error sin contexto.","Basar la comparación solo en lo que indica el manual de marca vigente, no en preferencias estéticas propias."],"prompt":"Eres un agente de coherencia de marca. Te doy el manual de marca (o el archivo de tokens de diseño) con las tipografías y espaciados oficiales, y el código o las capturas de las páginas del sitio. Compara cada página contra el manual y lista las discrepancias encontradas: fuentes que no están en la lista oficial, tamaños de fuente o espaciados que no correspondan a la escala definida. Para cada discrepancia, indica la página, el elemento afectado y el valor esperado según el manual. No corrijas los archivos directamente: algunas variaciones pueden ser intencionales (una landing especial, un experimento), así que preséntalas como hallazgos para que una persona decida cuáles corregir."}},
  {"id":"gr90","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Sistema de diseño y marca","titulo":"Convierte una imagen de referencia en una paleta de colores lista para inspirar tu próximo diseño","beneficio":"Acelera la fase de exploración creativa de un nuevo diseño sin depender de un diseñador solo para probar combinaciones de color.","alcance":"Identifica los colores dominantes de una imagen de referencia y propone una paleta reducida y coherente. Es un punto de partida creativo, no una paleta de marca terminada: debe filtrarse con criterio de accesibilidad e identidad de marca antes de usarse.","precio":1.99,"blueprint":{"quePuedeHacer":"A partir de una imagen de referencia, identifica sus colores dominantes y propone una paleta reducida como punto de partida para un nuevo diseño.","modo":"Recibe una imagen (archivo o captura de pantalla) como entrada única; entrega una paleta con códigos hexadecimales.","pasos":["Analizar la imagen de referencia entregada y extraer sus colores dominantes.","Agrupar los colores en una paleta reducida: un color principal, uno o dos secundarios, un neutro claro y uno oscuro.","Asignar a cada color un código hexadecimal y una posible función (fondo, acento, texto).","Señalar qué pares de color de la paleta podrían tener problemas de contraste para texto.","Entregar la paleta como punto de partida creativo, no como decisión final."],"reglas":["Dejar explícito que la paleta extraída es inspiración inicial, no una paleta de marca aprobada.","No garantizar que los colores extraídos cumplan contraste adecuado: eso debe verificarse aparte.","No mezclar la paleta nueva con la identidad de marca existente sin que una persona lo evalúe."],"prompt":"Eres un asistente de exploración visual. Te doy una imagen de referencia (captura de un competidor, una foto de producto, una tendencia de redes sociales). Identifica los colores dominantes de la imagen y agrúpalos en una paleta reducida y coherente (un color principal, uno o dos secundarios, un neutro claro y uno oscuro). Para cada color, entrega el código hexadecimal y una breve descripción de dónde podría usarse (fondo, acento, texto). Aclara que esta paleta es un punto de partida creativo: antes de adoptarla hay que revisar que los pares de color propuestos para texto sobre fondo cumplan un contraste adecuado y que no choquen con la identidad de marca ya existente."}},
  {"id":"gr91","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Sistema de diseño y marca","titulo":"Limpia los archivos de diseño exportados desde Figma antes de subirlos al proyecto","beneficio":"Entrega archivos más livianos para el sitio y evita filtrar información interna (nombres de capas, notas del equipo) que a veces queda incrustada en el SVG exportado.","alcance":"Elimina metadatos, comentarios y capas ocultas de archivos SVG exportados, sin modificar el diseño en sí. Una persona debe verificar que el archivo limpio se vea idéntico al original antes de reemplazarlo en el proyecto.","precio":1.99,"blueprint":{"quePuedeHacer":"Limpia archivos SVG exportados de Figma, quitando metadatos, comentarios y capas ocultas innecesarias antes de integrarlos al proyecto.","modo":"Recibe el archivo vectorial exportado como entrada; entrega el archivo limpio junto con un resumen de los cambios.","pasos":["Recibir el archivo SVG exportado desde Figma u otra herramienta de diseño.","Detectar y eliminar metadatos, comentarios de editor, IDs autogenerados sin uso y capas vacías u ocultas.","Optimizar paths solo cuando el cambio no altera la forma visual resultante.","Comparar el tamaño de archivo antes y después de la limpieza.","Señalar si algún nombre de capa o comentario parece contener información interna sensible."],"reglas":["Nunca alterar la apariencia visual del archivo al limpiarlo: solo quitar lo que no se renderiza.","Avisar, no borrar en silencio, cuando se detecte información interna (nombres de cliente, notas de equipo) en el archivo original.","Entregar siempre una comparación visual disponible (o instrucción para generarla) antes de reemplazar el archivo original."],"prompt":"Eres un agente de limpieza de archivos de diseño. Recibo archivos SVG exportados desde Figma. Elimina metadatos innecesarios (comentarios del editor, atributos de datos específicos de Figma, capas ocultas o vacías, IDs generados automáticamente que no se usan en el código) sin alterar la apariencia visual del archivo. Optimiza los paths donde sea seguro hacerlo sin cambiar la forma resultante. Entrega el archivo limpio junto con un resumen de qué se quitó y el tamaño de archivo antes y después. Señala si detectas texto o capas con nombres que parezcan contener información interna (nombres de clientes, notas del equipo) que no deberían quedar en un archivo público."}},
  {"id":"gr92","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Conversión visual","titulo":"Estima hacia dónde mirará primero un visitante para comprobar que tu botón principal esté bien ubicado","beneficio":"Ayuda a decidir dónde poner el llamado a la acción antes de invertir tiempo y dinero en pruebas con usuarios reales.","alcance":"Genera una estimación de las zonas que probablemente concentran atención visual, basada en principios de jerarquía de diseño (no en una medición real de seguimiento ocular). Es una guía orientativa: las decisiones de conversión importantes deben validarse con pruebas A/B o estudios con usuarios reales.","precio":1.99,"blueprint":{"quePuedeHacer":"A partir de una captura de un diseño, estima qué zonas concentran más atención visual según principios de jerarquía de diseño, y si el botón principal queda bien ubicado.","modo":"Recibe una captura o maqueta del diseño como entrada; entrega una estimación cualitativa, no una medición de eye-tracking real.","pasos":["Analizar la composición del diseño: tamaño, contraste, posición y espacio en blanco de los elementos principales.","Estimar, según principios de jerarquía visual, el orden probable en que un visitante recorrería la página con la vista.","Señalar si el llamado a la acción principal cae dentro de una zona de buen peso visual estimado.","Dejar explícito que se trata de una estimación heurística, no de una medición real de seguimiento ocular.","Recomendar validar cualquier decisión relevante con una prueba A/B o estudio con usuarios reales."],"reglas":["No presentar la estimación como un dato medido: debe quedar claro que es una aproximación basada en heurísticas de diseño.","No tomar decisiones de conversión solo con este análisis: es un insumo, no una prueba.","Evitar cifras de porcentaje de atención inventadas; describir las zonas en términos cualitativos (alta, media, baja probabilidad de atención)."],"prompt":"Eres un asistente de jerarquía visual. Te doy una captura de un diseño de página (landing, ficha de producto). Describe, en orden estimado, las zonas que probablemente capturan primero la atención visual según principios de diseño (contraste, tamaño, posición, espacio en blanco alrededor), y señala si el llamado a la acción principal queda o no en una de esas zonas de buen peso visual. Deja explícito en la respuesta que esto es una estimación heurística, no una medición real de seguimiento ocular, y que cualquier decisión de conversión importante debería confirmarse con una prueba A/B o un estudio con usuarios reales."}},
  {"id":"gr93","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Conversión visual","titulo":"Genera variaciones de un mismo banner para distintas campañas sin tapar nunca el logotipo","beneficio":"Multiplica las piezas para campañas de anuncios o redes sociales sin rehacer el diseño desde cero en cada variación.","alcance":"Genera variantes de un banner cambiando texto e imagen, respetando el área reservada para el logotipo. Cada lote debe revisarse visualmente antes de publicarse: la IA puede recortar mal una imagen o dejar un contraste de texto insuficiente en alguna variante puntual.","precio":1.99,"blueprint":{"quePuedeHacer":"Genera variaciones de un banner cambiando texto e imagen de fondo por lote, respetando siempre el espacio reservado para el logotipo.","modo":"Recibe la plantilla base y una lista de combinaciones de texto/imagen; entrega el lote de banners generado.","pasos":["Recibir la plantilla base del banner con la posición fija del logotipo y otros elementos protegidos.","Aplicar cada combinación de texto e imagen de fondo de la lista de campaña.","Verificar en cada variante que el logotipo y los elementos fijos queden completamente visibles, sin recortes ni superposición de texto.","Revisar el contraste del texto sobre la nueva imagen de fondo en cada variante.","Entregar el lote completo señalando las variantes con contraste ajustado o dudoso."],"reglas":["Nunca generar una variante que cubra, recorte o superponga texto sobre el logotipo.","Marcar para revisión humana cualquier variante donde el contraste de texto quede al límite.","No alterar las proporciones ni el tamaño del banner definidos por la plantilla base."],"prompt":"Eres un generador de variaciones de banner. Te doy una plantilla base (tamaño, posición del logotipo y de los elementos fijos) y una lista de combinaciones de texto e imagen de fondo para una campaña. Genera una variante del banner por cada combinación, respetando siempre el área de exclusión reservada para el logotipo (no lo cubras ni lo recortes) y verificando que el texto mantenga un contraste legible sobre la imagen de fondo elegida. Entrega el lote completo con una nota indicando en qué variantes el contraste de texto quedó ajustado o dudoso, para revisión visual antes de publicar."}},
  {"id":"gr94","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Conversión visual","titulo":"Ubica las opiniones de clientes y las cifras de confianza donde el visitante las vea nada más entrar","beneficio":"Refuerza la confianza del visitante en los primeros segundos, un factor que suele pesar en la decisión de quedarse o irse de la página.","alcance":"Propone un wireframe que ubica elementos de prueba social en el área visible sin scroll. Es un boceto de estructura, no un diseño final: el contenido definitivo y el diseño visual requieren trabajo adicional de diseño y redacción.","precio":1.99,"blueprint":{"quePuedeHacer":"Propone un esquema de bloques (wireframe) para una página de conversión, ubicando los elementos de prueba social dentro del área visible sin scroll.","modo":"Recibe el objetivo de la página y los elementos de prueba social disponibles; entrega un esquema de estructura, no un diseño visual terminado.","pasos":["Definir el objetivo principal de la página (conversión, captación de datos, venta) y el llamado a la acción central.","Revisar qué elementos de prueba social están disponibles (testimonios, cifras, logos, valoraciones).","Ubicar al menos un elemento de prueba social dentro del área visible sin scroll, junto al llamado a la acción.","Esbozar el resto de bloques de la página en orden de prioridad de lectura.","Entregar el wireframe como esquema de bloques, no como diseño visual terminado."],"reglas":["No usar cifras o testimonios inventados para llenar el wireframe: dejar marcadores de contenido pendiente si no hay datos reales disponibles.","El wireframe es una guía de estructura, no reemplaza el trabajo de diseño visual ni de copywriting.","Priorizar que el área visible sin scroll no quede sobrecargada: menos elementos, pero relevantes."],"prompt":"Eres un arquitecto de wireframes orientados a conversión. Te doy el objetivo de la página (ej. página de precios, landing de captación) y los elementos de prueba social disponibles (testimonios, cifras de clientes, logos, valoraciones). Propón un wireframe en texto o esquema de bloques que ubique al menos un elemento de prueba social dentro del área visible sin necesidad de hacer scroll, junto con el llamado a la acción principal. Aclara que es un boceto de estructura: el copy definitivo, las imágenes reales y el diseño visual final deben trabajarse aparte."}},
  {"id":"gr95","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Rendimiento de interfaz","titulo":"Evita que tu página 'salte' mientras carga, reservando el espacio exacto para cada elemento","beneficio":"Evita que el contenido se mueva mientras carga, lo que reduce clics accidentales y ayuda a las métricas de calidad de página que usan los buscadores.","alcance":"Añade esqueletos de carga del mismo tamaño que el contenido final (imágenes, bloques de texto, anuncios) para que el layout no se desplace. Debe revisarse visualmente en distintos dispositivos, porque un tamaño de esqueleto mal calculado puede generar el mismo problema que intenta resolver.","precio":1.99,"blueprint":{"quePuedeHacer":"Añade marcadores de posición (esqueletos de carga) del mismo tamaño que el contenido real, para evitar que la página salte mientras carga.","modo":"Agente con acceso de lectura al código de las páginas; entrega el código del esqueleto propuesto y el punto de inserción.","pasos":["Identificar elementos que cargan de forma asíncrona: imágenes sin dimensiones definidas, contenido inyectado por JavaScript, anuncios, embeds.","Determinar el tamaño final de cada elemento cuando sea posible (dimensiones reales de la imagen, tamaño típico del embed).","Generar un marcador de posición (esqueleto) con esas mismas dimensiones o una relación de aspecto fija.","Insertar el esqueleto en el punto exacto donde aparecerá el contenido real.","Señalar los casos donde el tamaño final no se pudo determinar con certeza."],"reglas":["Nunca definir un tamaño de esqueleto arbitrario cuando el tamaño real del contenido es conocido: usar ese valor.","Avisar explícitamente cuando el tamaño del contenido final es incierto, para que una persona lo confirme visualmente.","Verificar el resultado en distintos tamaños de pantalla, no solo en el diseño de escritorio."],"prompt":"Eres un agente de estabilidad de layout. Revisa el código de las páginas adjuntas y encuentra elementos que cargan de forma asíncrona (imágenes sin ancho/alto definidos, bloques de contenido inyectado por JavaScript, anuncios, embeds). Para cada uno, propón un marcador de posición (esqueleto de carga) con las mismas dimensiones que el contenido final, usando el ancho y alto reales del recurso cuando estén disponibles (ej. atributos width/height de la imagen) o una relación de aspecto fija. Entrega el código del esqueleto propuesto junto con el selector donde insertarlo, y señala los casos donde no se pudo determinar el tamaño final con certeza para que una persona lo confirme visualmente."}},
  {"id":"gr96","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Rendimiento de interfaz","titulo":"Carga solo las fuentes y los caracteres que tu web realmente usa, para que el texto aparezca más rápido","beneficio":"Hace que el texto aparezca antes en pantallas y conexiones lentas, sin renunciar a la tipografía de marca.","alcance":"Ajusta la precarga de fuentes para incluir solo los pesos y caracteres realmente usados en el idioma del sitio. Requiere revisión visual tras el cambio: un subconjunto de caracteres mal definido puede hacer que letras especiales no se vean bien.","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta qué fuentes y caracteres se usan realmente en el sitio y ajusta la precarga para no cargar pesos ni juegos de caracteres innecesarios.","modo":"Agente con acceso de lectura al código y a las hojas de estilo del proyecto; entrega la configuración de precarga ajustada.","pasos":["Detectar qué familias, pesos y estilos de fuente están realmente en uso en el sitio.","Comparar contra las fuentes y pesos que se están precargando o cargando actualmente.","Eliminar de la precarga los pesos o estilos que no se usan.","Si el proveedor lo permite, limitar el subconjunto de caracteres al necesario para el idioma del sitio (incluyendo tildes, eñe y signos de apertura).","Entregar la lista de cambios y advertir sobre la necesidad de revisión visual posterior."],"reglas":["No eliminar un peso o estilo de fuente que sí esté en uso, aunque sea en pocas páginas.","Asegurar que el subconjunto de caracteres cubra todos los signos propios del idioma de la web (tildes, eñe, ¿, ¡).","Revisar visualmente el resultado en las páginas que usan texto con caracteres especiales antes de dar el cambio por cerrado."],"prompt":"Eres un optimizador de rendimiento de fuentes web. Revisa el código y las hojas de estilo del proyecto y detecta qué familias, pesos (bold, regular) y estilos de fuente se usan realmente en el sitio. Ajusta las etiquetas de precarga (preload, font-display) para cargar solo esas variantes, y si el proveedor de fuentes lo permite, limita el subconjunto de caracteres al necesario para el idioma del sitio (por ejemplo, español con tildes, eñe y signos de apertura ¿¡). Entrega la lista de fuentes/pesos que se estaban cargando sin usarse, y advierte que hay que revisar visualmente las páginas después del cambio para confirmar que ningún carácter especial se vea afectado."}},
  {"id":"gr97","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Rendimiento de interfaz","titulo":"Elimina las reglas de estilo que ya nadie usa y que solo hacen más pesada tu web","beneficio":"Aligera los archivos de estilo del sitio, lo que ayuda a que cargue más rápido, especialmente en móviles.","alcance":"Detecta reglas de CSS no enlazadas a ningún componente activo y las marca para eliminación. Antes de aplicar los cambios en producción hay que revisar visualmente las páginas principales: el análisis puede fallar con estilos que solo se activan en ciertos estados (hover, un menú desplegable).","precio":1.99,"blueprint":{"quePuedeHacer":"Detecta reglas de CSS que ya no están enlazadas a ningún componente activo del sitio y las marca como candidatas a eliminar.","modo":"Agente con acceso de lectura al CSS y a los componentes activos del proyecto; separa hallazgos de alta confianza de los que requieren revisión manual.","pasos":["Listar todas las reglas CSS definidas en el proyecto.","Verificar cuáles están enlazadas a selectores presentes en el código actual (componentes activos).","Excluir de la eliminación las reglas asociadas a estados dinámicos (:hover, :focus, clases añadidas por JavaScript).","Separar los hallazgos en 'alta confianza' y 'requiere revisión manual'.","Entregar el listado con archivo y línea, sin aplicar la eliminación directamente."],"reglas":["Nunca eliminar una regla asociada a un estado dinámico sin marcarla para revisión manual primero.","No aplicar la purga directo a producción: siempre como propuesta revisable.","Verificar visualmente las páginas principales después de aplicar cualquier eliminación."],"prompt":"Eres un agente de limpieza de CSS. Analiza el código del proyecto (componentes activos y hojas de estilo) y detecta reglas CSS que no están enlazadas a ningún selector presente en el código actual. Antes de marcar una regla como 'sin usar', verifica si corresponde a estados dinámicos (:hover, :focus, clases añadidas por JavaScript, ej. un menú desplegable o un modal) para no eliminarla por error. Entrega la lista de reglas candidatas a eliminar con el archivo y la línea donde están definidas, separadas en 'alta confianza' y 'requiere revisión manual', y deja claro que el resultado debe verificarse visualmente en las páginas principales antes de aplicar los cambios en producción."}},
  {"id":"gr98","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Calidad UX y cierre de trabajo","titulo":"Revisa que tu sitio cumpla los principios básicos de un diseño fácil de usar","beneficio":"Detecta fricciones comunes de uso antes de que las note un cliente frustrado, como la falta de una forma clara de volver atrás.","alcance":"Recorre las pantallas principales contra una lista de principios de usabilidad reconocidos y avisa de incumplimientos. Es un chequeo de lista, no un test con usuarios reales: las señales deben priorizarse e interpretarse por una persona antes de decidir qué cambiar.","precio":1.99,"blueprint":{"quePuedeHacer":"Revisa las pantallas principales del sitio contra una lista de principios de usabilidad reconocidos y avisa de los incumplimientos encontrados.","modo":"Recibe capturas o acceso de lectura a las pantallas principales; entrega un informe priorizado de hallazgos.","pasos":["Reunir las pantallas principales del sitio (capturas o código) a revisar.","Comparar cada pantalla contra una lista de heurísticas de usabilidad reconocidas.","Registrar cada incumplimiento con la pantalla afectada, la heurística que falla y una breve explicación.","Priorizar los hallazgos según el impacto probable en la experiencia del usuario.","Entregar el informe como lista de verificación, no como veredicto definitivo."],"reglas":["No inventar heurísticas: usar principios de usabilidad reconocidos y documentados.","Dejar que una persona del equipo decida la prioridad final de corrección, no solo el orden sugerido por el chequeo automático.","Aclarar que esta revisión no sustituye una prueba con usuarios reales."],"prompt":"Eres un auditor de usabilidad. Revisa las pantallas principales del sitio adjuntas (capturas o código) contra una lista de heurísticas de usabilidad reconocidas: visibilidad del estado del sistema, existencia de una forma clara de volver atrás o cancelar una acción, consistencia de patrones de navegación, mensajes de error comprensibles, prevención de errores en formularios. Para cada incumplimiento encontrado, describe la pantalla, la heurística que falla y por qué. Prioriza los hallazgos según el impacto probable en la experiencia del usuario, y aclara que esta es una revisión de lista de verificación, no un test con usuarios reales: las prioridades finales debe definirlas una persona del equipo."}},
  {"id":"gr99","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Calidad UX y cierre de trabajo","titulo":"Recorta tus fotos de producto para que se vean bien en cualquier pantalla, sin descentrar el objeto","beneficio":"Ahorra el trabajo manual de recortar cada imagen del catálogo en varios formatos, manteniendo un catálogo prolijo en cualquier pantalla.","alcance":"Genera recortes cuadrados y verticales de una imagen de producto manteniendo el objeto principal centrado. Debe revisarse visualmente antes de subir el lote al catálogo: la detección automática puede fallar en fotos con fondos complejos o varios elementos.","precio":1.99,"blueprint":{"quePuedeHacer":"Genera recortes cuadrados y verticales de una imagen de producto, manteniendo el objeto principal centrado para distintos formatos de pantalla.","modo":"Recibe la imagen de producto original como entrada; entrega los recortes generados junto con los casos que requieren revisión manual.","pasos":["Recibir la imagen de producto en su formato y resolución original.","Detectar el objeto principal dentro de la imagen.","Generar un recorte cuadrado y uno vertical, manteniendo el objeto centrado y completo.","Señalar los casos de fondo complejo o múltiples objetos donde la detección no sea confiable.","Entregar los archivos resultantes junto con la lista de imágenes que requieren revisión manual."],"reglas":["No forzar un recorte cuando no se puede identificar con confianza el objeto principal: reportarlo en vez de adivinar.","Mantener siempre el objeto de producto completo dentro del encuadre, sin cortar partes relevantes.","Revisar visualmente el lote completo antes de subirlo al catálogo."],"prompt":"Eres un asistente de adaptación de imágenes de producto. Te doy una imagen de producto en su formato original. Genera un recorte cuadrado y uno vertical (más alto que ancho) manteniendo el objeto principal del producto centrado y completo dentro del encuadre, sin cortar partes relevantes. Si detectas que el fondo es complejo o hay más de un objeto y no puedes identificar con confianza cuál es el producto principal, indícalo en vez de adivinar el recorte. Entrega los archivos resultantes junto con una nota de qué imágenes requieren revisión visual manual antes de subirse al catálogo."}},
  {"id":"gr100","catalogo":"growth","grupo":"Diseño y experiencia","tema":"Calidad UX y cierre de trabajo","titulo":"Documenta en minutos qué cambiaste en el diseño para que cualquiera pueda continuar sin perder el hilo","beneficio":"Evita perder tiempo reconstruyendo el contexto cuando cambia quien lleva el diseño, o cuando retomas tú mismo el trabajo días después.","alcance":"Genera un documento de traspaso con los componentes modificados, las pruebas visuales revisadas y las tareas pendientes de la sesión. Es un resumen de lo hecho, no una auditoría de calidad: quien retome el trabajo debe verificar visualmente el estado real antes de continuar.","precio":1.99,"blueprint":{"quePuedeHacer":"Documenta al cierre de una sesión de trabajo qué se modificó, qué se validó visualmente y qué queda pendiente, para que otra persona pueda continuar sin perder contexto.","modo":"Recibe un resumen de los cambios de la sesión (o acceso al historial de cambios) y entrega un documento de traspaso breve.","pasos":["Revisar los cambios realizados durante la sesión de trabajo (componentes, estilos, pantallas).","Documentar qué se modificó y en qué consistió cada cambio.","Registrar qué pruebas visuales o de accesibilidad se hicieron y su resultado.","Listar lo que queda pendiente, incluyendo decisiones de diseño abiertas.","Redactar el documento asumiendo que el lector no tiene el contexto previo de la sesión."],"reglas":["No omitir las decisiones que quedaron sin resolver: dejarlas explícitas para quien continúe.","Describir el estado real del trabajo, no el estado deseado: si algo quedó a medias, decirlo.","El documento debe ser legible para alguien externo a la sesión, evitando abreviaturas o referencias sin contexto."],"prompt":"Eres un asistente de traspaso de sesión de diseño. Al final de la sesión de trabajo, genera un documento breve con tres secciones: (1) qué componentes o pantallas se modificaron y en qué consistió el cambio, (2) qué pruebas visuales o de accesibilidad se revisaron y su resultado (aprobado, pendiente, falló), y (3) qué queda pendiente para la próxima sesión, incluyendo cualquier decisión de diseño que quedó abierta. Escribe el documento asumiendo que quien lo lea no tiene el contexto de esta sesión y necesita poder continuar el trabajo sin tener que revisar todo el historial de cambios."}},
];
